# Bluesky Client

A full-featured Bluesky social client built on the AT Protocol using `@atproto/api`.

## Capabilities

- **Authentication** — Log in with Bluesky handle and app password. Sessions are persisted locally.
- **Timeline Feed** — View your home timeline with post content, author info (display name, handle, avatar), and timestamps.
- **Create Posts** — Compose and publish new text posts to your Bluesky account.
- **Like / Unlike** — Toggle likes on any post in your feed.
- **View Profiles** — Look up any user's profile including bio, follower/following counts, and recent posts.
- **Follow / Unfollow** — Manage your social graph by following or unfollowing users.

## Usage

```ts
import { createBlueskyClient } from "./src/index";

const client = await createBlueskyClient({
  identifier: "you.bsky.social",
  password: "app-password-here",
});

// View timeline
const feed = await client.getTimeline();

// Create a post
await client.createPost("Hello from modnet!");

// Like a post
await client.likePost(postUri, postCid);

// View a profile
const profile = await client.getProfile("someone.bsky.social");

// Follow a user
await client.followUser(profile.did);
```

## Data Storage

Session data is stored in `data/session.json` for persistence across restarts. No passwords are stored — only the session tokens returned by the AT Protocol.

export type Credentials = {
  identifier: string;
  password: string;
};

export type SessionData = {
  did: string;
  handle: string;
  accessJwt: string;
  refreshJwt: string;
};

export type AuthorInfo = {
  did: string;
  handle: string;
  displayName: string;
  avatar: string | undefined;
};

export type PostData = {
  uri: string;
  cid: string;
  author: AuthorInfo;
  text: string;
  createdAt: string;
  likeCount: number;
  repostCount: number;
  replyCount: number;
  likeUri: string | undefined;
  isRepost: boolean;
  repostedBy: AuthorInfo | undefined;
};

export type ProfileData = {
  did: string;
  handle: string;
  displayName: string;
  description: string;
  avatar: string | undefined;
  banner: string | undefined;
  followersCount: number;
  followsCount: number;
  postsCount: number;
  followUri: string | undefined;
};

export type TimelineResponse = {
  posts: PostData[];
  cursor: string | undefined;
};

export type ProfileFeedResponse = {
  posts: PostData[];
  cursor: string | undefined;
  profile: ProfileData;
};

import { AtpAgent } from "@atproto/api";
import type { Credentials, SessionData } from "./types";

const SESSION_PATH = "data/session.json";

export const saveSession = async (session: SessionData): Promise<void> => {
  await Bun.write(SESSION_PATH, JSON.stringify(session, null, 2));
};

export const loadSession = async (): Promise<SessionData | null> => {
  const file = Bun.file(SESSION_PATH);
  if (!(await file.exists())) return null;
  try {
    return (await file.json()) as SessionData;
  } catch {
    return null;
  }
};

export const clearSession = async (): Promise<void> => {
  const file = Bun.file(SESSION_PATH);
  if (await file.exists()) {
    await Bun.write(SESSION_PATH, "{}");
  }
};

export const authenticate = async (
  agent: AtpAgent,
  credentials: Credentials
): Promise<SessionData> => {
  const response = await agent.login({
    identifier: credentials.identifier,
    password: credentials.password,
  });

  const session: SessionData = {
    did: response.data.did,
    handle: response.data.handle,
    accessJwt: response.data.accessJwt,
    refreshJwt: response.data.refreshJwt,
  };

  await saveSession(session);
  return session;
};

export const resumeSession = async (
  agent: AtpAgent
): Promise<SessionData | null> => {
  const session = await loadSession();
  if (!session) return null;

  try {
    await agent.resumeSession({
      did: session.did,
      handle: session.handle,
      accessJwt: session.accessJwt,
      refreshJwt: session.refreshJwt,
      active: true,
    });
    return session;
  } catch {
    await clearSession();
    return null;
  }
};

import type { AtpAgent } from "@atproto/api";
import type {
  AppBskyFeedDefs,
  AppBskyFeedPost,
  AppBskyActorDefs,
} from "@atproto/api";
import type { AuthorInfo, PostData, TimelineResponse } from "./types";

const extractAuthor = (
  author: AppBskyActorDefs.ProfileViewBasic
): AuthorInfo => ({
  did: author.did,
  handle: author.handle,
  displayName: author.displayName ?? author.handle,
  avatar: author.avatar,
});

const extractPost = (
  feedItem: AppBskyFeedDefs.FeedViewPost
): PostData | null => {
  const post = feedItem.post;
  const record = post.record as AppBskyFeedPost.Record;

  if (!record?.text && record?.text !== "") return null;

  const isRepost = feedItem.reason?.$type === "app.bsky.feed.defs#reasonRepost";
  const reasonAuthor = isRepost
    ? (feedItem.reason as AppBskyFeedDefs.ReasonRepost & { by: AppBskyActorDefs.ProfileViewBasic }).by
    : undefined;

  return {
    uri: post.uri,
    cid: post.cid,
    author: extractAuthor(post.author),
    text: record.text,
    createdAt: record.createdAt,
    likeCount: post.likeCount ?? 0,
    repostCount: post.repostCount ?? 0,
    replyCount: post.replyCount ?? 0,
    likeUri: post.viewer?.like,
    isRepost,
    repostedBy: reasonAuthor ? extractAuthor(reasonAuthor) : undefined,
  };
};

export const getTimeline = async (
  agent: AtpAgent,
  cursor?: string,
  limit = 25
): Promise<TimelineResponse> => {
  const response = await agent.getTimeline({
    cursor,
    limit,
  });

  const posts = response.data.feed
    .map(extractPost)
    .filter((p): p is PostData => p !== null);

  return {
    posts,
    cursor: response.data.cursor,
  };
};

export const getAuthorFeed = async (
  agent: AtpAgent,
  actor: string,
  cursor?: string,
  limit = 25
): Promise<TimelineResponse> => {
  const response = await agent.getAuthorFeed({
    actor,
    cursor,
    limit,
  });

  const posts = response.data.feed
    .map(extractPost)
    .filter((p): p is PostData => p !== null);

  return {
    posts,
    cursor: response.data.cursor,
  };
};

import type { AtpAgent } from "@atproto/api";
import { RichText } from "@atproto/api";

export type CreatePostResult = {
  uri: string;
  cid: string;
};

export const createPost = async (
  agent: AtpAgent,
  text: string
): Promise<CreatePostResult> => {
  const rt = new RichText({ text });
  await rt.detectFacets(agent);

  const response = await agent.post({
    text: rt.text,
    facets: rt.facets,
    createdAt: new Date().toISOString(),
  });

  return {
    uri: response.uri,
    cid: response.cid,
  };
};

export const createReply = async (
  agent: AtpAgent,
  text: string,
  parentUri: string,
  parentCid: string,
  rootUri?: string,
  rootCid?: string
): Promise<CreatePostResult> => {
  const rt = new RichText({ text });
  await rt.detectFacets(agent);

  const response = await agent.post({
    text: rt.text,
    facets: rt.facets,
    reply: {
      root: {
        uri: rootUri ?? parentUri,
        cid: rootCid ?? parentCid,
      },
      parent: {
        uri: parentUri,
        cid: parentCid,
      },
    },
    createdAt: new Date().toISOString(),
  });

  return {
    uri: response.uri,
    cid: response.cid,
  };
};

export const likePost = async (
  agent: AtpAgent,
  uri: string,
  cid: string
): Promise<string> => {
  const response = await agent.like(uri, cid);
  return response.uri;
};

export const unlikePost = async (
  agent: AtpAgent,
  likeUri: string
): Promise<void> => {
  await agent.deleteLike(likeUri);
};

export const deletePost = async (
  agent: AtpAgent,
  postUri: string
): Promise<void> => {
  await agent.deletePost(postUri);
};

import type { AtpAgent } from "@atproto/api";
import type { ProfileData } from "./types";

export const getProfile = async (
  agent: AtpAgent,
  actor: string
): Promise<ProfileData> => {
  const response = await agent.getProfile({ actor });
  const profile = response.data;

  return {
    did: profile.did,
    handle: profile.handle,
    displayName: profile.displayName ?? profile.handle,
    description: profile.description ?? "",
    avatar: profile.avatar,
    banner: profile.banner,
    followersCount: profile.followersCount ?? 0,
    followsCount: profile.followsCount ?? 0,
    postsCount: profile.postsCount ?? 0,
    followUri: profile.viewer?.following,
  };
};

export const followUser = async (
  agent: AtpAgent,
  did: string
): Promise<string> => {
  const response = await agent.follow(did);
  return response.uri;
};

export const unfollowUser = async (
  agent: AtpAgent,
  followUri: string
): Promise<void> => {
  await agent.deleteFollow(followUri);
};

export const searchUsers = async (
  agent: AtpAgent,
  query: string,
  limit = 10
): Promise<ProfileData[]> => {
  const response = await agent.searchActors({
    term: query,
    limit,
  });

  return response.data.actors.map((actor) => ({
    did: actor.did,
    handle: actor.handle,
    displayName: actor.displayName ?? actor.handle,
    description: actor.description ?? "",
    avatar: actor.avatar,
    banner: undefined,
    followersCount: actor.viewer ? 0 : 0,
    followsCount: 0,
    postsCount: 0,
    followUri: actor.viewer?.following,
  }));
};

