const AvatarEl = ({ author }: { author: { avatar?: string; displayName: string } }) => {
  if (author.avatar) {
    return h("img", { src: author.avatar, alt: author.displayName, style: styles.avatar });
  }
  const initial = author.displayName.charAt(0).toUpperCase();
  return h("div", { style: styles.avatarPlaceholder }, initial);
};

const PostCard = ({ post }: { post: PostData }) => {
  return h(Fragment, {},
    post.isRepost && post.repostedBy
      ? h("div", { style: styles.repostBanner },
          "\u{1F501} Reposted by ",
          h("span", { style: { fontWeight: "600" } }, post.repostedBy.displayName)
        )
      : null,
    h("div", { style: styles.postCard },
      AvatarEl({ author: post.author }),
      h("div", { style: styles.postBody },
        h("div", { style: styles.authorRow },
          h("span", { style: styles.displayName }, post.author.displayName),
          h("span", { style: styles.handle }, `@${post.author.handle}`),
          h("span", { style: styles.timestamp }, ` \u00B7 ${formatTimestamp(post.createdAt)}`)
        ),
        h("div", { style: styles.postText }, post.text),
        h("div", { style: styles.actions },
          h("button", {
            style: styles.actionBtn,
            "p-trigger": "click:reply",
            "data-uri": post.uri,
            "data-cid": post.cid,
          }, `\u{1F4AC} ${post.replyCount}`),
          h("button", {
            style: styles.actionBtn,
            "p-trigger": "click:repost",
            "data-uri": post.uri,
          }, `\u{1F501} ${post.repostCount}`),
          h("button", {
            style: post.likeUri ? styles.actionBtnLiked : styles.actionBtn,
            "p-trigger": "click:toggleLike",
            "data-uri": post.uri,
            "data-cid": post.cid,
            "data-like-uri": post.likeUri ?? "",
          }, `${post.likeUri ? "\u2764\uFE0F" : "\u{1F90D}"} ${post.likeCount}`)
        )
      )
    )
  );
};

export const renderTimeline = (timeline: TimelineResponse): string => {
  const template = h("div", { style: styles.container },
    h("div", { style: styles.header },
      h("h1", { style: styles.headerTitle }, "Bluesky"),
      h("button", {
        style: { ...styles.postBtn, backgroundColor: "#ffffff", color: "#0085ff" },
        "p-trigger": "click:compose",
      }, "New Post")
    ),
    h("div", { "p-target": "compose-area" }),
    h("div", { "p-target": "feed" },
      ...timeline.posts.map((post) => PostCard({ post }))
    ),
    timeline.cursor
      ? h("div", { style: { padding: "16px", textAlign: "center" } },
          h("button", {
            style: { ...styles.actionBtn, color: "#0085ff", margin: "0 auto" },
            "p-trigger": "click:loadMore",
            "data-cursor": timeline.cursor,
          }, "Load more")
        )
      : null
  );

  return createSSR(template);
};

