    h("div", { style: styles.profileInfo },
      profile.avatar
        ? h("img", { src: profile.avatar, alt: profile.displayName, style: styles.profileAvatar })
        : h("div", {
            style: {
              ...styles.avatarPlaceholder,
              width: "80px",
              height: "80px",
              fontSize: "32px",
              marginTop: "-40px",
              border: "4px solid #ffffff",
            },
          }, profile.displayName.charAt(0).toUpperCase()),
      h("div", { style: styles.profileDisplayName }, profile.displayName),
      h("div", { style: styles.profileHandle }, `@${profile.handle}`),
      profile.description
        ? h("div", { style: styles.profileBio }, profile.description)
        : null,
      h("div", { style: styles.stats },
        h("span", {},
          h("span", { style: styles.statCount }, String(profile.followsCount)),
          h("span", { style: styles.statLabel }, " Following")
        ),
        h("span", {},
          h("span", { style: styles.statCount }, String(profile.followersCount)),
          h("span", { style: styles.statLabel }, " Followers")
        ),
        h("span", {},
          h("span", { style: styles.statCount }, String(profile.postsCount)),
          h("span", { style: styles.statLabel }, " Posts")
        )
      ),
      profile.followUri
        ? h("button", {
            style: styles.unfollowBtn,
            "p-trigger": "click:unfollow",
            "data-follow-uri": profile.followUri,
          }, "Following")
        : h("button", {
            style: styles.followBtn,
            "p-trigger": "click:follow",
            "data-did": profile.did,
          }, "Follow")
    )
  );

  return createSSR(template);
};

