        h("input", {
          style: styles.input,
          type: "text",
          placeholder: "you.bsky.social",
          "p-target": "identifier",
        })
      ),
      h("div", { style: styles.inputGroup },
        h("label", { style: styles.inputLabel }, "App Password"),
        h("input", {
          style: styles.input,
          type: "password",
          placeholder: "xxxx-xxxx-xxxx-xxxx",
