  );

  return createSSR(template);
};

import { AtpAgent } from "@atproto/api";
import { authenticate, resumeSession, clearSession } from "./auth";
import { getTimeline, getAuthorFeed } from "./feed";
import { createPost, createReply, likePost, unlikePost, deletePost } from "./posts";
import { getProfile, followUser, unfollowUser, searchUsers } from "./profiles";
import { renderTimeline, renderProfile, renderCompose, renderLogin, renderPost } from "./render";
import type { Credentials, SessionData, PostData, ProfileData, TimelineResponse } from "./types";

export type BlueskyClient = {
  login: (credentials: Credentials) => Promise<SessionData>;
  restoreSession: () => Promise<SessionData | null>;
  logout: () => Promise<void>;
  getTimeline: (cursor?: string, limit?: number) => Promise<TimelineResponse>;
  getAuthorFeed: (actor: string, cursor?: string, limit?: number) => Promise<TimelineResponse>;
  createPost: (text: string) => Promise<{ uri: string; cid: string }>;
  createReply: (text: string, parentUri: string, parentCid: string, rootUri?: string, rootCid?: string) => Promise<{ uri: string; cid: string }>;
  likePost: (uri: string, cid: string) => Promise<string>;
  unlikePost: (likeUri: string) => Promise<void>;
  deletePost: (postUri: string) => Promise<void>;
  getProfile: (actor: string) => Promise<ProfileData>;
  followUser: (did: string) => Promise<string>;
  unfollowUser: (followUri: string) => Promise<void>;
  searchUsers: (query: string, limit?: number) => Promise<ProfileData[]>;
  renderTimeline: (timeline: TimelineResponse) => string;
  renderProfile: (profile: ProfileData) => string;
  renderCompose: () => string;
  renderLogin: (error?: string) => string;
  renderPost: (post: PostData) => string;
  agent: AtpAgent;
};

const BLUESKY_SERVICE = "https://bsky.social";

export const createBlueskyClient = async (
  credentials?: Credentials
): Promise<BlueskyClient> => {
  const agent = new AtpAgent({ service: BLUESKY_SERVICE });

  if (credentials) {
    await authenticate(agent, credentials);
  } else {
    await resumeSession(agent);
  }

  const client: BlueskyClient = {
    login: (creds) => authenticate(agent, creds),
    restoreSession: () => resumeSession(agent),
    logout: clearSession,
    getTimeline: (cursor?, limit?) => getTimeline(agent, cursor, limit),
    getAuthorFeed: (actor, cursor?, limit?) => getAuthorFeed(agent, actor, cursor, limit),
    createPost: (text) => createPost(agent, text),
    createReply: (text, parentUri, parentCid, rootUri?, rootCid?) =>
      createReply(agent, text, parentUri, parentCid, rootUri, rootCid),
    likePost: (uri, cid) => likePost(agent, uri, cid),
    unlikePost: (likeUri) => unlikePost(agent, likeUri),
    deletePost: (postUri) => deletePost(agent, postUri),
    getProfile: (actor) => getProfile(agent, actor),
    followUser: (did) => followUser(agent, did),
    unfollowUser: (followUri) => unfollowUser(agent, followUri),
    searchUsers: (query, limit?) => searchUsers(agent, query, limit),
    renderTimeline,
    renderProfile,
    renderCompose,
    renderLogin,
    renderPost,
    agent,
  };

  return client;
};

