import { BskyAgent, RichText } from '@atproto/api'
import type {
  Session,
  PostRecord,
  ProfileView,
  TimelineResponse,
  AuthCredentials,
  StoredSession,
} from './types'

const SESSION_PATH = './data/session.json'

const agent = new BskyAgent({ service: 'https://bsky.social' })

const saveSession = async (identifier: string, session: Session): Promise<void> => {
  const stored: StoredSession = {
    identifier,
    session,
    savedAt: new Date().toISOString(),
  }
  await Bun.write(SESSION_PATH, JSON.stringify(stored, null, 2))
}

const loadSession = async (): Promise<StoredSession | null> => {
  const file = Bun.file(SESSION_PATH)
  if (!(await file.exists())) return null
  const text = await file.text()
  return JSON.parse(text) as StoredSession
}

export const authenticate = async (credentials: AuthCredentials): Promise<Session> => {
  const response = await agent.login({
    identifier: credentials.identifier,
    password: credentials.password,
  })

  const session: Session = {
    did: response.data.did,
    handle: response.data.handle,
    accessJwt: response.data.accessJwt,
    refreshJwt: response.data.refreshJwt,
  }

  await saveSession(credentials.identifier, session)
  return session
}

export const resumeSession = async (): Promise<Session | null> => {
  const stored = await loadSession()
  if (!stored) return null

  try {
    await agent.resumeSession({
      did: stored.session.did,
      handle: stored.session.handle,
      accessJwt: stored.session.accessJwt,
      refreshJwt: stored.session.refreshJwt,
      active: true,
    })
    return stored.session
  } catch {
    return null
  }
}

export const getTimeline = async (cursor?: string, limit = 30): Promise<TimelineResponse> => {
  const response = await agent.getTimeline({ cursor, limit })

  const posts: PostRecord[] = response.data.feed.map((item) => {
    const post = item.post
    const record = post.record as { text: string; createdAt: string }
    const author = post.author

    return {
      uri: post.uri,
      cid: post.cid,
      author: {
        did: author.did,
        handle: author.handle,
        displayName: author.displayName ?? author.handle,
        avatar: author.avatar,
      },
      text: record.text,
      createdAt: record.createdAt,
      likeCount: post.likeCount ?? 0,
      repostCount: post.repostCount ?? 0,
      replyCount: post.replyCount ?? 0,
      likeUri: post.viewer?.like,
    }
  })

  return {
    posts,
    cursor: response.data.cursor,
  }
}

export const createPost = async (text: string): Promise<{ uri: string; cid: string }> => {
  const rt = new RichText({ text })
  await rt.detectFacets(agent)

  const response = await agent.post({
    text: rt.text,
    facets: rt.facets,
    createdAt: new Date().toISOString(),
  })

  return { uri: response.uri, cid: response.cid }
}

export const getProfile = async (handle: string): Promise<ProfileView> => {
  const response = await agent.getProfile({ actor: handle })
  const profile = response.data

  return {
    did: profile.did,
    handle: profile.handle,
    displayName: profile.displayName ?? profile.handle,
    description: profile.description ?? '',
    avatar: profile.avatar,
    banner: profile.banner,
    followersCount: profile.followersCount ?? 0,
    followsCount: profile.followsCount ?? 0,
    postsCount: profile.postsCount ?? 0,
    followUri: profile.viewer?.following,
  }
}

export const likePost = async (uri: string, cid: string): Promise<{ uri: string }> => {
  const response = await agent.like(uri, cid)
  return { uri: response.uri }
}

export const unlikePost = async (likeUri: string): Promise<void> => {
  await agent.deleteLike(likeUri)
}

export const followUser = async (did: string): Promise<{ uri: string }> => {
  const response = await agent.follow(did)
  return { uri: response.uri }
}

export const unfollowUser = async (followUri: string): Promise<void> => {
  await agent.deleteFollow(followUri)
}

export const getAgent = (): BskyAgent => agent

