export const handleLogin = async (credentials: AuthCredentials) => {
  const session = await authenticate(credentials)
  const timeline = await getTimeline()
  return {
    session,
    composerHTML: renderToHTML(renderComposer()),
    feedHTML: renderToHTML(renderFeed(timeline.posts)),
    cursor: timeline.cursor,
  }
}

export const handleResume = async () => {
  const session = await resumeSession()
  if (!session) {
    return { authenticated: false as const, html: renderToHTML(renderLoginForm()) }
  }
  const timeline = await getTimeline()
  return {
    authenticated: true as const,
    session,
    composerHTML: renderToHTML(renderComposer()),
    feedHTML: renderToHTML(renderFeed(timeline.posts)),
    cursor: timeline.cursor,
  }
}

export const handleLoadMore = async (cursor: string) => {
  const timeline = await getTimeline(cursor)
  return {
    feedHTML: renderToHTML(renderFeed(timeline.posts)),
    cursor: timeline.cursor,
  }
}

export const handleCreatePost = async (text: string) => {
  const result = await createPost(text)
  const timeline = await getTimeline()
  return {
    post: result,
    feedHTML: renderToHTML(renderFeed(timeline.posts)),
  }
}

export const handleViewProfile = async (handle: string) => {
  const profile = await getProfile(handle)
  return {
    profile,
    profileHTML: renderToHTML(renderProfile(profile)),
  }
}

export const handleLike = async (uri: string, cid: string) => {
  const result = await likePost(uri, cid)
  return { likeUri: result.uri }
}

export const handleUnlike = async (likeUri: string) => {
  await unlikePost(likeUri)
  return { unliked: true }
}

export const handleFollow = async (did: string) => {
  const result = await followUser(did)
  return { followUri: result.uri }
}

export const handleUnfollow = async (followUri: string) => {
  await unfollowUser(followUri)
  return { unfollowed: true }
}

