import type { SessionData } from "./types";

const SESSION_PATH = `${import.meta.dir}/data/session.json`;

export const saveSession = async (session: SessionData): Promise<void> => {
  await Bun.write(SESSION_PATH, JSON.stringify(session, null, 2));
};

export const loadSession = async (): Promise<SessionData | null> => {
  const file = Bun.file(SESSION_PATH);
  const exists = await file.exists();
  if (!exists) return null;
  try {
    const text = await file.text();
    return JSON.parse(text) as SessionData;
  } catch {
    return null;
  }
};

export const clearSession = async (): Promise<void> => {
  const file = Bun.file(SESSION_PATH);
  const exists = await file.exists();
  if (exists) {
    await Bun.write(SESSION_PATH, "");
  }
};

import { BskyAgent } from "@atproto/api";
import type {
  LoginCredentials,
  SessionData,
  PostRecord,
  TimelineOptions,
  TimelineResult,
  ProfileView,
  CreatePostOptions,
} from "./types";
import { saveSession, loadSession, clearSession } from "./session";

export type BlueskyClient = {
  agent: BskyAgent;
  login: (credentials: LoginCredentials) => Promise<SessionData>;
  resumeSession: () => Promise<SessionData | null>;
  logout: () => Promise<void>;
  getTimeline: (options?: TimelineOptions) => Promise<TimelineResult>;
  createPost: (options: CreatePostOptions) => Promise<{ uri: string; cid: string }>;
  likePost: (uri: string, cid: string) => Promise<{ uri: string }>;
  unlikePost: (likeUri: string) => Promise<void>;
  getProfile: (actor: string) => Promise<ProfileView>;
  follow: (did: string) => Promise<{ uri: string }>;
  unfollow: (followUri: string) => Promise<void>;
};

const mapFeedPost = (item: { post: any }): PostRecord => {
  const { post } = item;
  const record = post.record as { text?: string; createdAt?: string };
  const viewer = post.viewer ?? {};

  return {
    uri: post.uri,
    cid: post.cid,
    author: {
      did: post.author.did,
      handle: post.author.handle,
      displayName: post.author.displayName ?? post.author.handle,
      avatar: post.author.avatar,
    },
    text: record.text ?? "",
    createdAt: record.createdAt ?? post.indexedAt,
    likeCount: post.likeCount ?? 0,
    replyCount: post.replyCount ?? 0,
    repostCount: post.repostCount ?? 0,
    isLiked: !!viewer.like,
    likeUri: viewer.like,
  };
};

export const createBlueskyClient = (): BlueskyClient => {
  const agent = new BskyAgent({ service: "https://bsky.social" });

  const login = async (credentials: LoginCredentials): Promise<SessionData> => {
    const response = await agent.login({
      identifier: credentials.identifier,
      password: credentials.password,
    });
    const session: SessionData = {
      did: response.data.did,
      handle: response.data.handle,
      accessJwt: response.data.accessJwt,
      refreshJwt: response.data.refreshJwt,
    };
    await saveSession(session);
    return session;
  };

  const resumeSession = async (): Promise<SessionData | null> => {
    const stored = await loadSession();
    if (!stored) return null;
    try {
      await agent.resumeSession({
        did: stored.did,
        handle: stored.handle,
        accessJwt: stored.accessJwt,
        refreshJwt: stored.refreshJwt,
        active: true,
      });
      const refreshed: SessionData = {
        did: agent.session?.did ?? stored.did,
        handle: agent.session?.handle ?? stored.handle,
        accessJwt: agent.session?.accessJwt ?? stored.accessJwt,
        refreshJwt: agent.session?.refreshJwt ?? stored.refreshJwt,
      };
      await saveSession(refreshed);
      return refreshed;
    } catch {
      await clearSession();
      return null;
    }
  };

  const logout = async (): Promise<void> => {
    await clearSession();
  };

  const getTimeline = async (options?: TimelineOptions): Promise<TimelineResult> => {
    const response = await agent.getTimeline({
      limit: options?.limit ?? 25,
      cursor: options?.cursor,
    });
    const posts = response.data.feed.map(mapFeedPost);
    return {
      posts,
      cursor: response.data.cursor,
    };
  };

  const createPost = async (
    options: CreatePostOptions,
  ): Promise<{ uri: string; cid: string }> => {
    const response = await agent.post({
      text: options.text,
      createdAt: new Date().toISOString(),
    });
    return { uri: response.uri, cid: response.cid };
  };

  const likePost = async (uri: string, cid: string): Promise<{ uri: string }> => {
    const response = await agent.like(uri, cid);
    return { uri: response.uri };
  };

  const unlikePost = async (likeUri: string): Promise<void> => {
    await agent.deleteLike(likeUri);
  };

  const getProfile = async (actor: string): Promise<ProfileView> => {
    const response = await agent.getProfile({ actor });
    const data = response.data;
    const viewer = data.viewer ?? {};

    return {
      did: data.did,
      handle: data.handle,
      displayName: data.displayName ?? data.handle,
      description: data.description ?? "",
      avatar: data.avatar,
      banner: data.banner,
      followersCount: data.followersCount ?? 0,
      followsCount: data.followsCount ?? 0,
      postsCount: data.postsCount ?? 0,
      isFollowing: !!viewer.following,
      followUri: viewer.following,
    };
  };

  const follow = async (did: string): Promise<{ uri: string }> => {
    const response = await agent.follow(did);
    return { uri: response.uri };
  };

  const unfollow = async (followUri: string): Promise<void> => {
    await agent.deleteFollow(followUri);
  };

  return {
    agent,
    login,
    resumeSession,
    logout,
    getTimeline,
    createPost,
    likePost,
    unlikePost,
    getProfile,
    follow,
    unfollow,
  };
};

