export const renderPost = (post: PostRecord): string => {
  const avatarEl = post.author.avatar
    ? h("img", { src: post.author.avatar, alt: post.author.displayName, style: styles.avatar })
    : h("div", { style: styles.avatar });

  const likeStyle = post.isLiked ? styles.actionBtnLiked : styles.actionBtn;
  const likeLabel = post.isLiked ? "\u2764\uFE0F" : "\u2661";

  const template = h("article", { style: styles.postCard, "data-uri": post.uri, "data-cid": post.cid },
    h("div", { style: styles.postHeader },
      avatarEl,
      h("div", { style: styles.authorInfo },
        h("span", { style: styles.displayName }, post.author.displayName),
        h("span", { style: styles.handle }, `@${post.author.handle}`),
      ),
      h("time", { style: styles.timestamp, datetime: post.createdAt }, formatTimestamp(post.createdAt)),
    ),
    h("div", { style: styles.postText }, post.text),
    h("div", { style: styles.actions },
      h("button", {
        style: styles.actionBtn,
        "p-trigger": "click:reply",
        "data-uri": post.uri,
      }, "\uD83D\uDCAC ", String(post.replyCount)),
      h("button", {
        style: styles.actionBtn,
        "p-trigger": "click:repost",
        "data-uri": post.uri,
      }, "\uD83D\uDD01 ", String(post.repostCount)),
      h("button", {
        style: likeStyle,
        "p-trigger": "click:toggleLike",
        "data-uri": post.uri,
        "data-cid": post.cid,
        "data-like-uri": post.likeUri ?? "",
      }, `${likeLabel} `, String(post.likeCount)),
    ),
  );
  const { render } = createSSR();
  return render(template);
};

export const renderTimeline = (posts: PostRecord[], cursor?: string): string => {
  const postElements = posts.map((post) => {
    const avatarEl = post.author.avatar
      ? h("img", { src: post.author.avatar, alt: post.author.displayName, style: styles.avatar })
      : h("div", { style: styles.avatar });

    const likeStyle = post.isLiked ? styles.actionBtnLiked : styles.actionBtn;
    const likeLabel = post.isLiked ? "\u2764\uFE0F" : "\u2661";

    return h("article", { style: styles.postCard, "data-uri": post.uri, "data-cid": post.cid },
      h("div", { style: styles.postHeader },
        avatarEl,
        h("div", { style: styles.authorInfo },
          h("span", { style: styles.displayName }, post.author.displayName),
          h("span", { style: styles.handle }, `@${post.author.handle}`),
        ),
        h("time", { style: styles.timestamp, datetime: post.createdAt }, formatTimestamp(post.createdAt)),
      ),
      h("div", { style: styles.postText }, post.text),
      h("div", { style: styles.actions },
        h("button", {
          style: styles.actionBtn,
          "p-trigger": "click:reply",
          "data-uri": post.uri,
        }, "\uD83D\uDCAC ", String(post.replyCount)),
        h("button", {
          style: styles.actionBtn,
          "p-trigger": "click:repost",
          "data-uri": post.uri,
        }, "\uD83D\uDD01 ", String(post.repostCount)),
        h("button", {
          style: likeStyle,
          "p-trigger": "click:toggleLike",
          "data-uri": post.uri,
          "data-cid": post.cid,
          "data-like-uri": post.likeUri ?? "",
        }, `${likeLabel} `, String(post.likeCount)),
      ),
    );
  });

  const loadMoreEl = cursor
    ? h("button", {
        style: { ...styles.submitBtn, margin: "16px", width: "calc(100% - 32px)" },
        "p-trigger": "click:loadMore",
        "data-cursor": cursor,
      }, "Load More")
    : null;

  const template = h("div", { style: styles.container },
    h("div", { style: styles.header },
      h("span", { style: styles.headerTitle }, "Bluesky"),
      h("button", {
        style: styles.actionBtn,
        "p-trigger": "click:compose",
      }, "\u270F\uFE0F New Post"),
    ),
    h("div", { "p-target": "compose-area" }),
    ...postElements,
    ...(loadMoreEl ? [loadMoreEl] : []),
  );
  const { render } = createSSR();
  return render(template);
};

