export const renderProfile = (profile: ProfileView): string => {
  const avatarEl = profile.avatar
    ? h("img", { src: profile.avatar, alt: profile.displayName, style: styles.profileAvatar })
    : h("div", { style: styles.profileAvatar });

  const bannerEl = profile.banner
    ? h("img", { src: profile.banner, alt: "Banner", style: styles.profileBanner })
    : h("div", { style: { ...styles.profileBanner, height: "100px" } });

  const followBtnEl = profile.isFollowing
    ? h("button", {
        style: styles.unfollowBtn,
        "p-trigger": "click:unfollow",
        "data-follow-uri": profile.followUri ?? "",
      }, "Following")
    : h("button", {
        style: styles.followBtn,
        "p-trigger": "click:follow",
        "data-did": profile.did,
      }, "Follow");

  const template = h("div", { style: styles.container },
    h("div", { style: styles.header },
      h("button", {
        style: styles.actionBtn,
        "p-trigger": "click:back",
      }, "\u2190 Back"),
      h("span", { style: styles.headerTitle }, "Profile"),
    ),
    h("div", { style: styles.profileCard },
      bannerEl,
      h("div", { style: styles.profileHeader },
        avatarEl,
        h("div", { style: { flex: "1" } },
          h("div", { style: styles.profileName }, profile.displayName),
          h("div", { style: styles.profileHandle }, `@${profile.handle}`),
        ),
        followBtnEl,
      ),
      profile.description
        ? h("p", { style: styles.profileBio }, profile.description)
        : null,
      h("div", { style: styles.profileStats },
        h("span", {},
          h("span", { style: styles.statValue }, String(profile.followersCount)),
          h("span", { style: styles.statLabel }, " followers"),
        ),
        h("span", {},
          h("span", { style: styles.statValue }, String(profile.followsCount)),
          h("span", { style: styles.statLabel }, " following"),
        ),
        h("span", {},
          h("span", { style: styles.statValue }, String(profile.postsCount)),
          h("span", { style: styles.statLabel }, " posts"),
        ),
      ),
    ),
  );
  const { render } = createSSR();
  return render(template);
};

