export type GetThreadsInput = {
  sort?: SortMode
  search?: string
}

export type ThreadDetail = Thread & {
  replies: ReplyWithChildren[]
}

export type ReplyWithChildren = Reply & {
  children: Reply[]
}

import type { Thread, Reply } from './types'

const THREADS_PATH = './data/threads.json'
const REPLIES_PATH = './data/replies.json'

export const readThreads = async (): Promise<Thread[]> => {
  const file = Bun.file(THREADS_PATH)
  const text = await file.text()
  return JSON.parse(text) as Thread[]
}

export const writeThreads = async (threads: Thread[]): Promise<void> => {
  await Bun.write(THREADS_PATH, JSON.stringify(threads, null, 2))
}

export const readReplies = async (): Promise<Reply[]> => {
  const file = Bun.file(REPLIES_PATH)
  const text = await file.text()
  return JSON.parse(text) as Reply[]
}

export const writeReplies = async (replies: Reply[]): Promise<void> => {
  await Bun.write(REPLIES_PATH, JSON.stringify(replies, null, 2))
}

import { readThreads, writeThreads, readReplies, writeReplies } from './store'
import type {
  Thread,
  Reply,
  CreateThreadInput,
  CreateReplyInput,
  VoteInput,
  GetThreadsInput,
  ThreadSummary,
  ThreadDetail,
  ReplyWithChildren,
  SortMode,
} from './types'

const generateId = (): string => crypto.randomUUID()

export const createThread = async (input: CreateThreadInput): Promise<Thread> => {
  const threads = await readThreads()
  const thread: Thread = {
    id: generateId(),
    title: input.title.trim(),
    body: input.body.trim(),
    author: input.author.trim(),
    createdAt: new Date().toISOString(),
    upvotes: 0,
    downvotes: 0,
  }
  threads.push(thread)
  await writeThreads(threads)
  return thread
}

export const replyToThread = async (input: CreateReplyInput): Promise<Reply> => {
  const threads = await readThreads()
  const thread = threads.find((t) => t.id === input.threadId)
  if (!thread) {
    throw new Error(`Thread not found: ${input.threadId}`)
  }

  if (input.parentReplyId) {
    const replies = await readReplies()
    const parent = replies.find((r) => r.id === input.parentReplyId)
    if (!parent) {
      throw new Error(`Parent reply not found: ${input.parentReplyId}`)
    }
    if (parent.parentReplyId !== null) {
      throw new Error('Cannot nest replies more than one level deep')
    }
  }

  const replies = await readReplies()
  const reply: Reply = {
    id: generateId(),
    threadId: input.threadId,
    parentReplyId: input.parentReplyId ?? null,
    body: input.body.trim(),
    author: input.author.trim(),
    createdAt: new Date().toISOString(),
    upvotes: 0,
    downvotes: 0,
  }
  replies.push(reply)
  await writeReplies(replies)
  return reply
}

export const vote = async (input: VoteInput): Promise<void> => {
  if (input.targetType === 'thread') {
    const threads = await readThreads()
    const thread = threads.find((t) => t.id === input.targetId)
    if (!thread) throw new Error(`Thread not found: ${input.targetId}`)
    if (input.direction === 'up') thread.upvotes++
    else thread.downvotes++
    await writeThreads(threads)
  } else {
    const replies = await readReplies()
    const reply = replies.find((r) => r.id === input.targetId)
    if (!reply) throw new Error(`Reply not found: ${input.targetId}`)
    if (input.direction === 'up') reply.upvotes++
    else reply.downvotes++
    await writeReplies(replies)
  }
}

const scoreOf = (item: { upvotes: number; downvotes: number }): number =>
  item.upvotes - item.downvotes

const sortThreadSummaries = (summaries: ThreadSummary[], mode: SortMode): ThreadSummary[] => {
  const sorted = [...summaries]
  switch (mode) {
    case 'newest':
      return sorted.sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime())
    case 'most-upvoted':
      return sorted.sort((a, b) => b.score - a.score)
    case 'most-active':
      return sorted.sort((a, b) => b.replyCount - a.replyCount)
  }
}

export const getThreads = async (input: GetThreadsInput = {}): Promise<ThreadSummary[]> => {
  const { sort = 'newest', search } = input
  const threads = await readThreads()
  const replies = await readReplies()

  let filtered = threads
  if (search && search.trim()) {
    const query = search.trim().toLowerCase()
    filtered = threads.filter((t) => t.title.toLowerCase().includes(query))
  }

  const summaries: ThreadSummary[] = filtered.map((t) => ({
    id: t.id,
    title: t.title,
    author: t.author,
    createdAt: t.createdAt,
    replyCount: replies.filter((r) => r.threadId === t.id).length,
    score: scoreOf(t),
  }))

  return sortThreadSummaries(summaries, sort)
}

export const getThreadDetail = async (threadId: string): Promise<ThreadDetail> => {
  const threads = await readThreads()
  const thread = threads.find((t) => t.id === threadId)
  if (!thread) throw new Error(`Thread not found: ${threadId}`)

  const allReplies = await readReplies()
  const threadReplies = allReplies.filter((r) => r.threadId === threadId)

  const topLevel = threadReplies.filter((r) => r.parentReplyId === null)
  const nested = threadReplies.filter((r) => r.parentReplyId !== null)

  const repliesWithChildren: ReplyWithChildren[] = topLevel
    .sort((a, b) => new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime())
    .map((r) => ({
      ...r,
      children: nested
        .filter((n) => n.parentReplyId === r.id)
        .sort((a, b) => new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime()),
    }))

  return {
    ...thread,
    replies: repliesWithChildren,
  }
}

