import { createSSR } from 'plaited'
import { createThread, replyToThread, vote, getThreads, getThreadDetail } from './forum'
import { renderThreadList, renderNewThreadForm, renderThreadDetail } from './render'
import type { SortMode, VoteDirection, VoteTarget } from './types'

const ssr = createSSR()

type AppState = {
  view: 'list' | 'new-thread' | 'thread-detail'
  sort: SortMode
  search: string
  currentThreadId: string | null
}

const state: AppState = {
  view: 'list',
  sort: 'newest',
  search: '',
  currentThreadId: null,
}

const renderCurrentView = async (): Promise<string> => {
  switch (state.view) {
    case 'list': {
      const threads = await getThreads({ sort: state.sort, search: state.search })
      return ssr(renderThreadList(threads, state.sort, state.search))
    }
    case 'new-thread':
      return ssr(renderNewThreadForm())
    case 'thread-detail': {
      if (!state.currentThreadId) {
        state.view = 'list'
        const threads = await getThreads({ sort: state.sort })
        return ssr(renderThreadList(threads, state.sort, state.search))
      }
      const detail = await getThreadDetail(state.currentThreadId)
      return ssr(renderThreadDetail(detail))
    }
  }
}

const htmlPage = async (): Promise<string> => {
  const content = await renderCurrentView()
  return `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Discussion Forum</title>
  <style>
    * { box-sizing: border-box; }
    body { margin: 0; background: #f5f5f5; }
  </style>
</head>
<body>${content}</body>
</html>`
}

const parseFormData = async (req: Request): Promise<Record<string, string>> => {
  const formData = await req.formData()
  const data: Record<string, string> = {}
  formData.forEach((value, key) => {
    data[key] = String(value)
  })
  return data
}

const handleAction = async (action: string, req: Request): Promise<Response> => {
  if (action === 'show-new-thread-form') {
    state.view = 'new-thread'
  } else if (action === 'back-to-list') {
    state.view = 'list'
    state.currentThreadId = null
  } else if (action.startsWith('sort:')) {
    state.sort = action.replace('sort:', '') as SortMode
    state.view = 'list'
  } else if (action.startsWith('open-thread:')) {
    state.currentThreadId = action.replace('open-thread:', '')
    state.view = 'thread-detail'
  } else if (action === 'submit-thread') {
    const data = await parseFormData(req)
    const thread = await createThread({
      title: data.title || 'Untitled',
      body: data.body || '',
      author: data.author || 'Anonymous',
    })
    state.currentThreadId = thread.id
    state.view = 'thread-detail'
  } else if (action.startsWith('submit-reply:')) {
    const threadId = action.replace('submit-reply:', '')
    const data = await parseFormData(req)
    await replyToThread({
      threadId,
      parentReplyId: data.parentReplyId || null,
      body: data.body || '',
      author: data.author || 'Anonymous',
    })
    state.currentThreadId = threadId
    state.view = 'thread-detail'
  } else if (action.startsWith('vote-')) {
    const parts = action.split(':')
    const direction = parts[0] === 'vote-up' ? 'up' : 'down'
    const targetType = parts[1] as VoteTarget
    const targetId = parts[2]
    await vote({ targetId, targetType, direction })
  } else if (action === 'search') {
    const data = await parseFormData(req)
    state.search = data.query || ''
    state.view = 'list'
  }

  const page = await htmlPage()
  return new Response(page, {
    headers: { 'Content-Type': 'text/html' },
  })
}

const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url)

    if (req.method === 'GET' && url.pathname === '/') {
      const page = await htmlPage()
      return new Response(page, {
        headers: { 'Content-Type': 'text/html' },
      })
    }

    if (req.method === 'POST' && url.pathname === '/action') {
      const action = url.searchParams.get('action') || ''
      return handleAction(action, req)
    }

    if (req.method === 'GET' && url.pathname === '/api/threads') {
      const sort = (url.searchParams.get('sort') as SortMode) || 'newest'
      const search = url.searchParams.get('search') || ''
      const threads = await getThreads({ sort, search })
      return Response.json(threads)
    }

    if (req.method === 'GET' && url.pathname.startsWith('/api/threads/')) {
      const threadId = url.pathname.replace('/api/threads/', '')
      const detail = await getThreadDetail(threadId)
      return Response.json(detail)
    }

    if (req.method === 'POST' && url.pathname === '/api/threads') {
      const body = await req.json()
      const thread = await createThread(body)
      return Response.json(thread, { status: 201 })
    }

    if (req.method === 'POST' && url.pathname === '/api/replies') {
      const body = await req.json()
      const reply = await replyToThread(body)
      return Response.json(reply, { status: 201 })
    }

    if (req.method === 'POST' && url.pathname === '/api/vote') {
      const body = await req.json()
      await vote(body)
      return Response.json({ ok: true })
    }

    return new Response('Not Found', { status: 404 })
  },
})

