import type { Thread, Reply, SortMode, CreateThreadInput, CreateReplyInput, VoteDirection } from './types'

const DATA_PATH = `${import.meta.dir}/data/threads.json`

const generateId = (): string => crypto.randomUUID()

const readThreads = async (): Promise<Thread[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  return text.trim() ? JSON.parse(text) : []
}

const writeThreads = async (threads: Thread[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(threads, null, 2))
}

export const getThreads = async (sort: SortMode = 'newest', query?: string): Promise<Thread[]> => {
  let threads = await readThreads()

  if (query) {
    const q = query.toLowerCase()
    threads = threads.filter((t) => t.title.toLowerCase().includes(q))
  }

  const getScore = (t: Thread): number => t.upvotes - t.downvotes

  const getLatestActivity = (t: Thread): number => {
    let latest = new Date(t.timestamp).getTime()
    for (const r of t.replies) {
      const rt = new Date(r.timestamp).getTime()
      if (rt > latest) latest = rt
      for (const c of r.children) {
        const ct = new Date(c.timestamp).getTime()
        if (ct > latest) latest = ct
      }
    }
    return latest
  }

  const replyCount = (t: Thread): number =>
    t.replies.reduce((sum, r) => sum + 1 + r.children.length, 0)

  switch (sort) {
    case 'newest':
      threads.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime())
      break
    case 'votes':
      threads.sort((a, b) => getScore(b) - getScore(a))
      break
    case 'active':
      threads.sort((a, b) => getLatestActivity(b) - getLatestActivity(a))
      break
  }

  return threads.map((t) => ({
    ...t,
    _replyCount: replyCount(t),
    _score: getScore(t),
  })) as (Thread & { _replyCount: number; _score: number })[]
}

export const getThread = async (id: string): Promise<Thread | undefined> => {
  const threads = await readThreads()
  return threads.find((t) => t.id === id)
}

export const createThread = async (input: CreateThreadInput): Promise<Thread> => {
  const threads = await readThreads()
  const thread: Thread = {
    id: generateId(),
    title: input.title,
    body: input.body,
    author: input.author,
    timestamp: new Date().toISOString(),
    upvotes: 0,
    downvotes: 0,
    replies: [],
  }
  threads.push(thread)
  await writeThreads(threads)
  return thread
}

export const addReply = async (threadId: string, input: CreateReplyInput): Promise<Reply | null> => {
  const threads = await readThreads()
  const thread = threads.find((t) => t.id === threadId)
  if (!thread) return null

  const reply: Reply = {
    id: generateId(),
    body: input.body,
    author: input.author,
    timestamp: new Date().toISOString(),
    upvotes: 0,
    downvotes: 0,
    children: [],
  }

  if (input.parentReplyId) {
    const parent = thread.replies.find((r) => r.id === input.parentReplyId)
    if (!parent) return null
    parent.children.push(reply)
  } else {
    thread.replies.push(reply)
  }

  await writeThreads(threads)
  return reply
}

export const voteThread = async (threadId: string, direction: VoteDirection): Promise<Thread | null> => {
  const threads = await readThreads()
  const thread = threads.find((t) => t.id === threadId)
  if (!thread) return null

  if (direction === 'up') thread.upvotes++
  else thread.downvotes++

  await writeThreads(threads)
  return thread
}

export const voteReply = async (
  threadId: string,
  replyId: string,
  direction: VoteDirection
): Promise<Reply | null> => {
  const threads = await readThreads()
  const thread = threads.find((t) => t.id === threadId)
  if (!thread) return null

  const findReply = (replies: Reply[]): Reply | undefined => {
    for (const r of replies) {
      if (r.id === replyId) return r
      const child = r.children.find((c) => c.id === replyId)
      if (child) return child
    }
    return undefined
  }

  const reply = findReply(thread.replies)
  if (!reply) return null

  if (direction === 'up') reply.upvotes++
  else reply.downvotes++

  await writeThreads(threads)
  return reply
}

