import type { SortMode, VoteDirection } from './types'
import { getThreads, getThread, createThread, addReply, voteThread, voteReply } from './store'
import { renderThreadList, renderThreadDetail, renderNewThreadForm, renderReplyForm } from './render'

const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const htmlResponse = (html: string): Response =>
  new Response(`<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Discussion Forum</title><style>*{box-sizing:border-box}body{margin:0;background:#fafafa}</style></head><body>${html}</body></html>`, {
    headers: { 'Content-Type': 'text/html' },
  })

const parseBody = async (req: Request): Promise<Record<string, unknown>> => {
  const ct = req.headers.get('content-type') ?? ''
  if (ct.includes('application/json')) return req.json()
  if (ct.includes('form')) {
    const form = await req.formData()
    const obj: Record<string, unknown> = {}
    form.forEach((v, k) => { obj[k] = v })
    return obj
  }
  return {}
}

export const startServer = (port = 3000) => {
  const server = Bun.serve({
    port,
    fetch: async (req) => {
      const url = new URL(req.url)
      const path = url.pathname
      const method = req.method

      // HTML pages
      if (method === 'GET' && path === '/') {
        const sort = (url.searchParams.get('sort') as SortMode) || 'newest'
        const q = url.searchParams.get('q') || ''
        const threads = await getThreads(sort, q || undefined)
        return htmlResponse(renderThreadList(threads, sort, q))
      }

      if (method === 'GET' && path === '/new') {
        return htmlResponse(renderNewThreadForm())
      }

      if (method === 'GET' && path.match(/^\/thread\/[^/]+$/)) {
        const id = path.split('/')[2]
        const thread = await getThread(id)
        if (!thread) return new Response('Thread not found', { status: 404 })
        return htmlResponse(renderThreadDetail(thread))
      }

      if (method === 'GET' && path.match(/^\/thread\/[^/]+\/reply$/)) {
        const id = path.split('/')[2]
        const parentReplyId = url.searchParams.get('parent') || undefined
        return htmlResponse(renderReplyForm(id, parentReplyId))
      }

      // API endpoints
      if (method === 'GET' && path === '/api/threads') {
        const sort = (url.searchParams.get('sort') as SortMode) || 'newest'
        const q = url.searchParams.get('q') || ''
        const threads = await getThreads(sort, q || undefined)
        return jsonResponse(threads)
      }

      if (method === 'GET' && path.match(/^\/api\/threads\/[^/]+$/)) {
        const id = path.split('/')[3]
        const thread = await getThread(id)
        if (!thread) return jsonResponse({ error: 'Thread not found' }, 404)
        return jsonResponse(thread)
      }

      if (method === 'POST' && path === '/api/threads') {
        const body = await parseBody(req)
        const title = String(body.title ?? '').trim()
        const bodyText = String(body.body ?? '').trim()
        const author = String(body.author ?? '').trim()
        if (!title || !bodyText || !author) {
          return jsonResponse({ error: 'title, body, and author are required' }, 400)
        }
        const thread = await createThread({ title, body: bodyText, author })
        return jsonResponse(thread, 201)
      }

      if (method === 'POST' && path.match(/^\/api\/threads\/[^/]+\/replies$/)) {
        const threadId = path.split('/')[3]
        const body = await parseBody(req)
        const bodyText = String(body.body ?? '').trim()
        const author = String(body.author ?? '').trim()
        const parentReplyId = body.parentReplyId ? String(body.parentReplyId) : undefined
        if (!bodyText || !author) {
          return jsonResponse({ error: 'body and author are required' }, 400)
        }
        const reply = await addReply(threadId, { body: bodyText, author, parentReplyId })
        if (!reply) return jsonResponse({ error: 'Thread or parent reply not found' }, 404)
        return jsonResponse(reply, 201)
      }

      if (method === 'POST' && path.match(/^\/api\/threads\/[^/]+\/vote$/)) {
        const threadId = path.split('/')[3]
        const body = await parseBody(req)
        const direction = String(body.direction) as VoteDirection
        if (direction !== 'up' && direction !== 'down') {
          return jsonResponse({ error: 'direction must be "up" or "down"' }, 400)
        }
        const thread = await voteThread(threadId, direction)
        if (!thread) return jsonResponse({ error: 'Thread not found' }, 404)
        return jsonResponse(thread)
      }

      if (method === 'POST' && path.match(/^\/api\/threads\/[^/]+\/replies\/[^/]+\/vote$/)) {
        const parts = path.split('/')
        const threadId = parts[3]
        const replyId = parts[5]
        const body = await parseBody(req)
        const direction = String(body.direction) as VoteDirection
        if (direction !== 'up' && direction !== 'down') {
          return jsonResponse({ error: 'direction must be "up" or "down"' }, 400)
        }
        const reply = await voteReply(threadId, replyId, direction)
        if (!reply) return jsonResponse({ error: 'Reply not found' }, 404)
        return jsonResponse(reply)
      }

      return new Response('Not Found', { status: 404 })
    },
  })

  console.log(`Discussion Forum running at http://localhost:${port}`)
  return server
}

