import type { Thread, Reply, SortMode, VoteDirection, ThreadSummary } from './types'

const DATA_PATH = `${import.meta.dir}/data/threads.jsonl`

const generateId = (): string => crypto.randomUUID()

const readThreads = async (): Promise<Thread[]> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return []
  const text = await file.text()
  if (!text.trim()) return []
  return text
    .trim()
    .split('\n')
    .map((line) => JSON.parse(line) as Thread)
}

const writeThreads = async (threads: Thread[]): Promise<void> => {
  const content = threads.map((t) => JSON.stringify(t)).join('\n')
  await Bun.write(DATA_PATH, content ? content + '\n' : '')
}

const getVoteScore = (item: { upvotes: number; downvotes: number }): number =>
  item.upvotes - item.downvotes

const getLastActivity = (thread: Thread): string => {
  if (thread.replies.length === 0) return thread.createdAt
  const sorted = [...thread.replies].sort(
    (a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
  )
  return sorted[0].createdAt
}

export const createThread = async (title: string, body: string, author: string): Promise<Thread> => {
  const threads = await readThreads()
  const thread: Thread = {
    id: generateId(),
    title,
    body,
    author,
    createdAt: new Date().toISOString(),
    upvotes: 0,
    downvotes: 0,
    replies: [],
  }
  threads.push(thread)
  await writeThreads(threads)
  return thread
}

export const getThread = async (threadId: string): Promise<Thread | null> => {
  const threads = await readThreads()
  return threads.find((t) => t.id === threadId) ?? null
}

export const addReply = async (
  threadId: string,
  body: string,
  author: string,
  parentReplyId: string | null = null
): Promise<Reply | null> => {
  const threads = await readThreads()
  const thread = threads.find((t) => t.id === threadId)
  if (!thread) return null

  if (parentReplyId) {
    const parentReply = thread.replies.find((r) => r.id === parentReplyId)
    if (!parentReply) return null
    if (parentReply.parentReplyId !== null) return null
  }

  const reply: Reply = {
    id: generateId(),
    threadId,
    parentReplyId,
    body,
    author,
    createdAt: new Date().toISOString(),
    upvotes: 0,
    downvotes: 0,
  }
  thread.replies.push(reply)
  await writeThreads(threads)
  return reply
}

export const voteThread = async (threadId: string, direction: VoteDirection): Promise<Thread | null> => {
  const threads = await readThreads()
  const thread = threads.find((t) => t.id === threadId)
  if (!thread) return null

  if (direction === 'up') thread.upvotes++
  else thread.downvotes++

  await writeThreads(threads)
  return thread
}

export const voteReply = async (
  threadId: string,
  replyId: string,
  direction: VoteDirection
): Promise<Reply | null> => {
  const threads = await readThreads()
  const thread = threads.find((t) => t.id === threadId)
  if (!thread) return null

  const reply = thread.replies.find((r) => r.id === replyId)
  if (!reply) return null

  if (direction === 'up') reply.upvotes++
  else reply.downvotes++

  await writeThreads(threads)
  return reply
}

export const listThreads = async (
  sort: SortMode = 'newest',
  search?: string
): Promise<ThreadSummary[]> => {
  let threads = await readThreads()

  if (search) {
    const query = search.toLowerCase()
    threads = threads.filter((t) => t.title.toLowerCase().includes(query))
  }

  const summaries: ThreadSummary[] = threads.map((t) => ({
    id: t.id,
    title: t.title,
    author: t.author,
    replyCount: t.replies.length,
    voteScore: getVoteScore(t),
    createdAt: t.createdAt,
    lastActivityAt: getLastActivity(t),
  }))

  const sortFns: Record<SortMode, (a: ThreadSummary, b: ThreadSummary) => number> = {
    newest: (a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime(),
    'most-upvoted': (a, b) => b.voteScore - a.voteScore,
    'most-active': (a, b) =>
      new Date(b.lastActivityAt).getTime() - new Date(a.lastActivityAt).getTime(),
  }

  return summaries.sort(sortFns[sort])
}

