const parseBody = async (req: Request): Promise<Record<string, string>> => {
  const contentType = req.headers.get('content-type') ?? ''
  if (contentType.includes('application/json')) {
    return req.json()
  }
  if (contentType.includes('application/x-www-form-urlencoded')) {
    const text = await req.text()
    const params = new URLSearchParams(text)
    return Object.fromEntries(params.entries())
  }
  return {}
}

const jsonResponse = (data: { html: string; status: number }) =>
  new Response(JSON.stringify(data), {
    status: data.status,
    headers: { 'Content-Type': 'application/json' },
  })

const htmlResponse = (data: { html: string; status: number }) =>
  new Response(data.html, {
    status: data.status,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const router = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const path = url.pathname
  const method = req.method

  const wantsJson = req.headers.get('accept')?.includes('application/json')
  const respond = wantsJson ? jsonResponse : htmlResponse

  // GET / — Thread list
  if (method === 'GET' && path === '/') {
    const sort = (url.searchParams.get('sort') as SortMode) ?? 'newest'
    const search = url.searchParams.get('search') ?? ''
    return respond(await handleListThreads(sort, search))
  }

  // GET /new — New thread form
  if (method === 'GET' && path === '/new') {
    return respond(handleNewThreadForm())
  }

  // POST /threads — Create thread
  if (method === 'POST' && path === '/threads') {
    const body = await parseBody(req)
    return respond(await handleCreateThread(body.title, body.body, body.author))
  }

  // GET /threads/:id — Thread detail
  const threadMatch = path.match(/^\/threads\/([^/]+)$/)
  if (method === 'GET' && threadMatch) {
    return respond(await handleGetThread(threadMatch[1]))
  }

  // POST /threads/:id/replies — Add reply
  const replyMatch = path.match(/^\/threads\/([^/]+)\/replies$/)
  if (method === 'POST' && replyMatch) {
    const body = await parseBody(req)
    return respond(
      await handleAddReply(replyMatch[1], body.body, body.author, body.parentReplyId || null)
    )
  }

  // POST /threads/:id/vote — Vote on thread
  const threadVoteMatch = path.match(/^\/threads\/([^/]+)\/vote$/)
  if (method === 'POST' && threadVoteMatch) {
    const body = await parseBody(req)
    return respond(
      await handleVoteThread(threadVoteMatch[1], body.direction as VoteDirection)
    )
  }

  // POST /threads/:id/replies/:replyId/vote — Vote on reply
  const replyVoteMatch = path.match(/^\/threads\/([^/]+)\/replies\/([^/]+)\/vote$/)
  if (method === 'POST' && replyVoteMatch) {
    const body = await parseBody(req)
    return respond(
      await handleVoteReply(replyVoteMatch[1], replyVoteMatch[2], body.direction as VoteDirection)
    )
  }

  return new Response('Not Found', { status: 404 })
}

export default {
  port: 3000,
  fetch: router,
}

export {
  handleListThreads,
  handleGetThread,
  handleCreateThread,
  handleAddReply,
  handleVoteThread,
  handleVoteReply,
}

