import type { FieldInfo, FieldType, ParsedData } from './types'

const detectFieldType = (values: unknown[]): FieldType => {
  const validValues = values.filter((v) => v !== null && v !== undefined && v !== '')
  if (validValues.length === 0) return 'categorical'

  const numericCount = validValues.filter((v) => {
    if (typeof v === 'number') return !Number.isNaN(v)
    if (typeof v === 'string') {
      const parsed = Number(v)
      return !Number.isNaN(parsed) && v.trim() !== ''
    }
    return false
  }).length

  return numericCount / validValues.length > 0.8 ? 'numeric' : 'categorical'
}

const coerceNumeric = (value: unknown): number => {
  if (typeof value === 'number') return value
  if (typeof value === 'string') {
    const parsed = Number(value)
    return Number.isNaN(parsed) ? 0 : parsed
  }
  return 0
}

export const parseJsonData = (jsonString: string): ParsedData => {
  const raw = JSON.parse(jsonString)

  if (!Array.isArray(raw) || raw.length === 0) {
    throw new Error('Input must be a non-empty array of objects')
  }

  const firstRecord = raw[0]
  if (typeof firstRecord !== 'object' || firstRecord === null || Array.isArray(firstRecord)) {
    throw new Error('Each element must be a plain object')
  }

  const fieldNames = Object.keys(firstRecord)
  if (fieldNames.length === 0) {
    throw new Error('Objects must have at least one field')
  }

  const fields: FieldInfo[] = fieldNames.map((name) => {
    const rawValues = raw.map((record: Record<string, unknown>) => record[name])
    const fieldType = detectFieldType(rawValues)

    const values: (string | number)[] = rawValues.map((v: unknown) =>
      fieldType === 'numeric' ? coerceNumeric(v) : String(v ?? '')
    )

    return { name, type: fieldType, values }
  })

  const numericFields = fields.filter((f) => f.type === 'numeric').map((f) => f.name)
  const categoricalFields = fields.filter((f) => f.type === 'categorical').map((f) => f.name)

  const records = raw.map((record: Record<string, unknown>) => {
    const coerced: Record<string, string | number> = {}
    for (const field of fields) {
      coerced[field.name] =
        field.type === 'numeric' ? coerceNumeric(record[field.name]) : String(record[field.name] ?? '')
    }
    return coerced
  })

  return { records, fields, numericFields, categoricalFields }
}

export const getFieldValues = (data: ParsedData, fieldName: string): (string | number)[] => {
  const field = data.fields.find((f) => f.name === fieldName)
  return field?.values ?? []
}

import { h } from 'plaited/template'
import type { ChartConfig, ParsedData } from './types'
import { getFieldValues } from './data-parser'

const PADDING = { top: 50, right: 30, bottom: 60, left: 70 }

const escapeXml = (str: string): string =>
  str.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;')

const truncateLabel = (label: string, maxLen = 12): string =>
  label.length > maxLen ? `${label.slice(0, maxLen - 1)}…` : label

const renderTitle = (config: ChartConfig) => {
  if (!config.title) return ''
  return h('text', {
    x: String(config.width / 2),
    y: '28',
    'text-anchor': 'middle',
    'font-size': '16',
    'font-weight': 'bold',
    fill: '#1a1a1a',
  }, config.title)
}

const renderBarChart = (data: ParsedData, config: ChartConfig) => {
  const categories = getFieldValues(data, config.categoryField).map(String)
  const values = getFieldValues(data, config.valueField).map(Number)

  const chartW = config.width - PADDING.left - PADDING.right
  const chartH = config.height - PADDING.top - PADDING.bottom
  const maxVal = Math.max(...values, 0) * 1.1 || 1
  const barWidth = Math.max(1, (chartW / categories.length) * 0.7)
  const barGap = (chartW / categories.length) * 0.3

  const bars = categories.map((cat, i) => {
    const barH = (values[i] / maxVal) * chartH
    const x = PADDING.left + i * (barWidth + barGap) + barGap / 2
    const y = PADDING.top + chartH - barH
    const color = config.colors[i % config.colors.length]

    return h('g', {},
      h('rect', {
        x: String(x),
        y: String(y),
        width: String(barWidth),
        height: String(barH),
        fill: color,
        rx: '2',
      }),
      h('text', {
        x: String(x + barWidth / 2),
        y: String(PADDING.top + chartH + 16),
        'text-anchor': 'middle',
        'font-size': '11',
        fill: '#555',
      }, truncateLabel(cat)),
      h('text', {
        x: String(x + barWidth / 2),
        y: String(y - 5),
        'text-anchor': 'middle',
        'font-size': '10',
        fill: '#333',
      }, String(Math.round(values[i] * 100) / 100)),
    )
  })

  const yTicks = 5
  const gridLines = Array.from({ length: yTicks + 1 }, (_, i) => {
    const val = (maxVal / yTicks) * i
    const y = PADDING.top + chartH - (val / maxVal) * chartH
    return h('g', {},
      h('line', {
        x1: String(PADDING.left),
        y1: String(y),
        x2: String(PADDING.left + chartW),
        y2: String(y),
        stroke: '#e0e0e0',
        'stroke-width': '1',
      }),
      h('text', {
        x: String(PADDING.left - 8),
        y: String(y + 4),
        'text-anchor': 'end',
        'font-size': '10',
        fill: '#666',
      }, String(Math.round(val * 10) / 10)),
    )
  })

  return [...gridLines, ...bars]
}

const renderLineChart = (data: ParsedData, config: ChartConfig) => {
  const categories = getFieldValues(data, config.categoryField).map(String)
  const values = getFieldValues(data, config.valueField).map(Number)

  const chartW = config.width - PADDING.left - PADDING.right
  const chartH = config.height - PADDING.top - PADDING.bottom
  const maxVal = Math.max(...values, 0) * 1.1 || 1
  const minVal = Math.min(...values, 0) * 0.9
  const range = maxVal - minVal || 1

  const points = values.map((val, i) => {
    const x = PADDING.left + (i / Math.max(categories.length - 1, 1)) * chartW
    const y = PADDING.top + chartH - ((val - minVal) / range) * chartH
    return { x, y, val }
  })

  const pathD = points.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`).join(' ')

  const yTicks = 5
  const gridLines = Array.from({ length: yTicks + 1 }, (_, i) => {
    const val = minVal + (range / yTicks) * i
    const y = PADDING.top + chartH - ((val - minVal) / range) * chartH
    return h('g', {},
      h('line', {
        x1: String(PADDING.left),
        y1: String(y),
        x2: String(PADDING.left + chartW),
        y2: String(y),
        stroke: '#e0e0e0',
        'stroke-width': '1',
      }),
      h('text', {
        x: String(PADDING.left - 8),
        y: String(y + 4),
        'text-anchor': 'end',
        'font-size': '10',
        fill: '#666',
      }, String(Math.round(val * 10) / 10)),
    )
  })

  const xLabels = categories.map((cat, i) => {
    const x = PADDING.left + (i / Math.max(categories.length - 1, 1)) * chartW
    return h('text', {
      x: String(x),
      y: String(PADDING.top + chartH + 16),
      'text-anchor': 'middle',
      'font-size': '11',
      fill: '#555',
    }, truncateLabel(cat))
  })

  const dots = points.map((p, i) =>
    h('circle', {
      cx: String(p.x),
      cy: String(p.y),
      r: '4',
      fill: config.colors[0],
      stroke: '#fff',
      'stroke-width': '2',
    })
  )

  return [
    ...gridLines,
    h('path', {
      d: pathD,
      fill: 'none',
      stroke: config.colors[0],
      'stroke-width': '2.5',
      'stroke-linejoin': 'round',
    }),
    ...dots,
    ...xLabels,
  ]
}

const renderPieChart = (data: ParsedData, config: ChartConfig) => {
  const categories = getFieldValues(data, config.categoryField).map(String)
  const values = getFieldValues(data, config.valueField).map(Number).map((v) => Math.max(v, 0))

  const total = values.reduce((sum, v) => sum + v, 0) || 1
  const cx = config.width / 2
  const cy = PADDING.top + (config.height - PADDING.top - PADDING.bottom) / 2
  const radius = Math.min(config.width - PADDING.left - PADDING.right, config.height - PADDING.top - PADDING.bottom) / 2.5

  let currentAngle = -Math.PI / 2
  const slices = values.map((val, i) => {
    const sliceAngle = (val / total) * Math.PI * 2
    const startAngle = currentAngle
    const endAngle = currentAngle + sliceAngle
    currentAngle = endAngle

    const x1 = cx + radius * Math.cos(startAngle)
    const y1 = cy + radius * Math.sin(startAngle)
    const x2 = cx + radius * Math.cos(endAngle)
    const y2 = cy + radius * Math.sin(endAngle)
    const largeArc = sliceAngle > Math.PI ? 1 : 0

    const midAngle = startAngle + sliceAngle / 2
    const labelR = radius * 1.2
    const labelX = cx + labelR * Math.cos(midAngle)
    const labelY = cy + labelR * Math.sin(midAngle)

    const pct = Math.round((val / total) * 100)

    const pathD = sliceAngle >= Math.PI * 2 - 0.001
      ? `M ${cx - radius} ${cy} A ${radius} ${radius} 0 1 1 ${cx + radius} ${cy} A ${radius} ${radius} 0 1 1 ${cx - radius} ${cy}`
      : `M ${cx} ${cy} L ${x1} ${y1} A ${radius} ${radius} 0 ${largeArc} 1 ${x2} ${y2} Z`

    return h('g', {},
      h('path', {
        d: pathD,
        fill: config.colors[i % config.colors.length],
        stroke: '#fff',
        'stroke-width': '2',
      }),
      pct >= 3
        ? h('text', {
            x: String(labelX),
            y: String(labelY),
            'text-anchor': 'middle',
            'dominant-baseline': 'middle',
            'font-size': '11',
            fill: '#333',
          }, `${truncateLabel(categories[i], 8)} ${pct}%`)
        : '',
    )
  })

  return slices
}

const renderAxes = (config: ChartConfig) => {
  const chartW = config.width - PADDING.left - PADDING.right
  const chartH = config.height - PADDING.top - PADDING.bottom

  const elements = [
    h('line', {
      x1: String(PADDING.left),
      y1: String(PADDING.top),
      x2: String(PADDING.left),
      y2: String(PADDING.top + chartH),
      stroke: '#999',
      'stroke-width': '1',
    }),
    h('line', {
      x1: String(PADDING.left),
      y1: String(PADDING.top + chartH),
      x2: String(PADDING.left + chartW),
      y2: String(PADDING.top + chartH),
      stroke: '#999',
      'stroke-width': '1',
    }),
  ]

  if (config.xAxisLabel) {
    elements.push(
      h('text', {
        x: String(PADDING.left + chartW / 2),
        y: String(config.height - 8),
        'text-anchor': 'middle',
        'font-size': '12',
        fill: '#333',
      }, config.xAxisLabel)
    )
  }

  if (config.yAxisLabel) {
    elements.push(
      h('text', {
        x: '14',
        y: String(PADDING.top + chartH / 2),
        'text-anchor': 'middle',
        'font-size': '12',
        fill: '#333',
        transform: `rotate(-90, 14, ${PADDING.top + chartH / 2})`,
      }, config.yAxisLabel)
    )
  }

  return elements
}

export const renderChart = (data: ParsedData, config: ChartConfig): string => {
  const chartElements: unknown[] = [
    h('rect', {
      width: String(config.width),
      height: String(config.height),
      fill: '#ffffff',
      rx: '4',
    }),
    renderTitle(config),
  ]

  if (config.type !== 'pie') {
    chartElements.push(...renderAxes(config))
  }

  switch (config.type) {
    case 'bar':
      chartElements.push(...renderBarChart(data, config))
      break
    case 'line':
      chartElements.push(...renderLineChart(data, config))
      break
    case 'pie':
      chartElements.push(...renderPieChart(data, config))
      break
  }

  const svg = h(
    'svg',
    {
      xmlns: 'http://www.w3.org/2000/svg',
      width: String(config.width),
      height: String(config.height),
      viewBox: `0 0 ${config.width} ${config.height}`,
      'font-family': 'system-ui, -apple-system, sans-serif',
    },
    ...chartElements.flat(),
  )

  return String(svg)
}

import { h } from 'plaited/template'

type TokenType = 'key' | 'string' | 'number' | 'boolean' | 'null' | 'bracket' | 'punctuation'

type Token = {
  type: TokenType
  value: string
}

const TOKEN_COLORS: Record<TokenType, string> = {
  key: '#9b2393',
  string: '#0b7261',
  number: '#1750eb',
  boolean: '#ad3da4',
  null: '#ad3da4',
  bracket: '#333',
  punctuation: '#666',
}

const tokenize = (json: string): Token[] => {
  const tokens: Token[] = []
  const regex =
    /("(?:[^"\\]|\\.)*")\s*:|("(?:[^"\\]|\\.)*")|(-?\d+(?:\.\d+)?(?:[eE][+-]?\d+)?)|(\btrue\b|\bfalse\b)|(\bnull\b)|([\[\]{}])|([:,])|(\s+)/g

  let match: RegExpExecArray | null
  let lastIndex = 0

  while ((match = regex.exec(json)) !== null) {
    if (match.index > lastIndex) {
      tokens.push({ type: 'punctuation', value: json.slice(lastIndex, match.index) })
    }
    lastIndex = regex.lastIndex

    if (match[1] !== undefined) {
      tokens.push({ type: 'key', value: match[1] })
      const colonAndSpace = json.slice(match.index + match[1].length, regex.lastIndex)
      if (colonAndSpace) tokens.push({ type: 'punctuation', value: colonAndSpace })
    } else if (match[2] !== undefined) {
      tokens.push({ type: 'string', value: match[2] })
    } else if (match[3] !== undefined) {
      tokens.push({ type: 'number', value: match[3] })
    } else if (match[4] !== undefined) {
      tokens.push({ type: 'boolean', value: match[4] })
    } else if (match[5] !== undefined) {
      tokens.push({ type: 'null', value: match[5] })
    } else if (match[6] !== undefined) {
      tokens.push({ type: 'bracket', value: match[6] })
    } else if (match[7] !== undefined) {
      tokens.push({ type: 'punctuation', value: match[7] })
    } else if (match[8] !== undefined) {
      tokens.push({ type: 'punctuation', value: match[8] })
    }
  }

  if (lastIndex < json.length) {
    tokens.push({ type: 'punctuation', value: json.slice(lastIndex) })
  }

  return tokens
}

export const highlightJson = (json: string) => {
  const tokens = tokenize(json)

  const spans = tokens.map((token) =>
    h('span', { style: `color: ${TOKEN_COLORS[token.type]}` }, token.value)
  )

  return h(
    'div',
    { style: 'position: relative; width: 100%;' },
    h(
      'pre',
      {
        style: [
          'margin: 0',
          'padding: 12px',
          'background: #f8f9fa',
          'border: 1px solid #dee2e6',
          'border-radius: 6px',
          'font-family: "SF Mono", "Fira Code", "Consolas", monospace',
          'font-size: 13px',
          'line-height: 1.5',
          'overflow-x: auto',
          'white-space: pre-wrap',
          'word-wrap: break-word',
        ].join('; '),
      },
      h('code', {}, ...spans),
    ),
  )
}

