export const generateChartPage = (
  jsonInput?: string,
  overrides?: Partial<ChartConfig>,
): string => {
  const jsonData = jsonInput ?? SAMPLE_DATA
  let data: ParsedData | null = null
  let parseError: string | undefined

  try {
    data = parseJsonData(jsonData)
  } catch (e) {
    parseError = e instanceof Error ? e.message : 'Invalid JSON'
  }

  const config: ChartConfig = {
    ...DEFAULT_CONFIG,
    ...overrides,
    categoryField:
      overrides?.categoryField ?? data?.categoricalFields[0] ?? data?.fields[0]?.name ?? '',
    valueField:
      overrides?.valueField ?? data?.numericFields[0] ?? data?.fields[0]?.name ?? '',
  }

  const allFields = data?.fields.map((f) => f.name) ?? []
  const sectionStyle = [
    'background: #fff',
    'border: 1px solid #e5e7eb',
    'border-radius: 8px',
    'padding: 20px',
    'margin-bottom: 16px',
  ].join('; ')

  const page = h('div', {
    style: 'max-width: 960px; margin: 0 auto; padding: 24px; font-family: system-ui, -apple-system, sans-serif; background: #f3f4f6; min-height: 100vh;',
  },
    h('h1', {
      style: 'font-size: 24px; font-weight: 700; color: #1a1a1a; margin: 0 0 20px 0;',
    }, 'Chart Generator'),

    h('div', { style: sectionStyle },
      renderEditorForm(jsonData, parseError),
    ),

    data
      ? h(Fragment, {},
          h('div', { style: sectionStyle },
            h('div', { style: 'display: flex; justify-content: space-between; align-items: center; margin-bottom: 16px; flex-wrap: wrap; gap: 12px;' },
              renderChartTypeSelector(config.type),
              h('div', { style: 'display: flex; gap: 12px; flex-wrap: wrap;' },
                renderFieldSelector('Category / X Field', 'categoryField', allFields, config.categoryField),
                renderFieldSelector('Value / Y Field', 'valueField', allFields, config.valueField),
              ),
            ),
            renderCustomizationPanel(config),
          ),

          h('div', { style: `${sectionStyle} text-align: center;`, 'p-target': 'chartOutput' },
            h('div', {
              style: 'display: inline-block; border: 1px solid #e5e7eb; border-radius: 4px; overflow: hidden;',
            }, renderChart(data, config)),
          ),

          h('div', { style: 'display: flex; justify-content: flex-end; gap: 12px; margin-top: 4px;' },
            renderDownloadButton(),
          ),
        )
      : '',
  )

  return String(page)
}

export const handleGenerateChart = async (request: {
  jsonData: string
  type?: ChartType
  categoryField?: string
  valueField?: string
  title?: string
  xAxisLabel?: string
  yAxisLabel?: string
  colors?: string[]
}): Promise<{ html: string; svg: string }> => {
  const data = parseJsonData(request.jsonData)

  const config: ChartConfig = {
    ...DEFAULT_CONFIG,
    type: request.type ?? 'bar',
    title: request.title ?? '',
    xAxisLabel: request.xAxisLabel ?? '',
    yAxisLabel: request.yAxisLabel ?? '',
    colors: request.colors ?? DEFAULT_COLORS,
    categoryField: request.categoryField ?? data.categoricalFields[0] ?? data.fields[0].name,
    valueField: request.valueField ?? data.numericFields[0] ?? data.fields[0].name,
  }

  const svg = renderChart(data, config)
  const html = generateChartPage(request.jsonData, config)

  return { html, svg }
}

export const downloadSvg = (svg: string, filename = 'chart.svg'): string => {
  const blob = `data:image/svg+xml;charset=utf-8,${encodeURIComponent(svg)}`
  return h('a', {
    href: blob,
    download: filename,
    style: 'display: none;',
  }, '').toString()
}

export const saveSvgToFile = async (svg: string, path: string): Promise<void> => {
  await Bun.write(path, svg)
}

