import type { DataRecord, FieldInfo, FieldType, AnalyzedData } from './types'

const detectFieldType = (values: (string | number)[]): FieldType => {
  const allNumeric = values.every((v) => {
    if (typeof v === 'number') return true
    const parsed = Number(v)
    return !Number.isNaN(parsed) && v.toString().trim() !== ''
  })
  return allNumeric ? 'numeric' : 'categorical'
}

const coerceNumeric = (values: (string | number)[]): number[] =>
  values.map((v) => (typeof v === 'number' ? v : Number(v)))

export const analyzeData = (records: DataRecord[]): AnalyzedData => {
  if (records.length === 0) {
    return { fields: [], records: [], numericFields: [], categoricalFields: [] }
  }

  const fieldNames = Object.keys(records[0])
  const fields: FieldInfo[] = fieldNames.map((name) => {
    const rawValues = records.map((r) => r[name])
    const type = detectFieldType(rawValues)
    const values = type === 'numeric' ? coerceNumeric(rawValues) : rawValues
    return { name, type, values }
  })

  const numericFields = fields.filter((f) => f.type === 'numeric').map((f) => f.name)
  const categoricalFields = fields.filter((f) => f.type === 'categorical').map((f) => f.name)

  return { fields, records, numericFields, categoricalFields }
}

export const parseJsonInput = (input: string): DataRecord[] => {
  const parsed = JSON.parse(input)
  if (!Array.isArray(parsed)) {
    throw new Error('Input must be a JSON array')
  }
  if (parsed.length === 0) {
    throw new Error('Array must contain at least one object')
  }
  if (typeof parsed[0] !== 'object' || parsed[0] === null) {
    throw new Error('Array items must be objects')
  }
  return parsed as DataRecord[]
}

import type { ColorPalette } from './types'

const palettes: Record<ColorPalette, string[]> = {
  default: ['#4e79a7', '#f28e2b', '#e15759', '#76b7b2', '#59a14f', '#edc948', '#b07aa1', '#ff9da7', '#9c755f', '#bab0ac'],
  warm: ['#e6550d', '#fd8d3c', '#fdae6b', '#fdd0a2', '#d62728', '#ff7f0e', '#ff9896', '#ffbb78', '#c49c94', '#f7b6d2'],
  cool: ['#1f77b4', '#aec7e8', '#2ca02c', '#98df8a', '#17becf', '#9edae5', '#5254a3', '#6b6ecf', '#9c9ede', '#637939'],
  monochrome: ['#252525', '#525252', '#737373', '#969696', '#bdbdbd', '#d9d9d9', '#404040', '#636363', '#8c8c8c', '#a8a8a8'],
}

export const getColors = (palette: ColorPalette, count: number): string[] => {
  const colors = palettes[palette]
  return Array.from({ length: count }, (_, i) => colors[i % colors.length])
}

import { h } from 'plaited'
import type { ChartConfig, ChartDimensions, AnalyzedData, FieldInfo } from './types'
import { getColors } from './colors'

const DIMS: ChartDimensions = {
  width: 800,
  height: 500,
  padding: { top: 60, right: 40, bottom: 80, left: 70 },
  plotWidth: 690,
  plotHeight: 360,
  plotX: 70,
  plotY: 60,
}

const getField = (data: AnalyzedData, name: string): FieldInfo | undefined =>
  data.fields.find((f) => f.name === name)

const niceMax = (max: number): number => {
  if (max <= 0) return 10
  const magnitude = Math.pow(10, Math.floor(Math.log10(max)))
  const normalized = max / magnitude
  if (normalized <= 1) return magnitude
  if (normalized <= 2) return 2 * magnitude
  if (normalized <= 5) return 5 * magnitude
  return 10 * magnitude
}

const generateYTicks = (maxVal: number, count = 5): number[] => {
  const ceiling = niceMax(maxVal)
  const step = ceiling / count
  return Array.from({ length: count + 1 }, (_, i) => Math.round(i * step * 100) / 100)
}

const svgWrapper = (config: ChartConfig, children: string): string => {
  const titleEl = config.title
    ? h('text', {
        x: String(DIMS.width / 2),
        y: '30',
        'text-anchor': 'middle',
        'font-size': '18',
        'font-weight': 'bold',
        fill: '#333',
      }, config.title)
    : ''

  const xLabelEl = config.xLabel
    ? h('text', {
        x: String(DIMS.plotX + DIMS.plotWidth / 2),
        y: String(DIMS.height - 10),
        'text-anchor': 'middle',
        'font-size': '14',
        fill: '#555',
      }, config.xLabel)
    : ''

  const yLabelEl = config.yLabel
    ? h('text', {
        x: '15',
        y: String(DIMS.plotY + DIMS.plotHeight / 2),
        'text-anchor': 'middle',
        'font-size': '14',
        fill: '#555',
        transform: `rotate(-90, 15, ${DIMS.plotY + DIMS.plotHeight / 2})`,
      }, config.yLabel)
    : ''

  return h('svg', {
    xmlns: 'http://www.w3.org/2000/svg',
    viewBox: `0 0 ${DIMS.width} ${DIMS.height}`,
    width: String(DIMS.width),
    height: String(DIMS.height),
    style: 'background: #fff; font-family: system-ui, -apple-system, sans-serif;',
  }, titleEl + xLabelEl + yLabelEl + children)
}

const renderAxes = (xLabels: string[], yMax: number, config: ChartConfig): string => {
  const ticks = generateYTicks(yMax)
  const ceiling = ticks[ticks.length - 1]

  const gridLines = ticks.map((tick) => {
    const y = DIMS.plotY + DIMS.plotHeight - (tick / ceiling) * DIMS.plotHeight
    return h('g', {},
      h('line', {
        x1: String(DIMS.plotX),
        y1: String(y),
        x2: String(DIMS.plotX + DIMS.plotWidth),
        y2: String(y),
        stroke: '#e0e0e0',
        'stroke-dasharray': '4,4',
      }) +
      h('text', {
        x: String(DIMS.plotX - 10),
        y: String(y + 4),
        'text-anchor': 'end',
        'font-size': '12',
        fill: '#666',
      }, String(tick))
    )
  }).join('')

  const xAxisLabels = xLabels.map((label, i) => {
    const x = DIMS.plotX + (i + 0.5) * (DIMS.plotWidth / xLabels.length)
    const displayLabel = label.length > 12 ? label.slice(0, 11) + '…' : label
    return h('text', {
      x: String(x),
      y: String(DIMS.plotY + DIMS.plotHeight + 20),
      'text-anchor': 'middle',
      'font-size': '11',
      fill: '#666',
      transform: xLabels.length > 8 ? `rotate(-45, ${x}, ${DIMS.plotY + DIMS.plotHeight + 20})` : undefined,
    }, displayLabel)
  }).join('')

  const baseLine = h('line', {
    x1: String(DIMS.plotX),
    y1: String(DIMS.plotY + DIMS.plotHeight),
    x2: String(DIMS.plotX + DIMS.plotWidth),
    y2: String(DIMS.plotY + DIMS.plotHeight),
    stroke: '#999',
    'stroke-width': '1',
  })

  const yAxis = h('line', {
    x1: String(DIMS.plotX),
    y1: String(DIMS.plotY),
    x2: String(DIMS.plotX),
    y2: String(DIMS.plotY + DIMS.plotHeight),
    stroke: '#999',
    'stroke-width': '1',
  })

  return gridLines + baseLine + yAxis + xAxisLabels
}

export const renderBarChart = (data: AnalyzedData, config: ChartConfig): string => {
  const xField = getField(data, config.xField)
  const yField = getField(data, config.yField)
  if (!xField || !yField) return svgWrapper(config, h('text', { x: '400', y: '250', 'text-anchor': 'middle', fill: '#999' }, 'Select fields to display'))

  const labels = xField.values.map(String)
  const values = yField.values.map(Number)
  const maxVal = Math.max(...values)
  const ceiling = generateYTicks(maxVal).pop() ?? maxVal

  const colors = getColors(config.palette, labels.length)
  const barWidth = (DIMS.plotWidth / labels.length) * 0.7
  const barGap = (DIMS.plotWidth / labels.length) * 0.15

  const bars = values.map((val, i) => {
    const barHeight = (val / ceiling) * DIMS.plotHeight
    const x = DIMS.plotX + i * (DIMS.plotWidth / labels.length) + barGap
    const y = DIMS.plotY + DIMS.plotHeight - barHeight

    return h('g', {},
      h('rect', {
        x: String(x),
        y: String(y),
        width: String(barWidth),
        height: String(barHeight),
        fill: colors[i],
        rx: '3',
        ry: '3',
      }) +
      h('text', {
        x: String(x + barWidth / 2),
        y: String(y - 6),
        'text-anchor': 'middle',
        'font-size': '11',
        fill: '#444',
      }, String(val))
    )
  }).join('')

  const axes = renderAxes(labels, maxVal, config)
  return svgWrapper(config, axes + bars)
}

export const renderLineChart = (data: AnalyzedData, config: ChartConfig): string => {
  const xField = getField(data, config.xField)
  const yField = getField(data, config.yField)
  if (!xField || !yField) return svgWrapper(config, h('text', { x: '400', y: '250', 'text-anchor': 'middle', fill: '#999' }, 'Select fields to display'))

  const labels = xField.values.map(String)
  const values = yField.values.map(Number)
  const maxVal = Math.max(...values)
  const ceiling = generateYTicks(maxVal).pop() ?? maxVal

  const color = getColors(config.palette, 1)[0]

  const points = values.map((val, i) => {
    const x = DIMS.plotX + (i + 0.5) * (DIMS.plotWidth / labels.length)
    const y = DIMS.plotY + DIMS.plotHeight - (val / ceiling) * DIMS.plotHeight
    return { x, y, val }
  })

  const pathD = points.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`).join(' ')

  const areaD = pathD +
    ` L ${points[points.length - 1].x} ${DIMS.plotY + DIMS.plotHeight}` +
    ` L ${points[0].x} ${DIMS.plotY + DIMS.plotHeight} Z`

  const area = h('path', {
    d: areaD,
    fill: color,
    opacity: '0.1',
  })

  const line = h('path', {
    d: pathD,
    fill: 'none',
    stroke: color,
    'stroke-width': '2.5',
    'stroke-linejoin': 'round',
  })

  const dots = points.map((p) =>
    h('g', {},
      h('circle', {
        cx: String(p.x),
        cy: String(p.y),
        r: '5',
        fill: '#fff',
        stroke: color,
        'stroke-width': '2.5',
      }) +
      h('text', {
        x: String(p.x),
        y: String(p.y - 12),
        'text-anchor': 'middle',
        'font-size': '11',
        fill: '#444',
      }, String(p.val))
    )
  ).join('')

  const axes = renderAxes(labels, maxVal, config)
  return svgWrapper(config, axes + area + line + dots)
}

export const renderPieChart = (data: AnalyzedData, config: ChartConfig): string => {
  const labelField = getField(data, config.xField)
  const valueField = getField(data, config.yField)
  if (!labelField || !valueField) return svgWrapper(config, h('text', { x: '400', y: '250', 'text-anchor': 'middle', fill: '#999' }, 'Select fields to display'))

  const labels = labelField.values.map(String)
  const values = valueField.values.map(Number)
  const total = values.reduce((sum, v) => sum + v, 0)
  if (total === 0) return svgWrapper(config, h('text', { x: '400', y: '250', 'text-anchor': 'middle', fill: '#999' }, 'All values are zero'))

  const colors = getColors(config.palette, labels.length)
  const cx = 350
  const cy = 260
  const radius = 160

  let currentAngle = -Math.PI / 2
  const slices = values.map((val, i) => {
    const sliceAngle = (val / total) * 2 * Math.PI
    const startAngle = currentAngle
    const endAngle = currentAngle + sliceAngle
    currentAngle = endAngle

    const x1 = cx + radius * Math.cos(startAngle)
    const y1 = cy + radius * Math.sin(startAngle)
    const x2 = cx + radius * Math.cos(endAngle)
    const y2 = cy + radius * Math.sin(endAngle)
    const largeArc = sliceAngle > Math.PI ? 1 : 0

    const midAngle = startAngle + sliceAngle / 2
    const labelRadius = radius * 0.65
    const lx = cx + labelRadius * Math.cos(midAngle)
    const ly = cy + labelRadius * Math.sin(midAngle)

    const pct = ((val / total) * 100).toFixed(1)

    const pathData = sliceAngle >= 2 * Math.PI - 0.001
      ? `M ${cx - radius} ${cy} A ${radius} ${radius} 0 1 1 ${cx + radius} ${cy} A ${radius} ${radius} 0 1 1 ${cx - radius} ${cy}`
      : `M ${cx} ${cy} L ${x1} ${y1} A ${radius} ${radius} 0 ${largeArc} 1 ${x2} ${y2} Z`

    return h('g', {},
      h('path', {
        d: pathData,
        fill: colors[i],
        stroke: '#fff',
        'stroke-width': '2',
      }) +
      (sliceAngle > 0.2
        ? h('text', {
            x: String(lx),
            y: String(ly),
            'text-anchor': 'middle',
            'font-size': '12',
            'font-weight': 'bold',
            fill: '#fff',
          }, `${pct}%`)
        : '')
    )
  }).join('')

  const legendX = 580
  const legend = labels.map((label, i) => {
    const ly = DIMS.plotY + 20 + i * 24
    const displayLabel = label.length > 18 ? label.slice(0, 17) + '…' : label
    return h('g', {},
      h('rect', {
        x: String(legendX),
        y: String(ly - 10),
        width: '14',
        height: '14',
        fill: colors[i],
        rx: '2',
      }) +
      h('text', {
        x: String(legendX + 20),
        y: String(ly + 2),
        'font-size': '12',
        fill: '#555',
      }, `${displayLabel} (${values[i]})`)
    )
  }).join('')

  return svgWrapper(config, slices + legend)
}

export const renderChart = (data: AnalyzedData, config: ChartConfig): string => {
  switch (config.chartType) {
    case 'bar': return renderBarChart(data, config)
    case 'line': return renderLineChart(data, config)
    case 'pie': return renderPieChart(data, config)
  }
}

import { analyzeData, parseJsonInput } from './analyze'
import { renderChart } from './chart'
import { renderForm, getSampleData } from './ui'
import type { ChartConfig, ChartType, ColorPalette, AnalyzedData } from './types'

const DATA_PATH = './data/charts.json'

type AppState = {
  jsonInput: string
  data: AnalyzedData | null
  config: ChartConfig
  chartSvg: string
  error: string | null
}

const defaultConfig: ChartConfig = {
  chartType: 'bar',
  title: '',
  xLabel: '',
  yLabel: '',
  xField: '',
  yField: '',
  palette: 'default',
}

const createState = (): AppState => ({
  jsonInput: getSampleData(),
  data: null,
  config: { ...defaultConfig },
  chartSvg: '',
  error: null,
})

const autoSelectFields = (data: AnalyzedData, config: ChartConfig): ChartConfig => {
  const xField = config.xField && data.fields.some((f) => f.name === config.xField)
    ? config.xField
    : data.categoricalFields[0] ?? data.numericFields[0] ?? data.fields[0]?.name ?? ''

  const yField = config.yField && data.fields.some((f) => f.name === config.yField)
    ? config.yField
    : data.numericFields.find((f) => f !== xField) ?? data.numericFields[0] ?? ''

  return { ...config, xField, yField }
}

const generateChartFromState = (state: AppState): AppState => {
  try {
    const records = parseJsonInput(state.jsonInput)
    const data = analyzeData(records)
    const config = autoSelectFields(data, state.config)
    const chartSvg = renderChart(data, config)
    return { ...state, data, config, chartSvg, error: null }
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Invalid JSON input'
    return { ...state, error: message, chartSvg: '' }
  }
}

const saveState = async (state: AppState): Promise<void> => {
  const payload = {
    lastInput: state.jsonInput,
    lastConfig: state.config,
    savedAt: new Date().toISOString(),
  }
  await Bun.write(DATA_PATH, JSON.stringify(payload, null, 2))
}

const loadState = async (): Promise<Partial<AppState>> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return {}
  try {
    const payload = await file.json()
    return {
      jsonInput: payload.lastInput ?? getSampleData(),
      config: { ...defaultConfig, ...payload.lastConfig },
    }
  } catch {
    return {}
  }
}

const handleRequest = async (state: AppState, req: Request): Promise<{ state: AppState; response: Response }> => {
  const url = new URL(req.url)

  if (url.pathname === '/api/generate' && req.method === 'POST') {
    const body = await req.json() as { json?: string; config?: Partial<ChartConfig> }
    if (body.json) state.jsonInput = body.json
    if (body.config) state.config = { ...state.config, ...body.config }
    state = generateChartFromState(state)
    await saveState(state)
    return {
      state,
      response: Response.json({
        svg: state.chartSvg,
        error: state.error,
        fields: state.data?.fields.map((f) => ({ name: f.name, type: f.type })) ?? [],
        config: state.config,
      }),
    }
  }

  if (url.pathname === '/api/download' && req.method === 'GET') {
    if (!state.chartSvg) {
      return { state, response: new Response('No chart generated', { status: 400 }) }
    }
    const filename = `chart-${state.config.chartType}-${Date.now()}.svg`
    return {
      state,
      response: new Response(state.chartSvg, {
        headers: {
          'Content-Type': 'image/svg+xml',
          'Content-Disposition': `attachment; filename="${filename}"`,
        },
      }),
    }
  }

  if (url.pathname === '/api/sample' && req.method === 'GET') {
    return {
      state,
      response: Response.json({ json: getSampleData() }),
    }
  }

  // Serve main page
  state = generateChartFromState(state)
  const html = renderPage(state)
  return { state, response: new Response(html, { headers: { 'Content-Type': 'text/html' } }) }
}

const renderPage = (state: AppState): string => {
  const body = renderForm(state.data, state.config, state.chartSvg, state.error, state.jsonInput)
  return `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Chart Generator</title>
<style>
  *, *::before, *::after { box-sizing: border-box; }
  body { margin: 0; }
  textarea:focus, select:focus, input:focus, button:focus {
    outline: 2px solid #4e79a7;
    outline-offset: 1px;
  }
  button:hover { opacity: 0.9; }
  @media (max-width: 900px) {
    .layout { grid-template-columns: 1fr !important; }
  }
</style>
</head>
<body>${body}
<script>
const state = {
  json: document.querySelector('[p-target="jsonEditor"]')?.value ?? '',
  config: ${JSON.stringify(state.config)},
}

const debounce = (fn, ms) => {
  let timer
  return (...args) => { clearTimeout(timer); timer = setTimeout(() => fn(...args), ms) }
}

const generate = async () => {
  const res = await fetch('/api/generate', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ json: state.json, config: state.config }),
  })
  const data = await res.json()
  const output = document.querySelector('[p-target="chartOutput"]')
  if (output) output.innerHTML = data.svg || ''
  if (data.error) {
    console.error(data.error)
  }
  if (data.config) {
    state.config = data.config
  }
}

document.addEventListener('input', (e) => {
  const el = e.target
  if (el.matches('[p-target="jsonEditor"]')) {
    state.json = el.value
    highlightJson(el)
  }
  if (el.name === 'title') state.config.title = el.value
  if (el.name === 'xLabel') state.config.xLabel = el.value
  if (el.name === 'yLabel') state.config.yLabel = el.value
})

document.addEventListener('change', (e) => {
  const el = e.target
  if (el.name === 'xField') { state.config.xField = el.value; generate() }
  if (el.name === 'yField') { state.config.yField = el.value; generate() }
  if (el.name === 'palette') { state.config.palette = el.value; generate() }
})

document.addEventListener('click', (e) => {
  const el = e.target
  if (el.matches('[p-trigger*="generateChart"]')) {
    generate()
  }
  if (el.matches('[p-trigger*="loadSample"]')) {
    fetch('/api/sample').then(r => r.json()).then(d => {
      const editor = document.querySelector('[p-target="jsonEditor"]')
      if (editor) { editor.value = d.json; state.json = d.json }
      generate()
    })
  }
  if (el.matches('[p-trigger*="setChartType"]')) {
    const type = el.dataset.type
    if (type) {
      state.config.chartType = type
      document.querySelectorAll('[p-trigger*="setChartType"]').forEach(btn => {
        btn.style.background = btn.dataset.type === type ? '#4e79a7' : '#fff'
        btn.style.color = btn.dataset.type === type ? '#fff' : '#555'
        btn.style.borderColor = btn.dataset.type === type ? '#4e79a7' : '#ddd'
      })
      generate()
    }
  }
  if (el.matches('[p-trigger*="downloadSvg"]')) {
    window.open('/api/download', '_blank')
  }
})

const debouncedGenerate = debounce(generate, 400)
document.addEventListener('input', (e) => {
  if (e.target.name === 'title' || e.target.name === 'xLabel' || e.target.name === 'yLabel') {
    debouncedGenerate()
  }
})

// Syntax highlighting via overlay
const setupHighlighting = () => {
  const editor = document.querySelector('[p-target="jsonEditor"]')
  if (!editor) return

  const wrapper = document.createElement('div')
  wrapper.style.cssText = 'position:relative;'
  editor.parentNode.insertBefore(wrapper, editor)
  wrapper.appendChild(editor)

  const highlight = document.createElement('div')
  highlight.style.cssText = \`
    position:absolute;top:0;left:0;right:0;bottom:0;
    padding:14px;font-family:ui-monospace,SFMono-Regular,Menlo,monospace;
    font-size:13px;line-height:1.5;pointer-events:none;
    white-space:pre;overflow:auto;border:1px solid transparent;
    border-radius:8px;tab-size:2;
  \`
  highlight.setAttribute('aria-hidden', 'true')
  wrapper.appendChild(highlight)

  const colorize = (text) => {
    return text
      .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
      .replace(/("(?:[^"\\\\]|\\\\.)*")\s*:/g, '<span style="color:#0550ae">$1</span>:')
      .replace(/:\s*("(?:[^"\\\\]|\\\\.)*")/g, ': <span style="color:#0a3069">$1</span>')
      .replace(/:\s*(-?\\d+\\.?\\d*)/g, ': <span style="color:#0550ae;font-weight:600">$1</span>')
      .replace(/\\b(true|false|null)\\b/g, '<span style="color:#cf222e">$1</span>')
  }

  editor.style.color = 'transparent'
  editor.style.caretColor = '#333'
  editor.style.position = 'relative'
  editor.style.zIndex = '1'
  editor.style.background = 'transparent'

  const sync = () => {
    highlight.innerHTML = colorize(editor.value)
    highlight.scrollTop = editor.scrollTop
    highlight.scrollLeft = editor.scrollLeft
  }

  editor.addEventListener('input', sync)
  editor.addEventListener('scroll', () => {
    highlight.scrollTop = editor.scrollTop
    highlight.scrollLeft = editor.scrollLeft
  })
  sync()
}

setupHighlighting()

// Tab key support in editor
document.querySelector('[p-target="jsonEditor"]')?.addEventListener('keydown', (e) => {
  if (e.key === 'Tab') {
    e.preventDefault()
    const start = e.target.selectionStart
    const end = e.target.selectionEnd
    e.target.value = e.target.value.substring(0, start) + '  ' + e.target.value.substring(end)
    e.target.selectionStart = e.target.selectionEnd = start + 2
    e.target.dispatchEvent(new Event('input'))
  }
})
</script>
</body>
</html>`
}

const serve = async () => {
  const saved = await loadState()
  let state: AppState = {
    ...createState(),
    ...saved,
  }

  Bun.serve({
    port: 3000,
    fetch: async (req) => {
      const result = await handleRequest(state, req)
      state = result.state
      return result.response
    },
  })

  console.log('Chart Generator running at http://localhost:3000')
}

