import type { DataRow, FieldInfo, FieldType, ParsedData } from './types'

const isNumeric = (value: unknown): boolean => {
  if (typeof value === 'number') return true
  if (typeof value === 'string') {
    const trimmed = value.trim()
    return trimmed !== '' && !isNaN(Number(trimmed))
  }
  return false
}

const detectFieldType = (rows: DataRow[], fieldName: string): FieldType => {
  const values = rows.map((row) => row[fieldName]).filter((v) => v !== undefined && v !== null && v !== '')
  if (values.length === 0) return 'categorical'
  const numericCount = values.filter(isNumeric).length
  return numericCount / values.length >= 0.8 ? 'numeric' : 'categorical'
}

export const analyzeFields = (rows: DataRow[]): FieldInfo[] => {
  if (rows.length === 0) return []
  const fieldNames = Object.keys(rows[0])
  return fieldNames.map((name) => ({
    name,
    type: detectFieldType(rows, name),
  }))
}

export const parseData = (rows: DataRow[]): ParsedData => ({
  rows,
  fields: analyzeFields(rows),
})

export const getNumericFields = (fields: FieldInfo[]): string[] =>
  fields.filter((f) => f.type === 'numeric').map((f) => f.name)

export const getCategoricalFields = (fields: FieldInfo[]): string[] =>
  fields.filter((f) => f.type === 'categorical').map((f) => f.name)

export const coerceNumeric = (value: unknown): number => {
  if (typeof value === 'number') return value
  if (typeof value === 'string') return parseFloat(value) || 0
  return 0
}

import { h } from '@plaited/template'
import type { ChartConfig, ChartMargins, DataRow } from './types'
import { coerceNumeric } from './field-detector'
import { getColor, getPalette } from './colors'

const DEFAULT_WIDTH = 640
const DEFAULT_HEIGHT = 400

const defaultMargins: ChartMargins = {
  top: 50,
  right: 30,
  bottom: 70,
  left: 70,
}

const pieMargins: ChartMargins = {
  top: 50,
  right: 200,
  bottom: 30,
  left: 30,
}

const computeNiceTicks = (min: number, max: number, targetCount = 5): number[] => {
  if (min === max) return [min]
  const range = max - min
  const roughStep = range / targetCount
  const magnitude = Math.pow(10, Math.floor(Math.log10(roughStep)))
  const residual = roughStep / magnitude
  const niceStep =
    residual <= 1.5 ? magnitude
    : residual <= 3 ? 2 * magnitude
    : residual <= 7 ? 5 * magnitude
    : 10 * magnitude

  const tickMin = Math.floor(min / niceStep) * niceStep
  const ticks: number[] = []
  for (let t = tickMin; t <= max + niceStep * 0.01; t += niceStep) {
    ticks.push(Math.round(t * 1e10) / 1e10)
  }
  return ticks
}

const formatTick = (value: number): string => {
  if (Math.abs(value) >= 1e6) return `${(value / 1e6).toFixed(1)}M`
  if (Math.abs(value) >= 1e3) return `${(value / 1e3).toFixed(1)}K`
  return Number.isInteger(value) ? String(value) : value.toFixed(1)
}

const renderTitle = (title: string | undefined, width: number) => {
  if (!title) return null
  return h('text', {
    x: String(width / 2),
    y: '28',
    'text-anchor': 'middle',
    style: { fontSize: '16px', fontWeight: '600', fontFamily: 'system-ui, sans-serif', fill: '#1a1a1a' },
  }, title)
}

const renderXLabel = (label: string | undefined, width: number, height: number) => {
  if (!label) return null
  return h('text', {
    x: String(width / 2),
    y: String(height - 10),
    'text-anchor': 'middle',
    style: { fontSize: '12px', fontFamily: 'system-ui, sans-serif', fill: '#555' },
  }, label)
}

const renderYLabel = (label: string | undefined, height: number, margins: ChartMargins) => {
  if (!label) return null
  return h('text', {
    x: '0',
    y: '0',
    'text-anchor': 'middle',
    transform: `translate(16, ${(height - margins.top - margins.bottom) / 2 + margins.top}) rotate(-90)`,
    style: { fontSize: '12px', fontFamily: 'system-ui, sans-serif', fill: '#555' },
  }, label)
}

export const renderBarChart = (data: DataRow[], config: ChartConfig) => {
  const width = config.width ?? DEFAULT_WIDTH
  const height = config.height ?? DEFAULT_HEIGHT
  const margins = defaultMargins
  const colors = config.colors ?? getPalette()

  const chartW = width - margins.left - margins.right
  const chartH = height - margins.top - margins.bottom

  const categories = data.map((row) => String(row[config.categoryField] ?? ''))
  const valueFields = config.valueFields
  const groupCount = valueFields.length

  const allValues = data.flatMap((row) =>
    valueFields.map((f) => coerceNumeric(row[f]))
  )
  const dataMax = Math.max(...allValues, 0)
  const dataMin = Math.min(0, ...allValues)
  const ticks = computeNiceTicks(dataMin, dataMax)
  const yMin = ticks[0]
  const yMax = ticks[ticks.length - 1]
  const yRange = yMax - yMin || 1

  const bandWidth = chartW / categories.length
  const barPadding = 0.2
  const groupWidth = bandWidth * (1 - barPadding)
  const barWidth = groupWidth / groupCount
  const offsetStart = bandWidth * (barPadding / 2)

  const scaleY = (v: number) => margins.top + chartH - ((v - yMin) / yRange) * chartH
  const zeroY = scaleY(0)

  const gridLines = ticks.map((t) =>
    h('line', {
      x1: String(margins.left),
      y1: String(scaleY(t)),
      x2: String(width - margins.right),
      y2: String(scaleY(t)),
      stroke: '#e0e0e0',
      'stroke-width': '1',
    })
  )

  const yTickLabels = ticks.map((t) =>
    h('text', {
      x: String(margins.left - 8),
      y: String(scaleY(t) + 4),
      'text-anchor': 'end',
      style: { fontSize: '11px', fontFamily: 'system-ui, sans-serif', fill: '#666' },
    }, formatTick(t))
  )

  const bars = data.flatMap((row, i) =>
    valueFields.map((field, j) => {
      const val = coerceNumeric(row[field])
      const x = margins.left + i * bandWidth + offsetStart + j * barWidth
      const barTop = val >= 0 ? scaleY(val) : zeroY
      const barH = Math.abs(scaleY(val) - zeroY)
      return h('rect', {
        x: String(x),
        y: String(barTop),
        width: String(Math.max(barWidth - 2, 1)),
        height: String(Math.max(barH, 1)),
        fill: getColor(colors, j),
        rx: '2',
      })
    })
  )

  const xLabels = categories.map((cat, i) =>
    h('text', {
      x: String(margins.left + i * bandWidth + bandWidth / 2),
      y: String(height - margins.bottom + 18),
      'text-anchor': 'middle',
      style: { fontSize: '11px', fontFamily: 'system-ui, sans-serif', fill: '#666' },
    }, cat.length > 12 ? cat.slice(0, 11) + '\u2026' : cat)
  )

  const legend = groupCount > 1
    ? valueFields.map((field, j) =>
        h('g', { transform: `translate(${margins.left + j * 120}, ${height - 12})` },
          h('rect', { x: '0', y: '-8', width: '12', height: '12', fill: getColor(colors, j), rx: '2' }),
          h('text', {
            x: '16', y: '2',
            style: { fontSize: '11px', fontFamily: 'system-ui, sans-serif', fill: '#555' },
          }, field)
        )
      )
    : []

  return h('svg', {
    xmlns: 'http://www.w3.org/2000/svg',
    width: String(width),
    height: String(height),
    viewBox: `0 0 ${width} ${height}`,
    style: { backgroundColor: '#ffffff', borderRadius: '8px' },
  },
    renderTitle(config.title, width),
    ...gridLines,
    h('line', {
      x1: String(margins.left), y1: String(margins.top),
      x2: String(margins.left), y2: String(height - margins.bottom),
      stroke: '#ccc', 'stroke-width': '1',
    }),
    h('line', {
      x1: String(margins.left), y1: String(zeroY),
      x2: String(width - margins.right), y2: String(zeroY),
      stroke: '#ccc', 'stroke-width': '1',
    }),
    ...yTickLabels,
    ...bars,
    ...xLabels,
    ...legend,
    renderYLabel(config.yLabel, height, margins),
    renderXLabel(config.xLabel, width, height),
  )
}

export const renderLineChart = (data: DataRow[], config: ChartConfig) => {
  const width = config.width ?? DEFAULT_WIDTH
  const height = config.height ?? DEFAULT_HEIGHT
  const margins = defaultMargins
  const colors = config.colors ?? getPalette()

  const chartW = width - margins.left - margins.right
  const chartH = height - margins.top - margins.bottom

  const categories = data.map((row) => String(row[config.categoryField] ?? ''))
  const valueFields = config.valueFields

  const allValues = data.flatMap((row) =>
    valueFields.map((f) => coerceNumeric(row[f]))
  )
  const dataMax = Math.max(...allValues)
  const dataMin = Math.min(...allValues)
  const ticks = computeNiceTicks(dataMin, dataMax)
  const yMin = ticks[0]
  const yMax = ticks[ticks.length - 1]
  const yRange = yMax - yMin || 1

  const stepX = categories.length > 1 ? chartW / (categories.length - 1) : chartW / 2
  const scaleY = (v: number) => margins.top + chartH - ((v - yMin) / yRange) * chartH
  const scaleX = (i: number) =>
    categories.length > 1
      ? margins.left + i * stepX
      : margins.left + chartW / 2

  const gridLines = ticks.map((t) =>
    h('line', {
      x1: String(margins.left),
      y1: String(scaleY(t)),
      x2: String(width - margins.right),
      y2: String(scaleY(t)),
      stroke: '#e0e0e0',
      'stroke-width': '1',
    })
  )

  const yTickLabels = ticks.map((t) =>
    h('text', {
      x: String(margins.left - 8),
      y: String(scaleY(t) + 4),
      'text-anchor': 'end',
      style: { fontSize: '11px', fontFamily: 'system-ui, sans-serif', fill: '#666' },
    }, formatTick(t))
  )

  const lines = valueFields.map((field, j) => {
    const points = data.map((row, i) => `${scaleX(i)},${scaleY(coerceNumeric(row[field]))}`)
    return h('polyline', {
      points: points.join(' '),
      fill: 'none',
      stroke: getColor(colors, j),
      'stroke-width': '2.5',
      'stroke-linejoin': 'round',
      'stroke-linecap': 'round',
    })
  })

  const dots = valueFields.flatMap((field, j) =>
    data.map((row, i) =>
      h('circle', {
        cx: String(scaleX(i)),
        cy: String(scaleY(coerceNumeric(row[field]))),
        r: '4',
        fill: getColor(colors, j),
        stroke: '#fff',
        'stroke-width': '1.5',
      })
    )
  )

  const xLabels = categories.map((cat, i) =>
    h('text', {
      x: String(scaleX(i)),
      y: String(height - margins.bottom + 18),
      'text-anchor': 'middle',
      style: { fontSize: '11px', fontFamily: 'system-ui, sans-serif', fill: '#666' },
    }, cat.length > 12 ? cat.slice(0, 11) + '\u2026' : cat)
  )

  const legend = valueFields.length > 1
    ? valueFields.map((field, j) =>
        h('g', { transform: `translate(${margins.left + j * 120}, ${height - 12})` },
          h('line', {
            x1: '0', y1: '-2', x2: '12', y2: '-2',
            stroke: getColor(colors, j), 'stroke-width': '2.5',
          }),
          h('circle', { cx: '6', cy: '-2', r: '3', fill: getColor(colors, j) }),
          h('text', {
            x: '18', y: '2',
            style: { fontSize: '11px', fontFamily: 'system-ui, sans-serif', fill: '#555' },
          }, field)
        )
      )
    : []

  return h('svg', {
    xmlns: 'http://www.w3.org/2000/svg',
    width: String(width),
    height: String(height),
    viewBox: `0 0 ${width} ${height}`,
    style: { backgroundColor: '#ffffff', borderRadius: '8px' },
  },
    renderTitle(config.title, width),
    ...gridLines,
    h('line', {
      x1: String(margins.left), y1: String(margins.top),
      x2: String(margins.left), y2: String(height - margins.bottom),
      stroke: '#ccc', 'stroke-width': '1',
    }),
    h('line', {
      x1: String(margins.left), y1: String(height - margins.bottom),
      x2: String(width - margins.right), y2: String(height - margins.bottom),
      stroke: '#ccc', 'stroke-width': '1',
    }),
    ...yTickLabels,
    ...lines,
    ...dots,
    ...xLabels,
    ...legend,
    renderYLabel(config.yLabel, height, margins),
    renderXLabel(config.xLabel, width, height),
  )
}

export const renderPieChart = (data: DataRow[], config: ChartConfig) => {
  const width = config.width ?? DEFAULT_WIDTH
  const height = config.height ?? DEFAULT_HEIGHT
  const margins = pieMargins
  const colors = config.colors ?? getPalette()

  const valueField = config.valueFields[0]
  const categories = data.map((row) => String(row[config.categoryField] ?? ''))
  const values = data.map((row) => Math.max(0, coerceNumeric(row[valueField])))
  const total = values.reduce((sum, v) => sum + v, 0)

  if (total === 0) {
    return h('svg', {
      xmlns: 'http://www.w3.org/2000/svg',
      width: String(width), height: String(height),
      viewBox: `0 0 ${width} ${height}`,
    },
      h('text', {
        x: String(width / 2), y: String(height / 2),
        'text-anchor': 'middle',
        style: { fontSize: '14px', fontFamily: 'system-ui, sans-serif', fill: '#999' },
      }, 'No data to display')
    )
  }

  const cx = (width - margins.right) / 2 + margins.left / 2
  const cy = (height - margins.bottom) / 2 + margins.top / 2
  const radius = Math.min(
    (width - margins.left - margins.right) / 2,
    (height - margins.top - margins.bottom) / 2
  ) * 0.85

  let currentAngle = -Math.PI / 2
  const slices = values.map((val, i) => {
    const sliceAngle = (val / total) * 2 * Math.PI
    const startAngle = currentAngle
    const endAngle = currentAngle + sliceAngle
    currentAngle = endAngle

    const x1 = cx + radius * Math.cos(startAngle)
    const y1 = cy + radius * Math.sin(startAngle)
    const x2 = cx + radius * Math.cos(endAngle)
    const y2 = cy + radius * Math.sin(endAngle)
    const largeArc = sliceAngle > Math.PI ? 1 : 0

    const path = sliceAngle >= 2 * Math.PI - 0.001
      ? [
          `M ${cx + radius} ${cy}`,
          `A ${radius} ${radius} 0 1 1 ${cx - radius} ${cy}`,
          `A ${radius} ${radius} 0 1 1 ${cx + radius} ${cy}`,
          'Z',
        ].join(' ')
      : `M ${cx} ${cy} L ${x1} ${y1} A ${radius} ${radius} 0 ${largeArc} 1 ${x2} ${y2} Z`

    const midAngle = startAngle + sliceAngle / 2
    const labelR = radius * 0.65
    const labelX = cx + labelR * Math.cos(midAngle)
    const labelY = cy + labelR * Math.sin(midAngle)
    const pct = ((val / total) * 100).toFixed(1)

    return h('g', {},
      h('path', {
        d: path,
        fill: getColor(colors, i),
        stroke: '#fff',
        'stroke-width': '2',
      }),
      sliceAngle > 0.2
        ? h('text', {
            x: String(labelX),
            y: String(labelY + 4),
            'text-anchor': 'middle',
            style: { fontSize: '11px', fontWeight: '600', fontFamily: 'system-ui, sans-serif', fill: '#fff' },
          }, `${pct}%`)
        : null,
    )
  })

  const legendX = width - margins.right + 20
  const legendItems = categories.map((cat, i) =>
    h('g', { transform: `translate(${legendX}, ${margins.top + 20 + i * 22})` },
      h('rect', { x: '0', y: '-10', width: '14', height: '14', fill: getColor(colors, i), rx: '2' }),
      h('text', {
        x: '20', y: '1',
        style: { fontSize: '11px', fontFamily: 'system-ui, sans-serif', fill: '#555' },
      }, cat.length > 16 ? cat.slice(0, 15) + '\u2026' : cat)
    )
  )

  return h('svg', {
    xmlns: 'http://www.w3.org/2000/svg',
    width: String(width),
    height: String(height),
    viewBox: `0 0 ${width} ${height}`,
    style: { backgroundColor: '#ffffff', borderRadius: '8px' },
  },
    renderTitle(config.title, width),
    ...slices,
    ...legendItems,
  )
}

