  switch (config.type) {
    case 'bar': return renderBarChart(data, config)
    case 'line': return renderLineChart(data, config)
    case 'pie': return renderPieChart(data, config)
  }
}

import { h } from '@plaited/template'

type TokenType = 'key' | 'string' | 'number' | 'boolean' | 'null' | 'punctuation'

type Token = {
  text: string
  type: TokenType
}

const tokenColors: Record<TokenType, string> = {
  key: '#9c27b0',
  string: '#2e7d32',
  number: '#1565c0',
  boolean: '#e65100',
  null: '#78909c',
  punctuation: '#37474f',
}

const tokenize = (json: string): Token[] => {
  const tokens: Token[] = []
  const regex =
    /("(?:\\.|[^"\\])*")\s*(?=:)|("(?:\\.|[^"\\])*")|((?:-?\d+\.?\d*)|(?:-?\.\d+))([eE][+-]?\d+)?|(true|false)|(null)|([[\]{}:,])|(\s+)/g

  let match: RegExpExecArray | null
  while ((match = regex.exec(json)) !== null) {
    if (match[1]) {
      tokens.push({ text: match[1], type: 'key' })
    } else if (match[2]) {
      tokens.push({ text: match[2], type: 'string' })
    } else if (match[3]) {
      const text = match[4] ? match[3] + match[4] : match[3]
      tokens.push({ text, type: 'number' })
    } else if (match[5]) {
      tokens.push({ text: match[5], type: 'boolean' })
    } else if (match[6]) {
      tokens.push({ text: match[6], type: 'null' })
    } else if (match[7]) {
      tokens.push({ text: match[7], type: 'punctuation' })
    } else if (match[8]) {
      tokens.push({ text: match[8], type: 'punctuation' })
    }
  }
  return tokens
}

export const highlightJson = (json: string) => {
  const tokens = tokenize(json)
  return tokens.map((token) =>
    h('span', {
      style: { color: tokenColors[token.type] ?? '#333' },
    }, token.text)
  )
}

