const validateJsonInput = (input: string): { data: DataRow[] | null; error: string | null } => {
  try {
    const parsed = JSON.parse(input)
    if (!Array.isArray(parsed)) {
      return { data: null, error: 'Input must be a JSON array' }
    }
    if (parsed.length === 0) {
      return { data: null, error: 'Array must contain at least one object' }
    }
    if (typeof parsed[0] !== 'object' || parsed[0] === null || Array.isArray(parsed[0])) {
      return { data: null, error: 'Array items must be objects' }
    }
    return { data: parsed, error: null }
  } catch (e) {
    const msg = e instanceof SyntaxError ? e.message : 'Invalid JSON'
    return { data: null, error: msg }
  }
}

const autoSelectFields = (data: DataRow[]): { categoryField: string; valueFields: string[] } => {
  const parsed = parseData(data)
  const categorical = getCategoricalFields(parsed.fields)
  const numeric = getNumericFields(parsed.fields)

  const categoryField = categorical[0] ?? numeric[0] ?? Object.keys(data[0])[0]
  const valueFields = numeric.length > 0
    ? numeric.filter((f) => f !== categoryField)
    : []

  return {
    categoryField,
    valueFields: valueFields.length > 0 ? valueFields : [Object.keys(data[0])[1] ?? Object.keys(data[0])[0]],
  }
}

