export const renderApp = (
  jsonInput?: string,
  chartConfig?: Partial<ChartConfig>,
) => {
  const inputStr = jsonInput ?? JSON.stringify(SAMPLE_DATA, null, 2)
  const { data, error } = validateJsonInput(inputStr)
  const rows = data ?? SAMPLE_DATA

  const { categoryField, valueFields } = autoSelectFields(rows)
  const allFields = Object.keys(rows[0])

  const config: ChartConfig = {
    type: chartConfig?.type ?? 'bar',
    title: chartConfig?.title ?? 'Chart',
    xLabel: chartConfig?.xLabel ?? '',
    yLabel: chartConfig?.yLabel ?? '',
    categoryField: chartConfig?.categoryField ?? categoryField,
    valueFields: chartConfig?.valueFields ?? valueFields,
    colors: chartConfig?.colors,
    width: chartConfig?.width ?? 640,
    height: chartConfig?.height ?? 400,
  }

  return h('div', {
    style: {
      maxWidth: '900px',
      margin: '0 auto',
      padding: '24px',
      fontFamily: 'system-ui, sans-serif',
      color: '#1a1a1a',
