import type { MapData, MapMarker, MapCircle, AddMarkerPayload, AddCirclePayload } from './types'

const DATA_PATH = './data/markers.json'

const generateId = (prefix: string): string =>
  `${prefix}_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`

export const loadData = async (): Promise<MapData> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) {
    const empty: MapData = { markers: [], circles: [], categories: [] }
    await Bun.write(DATA_PATH, JSON.stringify(empty, null, 2))
    return empty
  }
  return file.json() as Promise<MapData>
}

const saveData = async (data: MapData): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(data, null, 2))
}

export const addMarker = async (payload: AddMarkerPayload): Promise<MapMarker> => {
  const data = await loadData()
  const marker: MapMarker = {
    id: generateId('m'),
    ...payload,
  }
  data.markers.push(marker)
  await saveData(data)
  return marker
}

export const removeMarker = async (id: string): Promise<boolean> => {
  const data = await loadData()
  const idx = data.markers.findIndex((m) => m.id === id)
  if (idx === -1) return false
  data.markers.splice(idx, 1)
  await saveData(data)
  return true
}

export const addCircle = async (payload: AddCirclePayload): Promise<MapCircle> => {
  const data = await loadData()
  const circle: MapCircle = {
    id: generateId('c'),
    lat: payload.lat,
    lng: payload.lng,
    radius: payload.radius,
    title: payload.title,
    color: payload.color ?? '#3388ff',
  }
  data.circles.push(circle)
  await saveData(data)
  return circle
}

export const removeCircle = async (id: string): Promise<boolean> => {
  const data = await loadData()
  const idx = data.circles.findIndex((c) => c.id === id)
  if (idx === -1) return false
  data.circles.splice(idx, 1)
  await saveData(data)
  return true
}

export const getMarkersByCategory = async (category: string): Promise<MapMarker[]> => {
  const data = await loadData()
  if (category === 'all') return data.markers
  return data.markers.filter((m) => m.category === category)
}

import type { SearchResult } from './types'

const NOMINATIM_BASE = 'https://nominatim.openstreetmap.org/search'

export const searchLocation = async (query: string): Promise<SearchResult[]> => {
  const params = new URLSearchParams({
    q: query,
    format: 'json',
    limit: '5',
    addressdetails: '1',
  })

  const response = await fetch(`${NOMINATIM_BASE}?${params}`, {
    headers: {
      'User-Agent': 'interactive-map-module/1.0',
    },
  })

  if (!response.ok) {
    return []
  }

  const results = (await response.json()) as Array<{
    lat: string
    lon: string
    display_name: string
  }>

  return results.map((r) => ({
    lat: parseFloat(r.lat),
    lng: parseFloat(r.lon),
    displayName: r.display_name,
  }))
}

