      if (r.ok) {
        MAP_DATA.markers = MAP_DATA.markers.filter(m => m.id !== deleteId);
        if (markerLayers[deleteId]) { map.removeLayer(markerLayers[deleteId]); delete markerLayers[deleteId]; }
        renderSidebar();
      }
