import { loadData, addMarker, removeMarker, addCircle, removeCircle } from './store'
import { searchLocation } from './search'
import { renderPage } from './render'
import type { AddMarkerPayload, AddCirclePayload } from './types'

const json = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const html = (body: string): Response =>
  new Response(body, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const { pathname } = url
  const method = req.method

  // Serve main page
  if (pathname === '/' && method === 'GET') {
    const data = await loadData()
    return html(renderPage(data))
  }

  // API: Get all data
  if (pathname === '/api/data' && method === 'GET') {
    const data = await loadData()
    return json(data)
  }

  // API: Add marker
  if (pathname === '/api/markers' && method === 'POST') {
    const payload = (await req.json()) as AddMarkerPayload
    if (!payload.title || payload.lat == null || payload.lng == null) {
      return json({ error: 'title, lat, lng required' }, 400)
    }
    const marker = await addMarker(payload)
    return json(marker, 201)
  }

  // API: Delete marker
  const markerDelete = pathname.match(/^\/api\/markers\/(.+)$/)
  if (markerDelete && method === 'DELETE') {
    const ok = await removeMarker(markerDelete[1])
    return ok ? json({ ok: true }) : json({ error: 'not found' }, 404)
  }

  // API: Add circle
  if (pathname === '/api/circles' && method === 'POST') {
    const payload = (await req.json()) as AddCirclePayload
    if (!payload.title || payload.lat == null || payload.lng == null) {
      return json({ error: 'title, lat, lng, radius required' }, 400)
    }
    const circle = await addCircle(payload)
    return json(circle, 201)
  }

  // API: Delete circle
  const circleDelete = pathname.match(/^\/api\/circles\/(.+)$/)
  if (circleDelete && method === 'DELETE') {
    const ok = await removeCircle(circleDelete[1])
    return ok ? json({ ok: true }) : json({ error: 'not found' }, 404)
  }

  // API: Search location
  if (pathname === '/api/search' && method === 'GET') {
    const query = url.searchParams.get('q') ?? ''
    if (query.length < 2) return json([])
    const results = await searchLocation(query)
    return json(results)
  }

  return json({ error: 'not found' }, 404)
}

