}

const writeData = async (data: MapData): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(data, null, 2))
}

export const getMapData = async (): Promise<MapData> => readData()

export const addMarker = async (
  marker: Omit<MapMarker, 'id'>
): Promise<MapMarker> => {
  const data = await readData()
  const newMarker: MapMarker = { id: generateId('m'), ...marker }
  data.markers.push(newMarker)
  await writeData(data)
  return newMarker
}

export const removeMarker = async (id: string): Promise<boolean> => {
  const data = await readData()
  const idx = data.markers.findIndex((m) => m.id === id)
  if (idx === -1) return false
  data.markers.splice(idx, 1)
  await writeData(data)
  return true
}

export const updateMarker = async (
  id: string,
  updates: Partial<Omit<MapMarker, 'id'>>
): Promise<MapMarker | null> => {
  const data = await readData()
  const marker = data.markers.find((m) => m.id === id)
  if (!marker) return null
  Object.assign(marker, updates)
  await writeData(data)
  return marker
}

export const addCircle = async (
  circle: Omit<MapCircle, 'id'>
): Promise<MapCircle> => {
  const data = await readData()
  const newCircle: MapCircle = { id: generateId('c'), ...circle }
  data.circles.push(newCircle)
  await writeData(data)
  return newCircle
}

export const removeCircle = async (id: string): Promise<boolean> => {
  const data = await readData()
  const idx = data.circles.findIndex((c) => c.id === id)
  if (idx === -1) return false
  data.circles.splice(idx, 1)
  await writeData(data)
  return true
}

export const addCategory = async (
  category: Omit<MarkerCategory, 'id'>
): Promise<MarkerCategory> => {
  const data = await readData()
  const newCat: MarkerCategory = { id: generateId('cat'), ...category }
  data.categories.push(newCat)
  await writeData(data)
  return newCat
}

export const removeCategory = async (id: string): Promise<boolean> => {
  const data = await readData()
  const idx = data.categories.findIndex((c) => c.id === id)
  if (idx === -1) return false
  data.categories.splice(idx, 1)
  data.markers = data.markers.filter((m) => m.categoryId !== id)
  await writeData(data)
  return true
}

export const updateMapView = async (
  center: { lat: number; lng: number },
  zoom: number
): Promise<void> => {
  const data = await readData()
  data.center = center
  data.zoom = zoom
  await writeData(data)
}

export type SearchResult = {
  lat: number
  lng: number
  displayName: string
}

export const searchLocation = async (
  query: string
): Promise<SearchResult[]> => {
  const encoded = encodeURIComponent(query)
  const url = `https://nominatim.openstreetmap.org/search?format=json&q=${encoded}&limit=5`

  const response = await fetch(url, {
    headers: {
      'User-Agent': 'interactive-map-module/1.0',
    },
  })

  if (!response.ok) return []

  const results = (await response.json()) as Array<{
    lat: string
    lon: string
    display_name: string
  }>

  return results.map((r) => ({
    lat: parseFloat(r.lat),
    lng: parseFloat(r.lon),
    displayName: r.display_name,
  }))
}

