        .custom-marker-icon {
          width: 28px; height: 28px; border-radius: 50% 50% 50% 0;
          transform: rotate(-45deg); border: 2px solid #fff;
          box-shadow: 0 2px 6px rgba(0,0,0,0.3);
        }
        .custom-marker-icon .inner {
          width: 10px; height: 10px; border-radius: 50%;
