          top: 50%; left: 50%; transform: translate(-50%, -50%);
        }
        `
      )
    ),
    h(
      'body',
      {},
      h(
        'div',
        { style: styleToString(styles.container), id: 'app' },
        h(
          'div',
          { style: styleToString(styles.sidebar), id: 'sidebar' },
