      h(
        'script',
        {},
        `
(function() {
  const mapData = ${JSON.stringify({ markers, circles, categories, center, zoom })};

  const categoryMap = {};
  mapData.categories.forEach(c => { categoryMap[c.id] = c; });

  const map = L.map('map').setView([mapData.center.lat, mapData.center.lng], mapData.zoom);

  L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
    attribution: '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors',
    maxZoom: 19,
  }).addTo(map);

  const markerLayers = {};
  const circleLayers = [];

  const createMarkerIcon = (color) => {
    return L.divIcon({
      className: '',
      html: '<div class="custom-marker-icon" style="background-color:' + color + '"><div class="inner"></div></div>',
      iconSize: [28, 28],
      iconAnchor: [14, 28],
      popupAnchor: [0, -28],
    });
  };

  mapData.markers.forEach(m => {
    const cat = categoryMap[m.categoryId];
    const color = cat ? cat.color : '#888';
    const icon = createMarkerIcon(color);
    const layer = L.marker([m.lat, m.lng], { icon })
      .addTo(map)
      .bindPopup('<strong>' + escapeHtml(m.title) + '</strong><br>' + escapeHtml(m.description));
    markerLayers[m.id] = layer;
  });

  mapData.circles.forEach(c => {
    const layer = L.circle([c.lat, c.lng], {
      radius: c.radiusMeters,
      color: c.color,
      fillColor: c.color,
      fillOpacity: 0.15,
      weight: 2,
    }).addTo(map).bindPopup('<strong>' + escapeHtml(c.title) + '</strong><br>Radius: ' + c.radiusMeters + 'm');
    circleLayers.push({ id: c.id, layer });
  });

  function escapeHtml(str) {
    const div = document.createElement('div');
    div.textContent = str;
    return div.innerHTML;
  }

  // Sidebar marker click
  document.getElementById('marker-list').addEventListener('click', (e) => {
    const item = e.target.closest('.marker-item');
    if (!item) return;
    const lat = parseFloat(item.dataset.lat);
    const lng = parseFloat(item.dataset.lng);
    const id = item.dataset.id;
    map.flyTo([lat, lng], 16, { duration: 0.8 });
    if (markerLayers[id]) markerLayers[id].openPopup();
  });

  // Category filter
  let activeFilter = 'all';
  document.getElementById('filter-container').addEventListener('click', (e) => {
    const chip = e.target.closest('.filter-chip');
    if (!chip) return;
    activeFilter = chip.dataset.category;

    document.querySelectorAll('.filter-chip').forEach(c => {
      c.classList.remove('active');
      c.style.borderColor = '#45475a';
      c.style.backgroundColor = '#313244';
    });
    chip.classList.add('active');
    chip.style.borderColor = '#89b4fa';
    chip.style.backgroundColor = '#89b4fa22';

    document.querySelectorAll('#marker-list [data-category]').forEach(group => {
      if (activeFilter === 'all' || group.dataset.category === activeFilter) {
        group.style.display = '';
      } else {
        group.style.display = 'none';
      }
    });

    mapData.markers.forEach(m => {
      if (markerLayers[m.id]) {
        if (activeFilter === 'all' || m.categoryId === activeFilter) {
          markerLayers[m.id].addTo(map);
        } else {
          map.removeLayer(markerLayers[m.id]);
        }
      }
    });
  });

  // Search
  const searchInput = document.getElementById('search-input');
  const searchBtn = document.getElementById('search-btn');
  const searchResults = document.getElementById('search-results');

  const doSearch = async () => {
    const query = searchInput.value.trim();
    if (!query) return;
    searchBtn.textContent = '...';
    try {
      const resp = await fetch('/api/search?q=' + encodeURIComponent(query));
      const results = await resp.json();
      if (results.length === 0) {
        searchResults.style.display = 'block';
        searchResults.innerHTML = '<div style="padding:8px;color:#a6adc8;font-size:13px;">No results found</div>';
        return;
      }
      searchResults.style.display = 'block';
      searchResults.innerHTML = results.map(r =>
        '<div class="search-result-item" style="padding:8px;border-radius:6px;cursor:pointer;font-size:13px;color:#cdd6f4;background-color:#313244;margin-bottom:4px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap" data-lat="' + r.lat + '" data-lng="' + r.lng + '">' + escapeHtml(r.displayName) + '</div>'
      ).join('');
    } catch(e) {
      console.error('Search failed', e);
    } finally {
      searchBtn.textContent = 'Go';
    }
  };

  searchBtn.addEventListener('click', doSearch);
  searchInput.addEventListener('keydown', (e) => {
    if (e.key === 'Enter') doSearch();
  });

  searchResults.addEventListener('click', (e) => {
    const item = e.target.closest('.search-result-item');
    if (!item) return;
    const lat = parseFloat(item.dataset.lat);
    const lng = parseFloat(item.dataset.lng);
    map.flyTo([lat, lng], 15, { duration: 1 });
    searchResults.style.display = 'none';
    searchInput.value = '';
  });

  // Add marker mode
  let addingMarker = false;
  let addingCircle = false;

  document.getElementById('add-marker-btn').addEventListener('click', () => {
    addingMarker = !addingMarker;
    addingCircle = false;
    document.getElementById('add-marker-btn').style.backgroundColor = addingMarker ? '#89b4fa' : '#313244';
    document.getElementById('add-marker-btn').style.color = addingMarker ? '#1e1e2e' : '#cdd6f4';
    document.getElementById('add-circle-btn').style.backgroundColor = '#313244';
    document.getElementById('add-circle-btn').style.color = '#cdd6f4';
    map.getContainer().style.cursor = addingMarker ? 'crosshair' : '';
  });

  document.getElementById('add-circle-btn').addEventListener('click', () => {
    addingCircle = !addingCircle;
    addingMarker = false;
    document.getElementById('add-circle-btn').style.backgroundColor = addingCircle ? '#89b4fa' : '#313244';
    document.getElementById('add-circle-btn').style.color = addingCircle ? '#1e1e2e' : '#cdd6f4';
    document.getElementById('add-marker-btn').style.backgroundColor = '#313244';
    document.getElementById('add-marker-btn').style.color = '#cdd6f4';
    map.getContainer().style.cursor = addingCircle ? 'crosshair' : '';
  });

  map.on('click', async (e) => {
    if (addingMarker) {
      const title = prompt('Marker title:');
      if (!title) return;
      const description = prompt('Description:') || '';
      const catOptions = mapData.categories.map((c, i) => (i + 1) + '. ' + c.name).join('\\n');
      const catChoice = prompt('Category:\\n' + catOptions + '\\n\\nEnter number:');
      const catIndex = parseInt(catChoice) - 1;
      const categoryId = (catIndex >= 0 && catIndex < mapData.categories.length) ? mapData.categories[catIndex].id : mapData.categories[0].id;

      try {
        const resp = await fetch('/api/markers', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ title, description, lat: e.latlng.lat, lng: e.latlng.lng, categoryId }),
        });
        const newMarker = await resp.json();
        const cat = categoryMap[categoryId];
        const color = cat ? cat.color : '#888';
        const icon = createMarkerIcon(color);
        markerLayers[newMarker.id] = L.marker([newMarker.lat, newMarker.lng], { icon })
          .addTo(map)
          .bindPopup('<strong>' + escapeHtml(newMarker.title) + '</strong><br>' + escapeHtml(newMarker.description))
          .openPopup();
      } catch(err) { console.error(err); }

      addingMarker = false;
      document.getElementById('add-marker-btn').style.backgroundColor = '#313244';
      document.getElementById('add-marker-btn').style.color = '#cdd6f4';
      map.getContainer().style.cursor = '';
    }

    if (addingCircle) {
      const title = prompt('Circle title:');
      if (!title) return;
      const radiusStr = prompt('Radius in meters:', '500');
      const radiusMeters = parseInt(radiusStr) || 500;
      const color = prompt('Color (hex):', '#3388ff') || '#3388ff';

      try {
        const resp = await fetch('/api/circles', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ title, lat: e.latlng.lat, lng: e.latlng.lng, radiusMeters, color }),
        });
        const newCircle = await resp.json();
        L.circle([newCircle.lat, newCircle.lng], {
          radius: newCircle.radiusMeters,
          color: newCircle.color,
          fillColor: newCircle.color,
          fillOpacity: 0.15,
          weight: 2,
        }).addTo(map).bindPopup('<strong>' + escapeHtml(newCircle.title) + '</strong><br>Radius: ' + newCircle.radiusMeters + 'm').openPopup();
      } catch(err) { console.error(err); }

      addingCircle = false;
      document.getElementById('add-circle-btn').style.backgroundColor = '#313244';
      document.getElementById('add-circle-btn').style.color = '#cdd6f4';
      map.getContainer().style.cursor = '';
    }
  });

  // Close search results when clicking elsewhere
  document.addEventListener('click', (e) => {
    if (!searchResults.contains(e.target) && e.target !== searchInput && e.target !== searchBtn) {
      searchResults.style.display = 'none';
    }
  });
})();
        `
      )
    )
  )

  const ssr = createSSR()
  return '<!DOCTYPE html>' + ssr(template)
}

import { getMapData, addMarker, removeMarker, updateMarker, addCircle, removeCircle, addCategory, removeCategory } from './store'
import { searchLocation } from './search'
import { renderMap } from './render'

const PORT = parseInt(process.env.PORT ?? '3000', 10)

const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const htmlResponse = (html: string): Response =>
  new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const parseBody = async <T>(req: Request): Promise<T> =>
  (await req.json()) as T

const server = Bun.serve({
  port: PORT,
  fetch: async (req) => {
    const url = new URL(req.url)
    const { pathname } = url
    const method = req.method

    // Serve the map page
    if (pathname === '/' && method === 'GET') {
      const data = await getMapData()
      return htmlResponse(renderMap(data))
    }

    // API: search locations
    if (pathname === '/api/search' && method === 'GET') {
      const query = url.searchParams.get('q') ?? ''
      if (!query) return jsonResponse([])
      const results = await searchLocation(query)
      return jsonResponse(results)
    }

    // API: get all map data
    if (pathname === '/api/data' && method === 'GET') {
      const data = await getMapData()
      return jsonResponse(data)
    }

    // API: markers
    if (pathname === '/api/markers' && method === 'POST') {
      const body = await parseBody<{
        title: string
        description: string
        lat: number
        lng: number
        categoryId: string
      }>(req)
      const marker = await addMarker(body)
      return jsonResponse(marker, 201)
    }

    if (pathname.startsWith('/api/markers/') && method === 'PATCH') {
      const id = pathname.split('/').pop()!
      const body = await parseBody<Record<string, unknown>>(req)
      const updated = await updateMarker(id, body)
      if (!updated) return jsonResponse({ error: 'Not found' }, 404)
      return jsonResponse(updated)
    }

    if (pathname.startsWith('/api/markers/') && method === 'DELETE') {
      const id = pathname.split('/').pop()!
      const removed = await removeMarker(id)
      if (!removed) return jsonResponse({ error: 'Not found' }, 404)
      return jsonResponse({ ok: true })
    }

    // API: circles
    if (pathname === '/api/circles' && method === 'POST') {
      const body = await parseBody<{
        title: string
        lat: number
        lng: number
        radiusMeters: number
        color: string
      }>(req)
      const circle = await addCircle(body)
      return jsonResponse(circle, 201)
    }

    if (pathname.startsWith('/api/circles/') && method === 'DELETE') {
      const id = pathname.split('/').pop()!
      const removed = await removeCircle(id)
      if (!removed) return jsonResponse({ error: 'Not found' }, 404)
      return jsonResponse({ ok: true })
    }

    // API: categories
    if (pathname === '/api/categories' && method === 'POST') {
      const body = await parseBody<{ name: string; color: string }>(req)
      const category = await addCategory(body)
      return jsonResponse(category, 201)
    }

    if (pathname.startsWith('/api/categories/') && method === 'DELETE') {
      const id = pathname.split('/').pop()!
      const removed = await removeCategory(id)
      if (!removed) return jsonResponse({ error: 'Not found' }, 404)
      return jsonResponse({ ok: true })
    }

    return jsonResponse({ error: 'Not found' }, 404)
  },
})

