};

export type MapCircle = {
  id: string;
  center: LatLng;
  radius: number;
  label: string;
  color: string;
  createdAt: string;
};

export type MapState = {
  markers: MapMarker[];
  circles: MapCircle[];
  categories: MarkerCategory[];
