import type { MapMarker, MapCircle, MarkerCategory, MapState } from './types';

const DATA_DIR = `${import.meta.dir}/data`;

const readJson = async <T>(filename: string): Promise<T> => {
  const file = Bun.file(`${DATA_DIR}/${filename}`);
  return file.json() as Promise<T>;
};

const writeJson = async <T>(filename: string, data: T): Promise<void> => {
  await Bun.write(`${DATA_DIR}/${filename}`, JSON.stringify(data, null, 2));
};

export const getMarkers = (): Promise<MapMarker[]> => readJson('markers.json');

export const getCircles = (): Promise<MapCircle[]> => readJson('circles.json');

export const getCategories = (): Promise<MarkerCategory[]> => readJson('categories.json');

export const getState = async (): Promise<MapState> => {
  const [markers, circles, categories] = await Promise.all([
    getMarkers(),
    getCircles(),
    getCategories(),
  ]);
  return { markers, circles, categories };
};

export const addMarker = async (marker: MapMarker): Promise<void> => {
  const markers = await getMarkers();
  markers.push(marker);
  await writeJson('markers.json', markers);
};

export const removeMarker = async (id: string): Promise<void> => {
  const markers = await getMarkers();
  const filtered = markers.filter((m) => m.id !== id);
  await writeJson('markers.json', filtered);
};

export const updateMarker = async (id: string, updates: Partial<MapMarker>): Promise<void> => {
  const markers = await getMarkers();
  const idx = markers.findIndex((m) => m.id === id);
  if (idx === -1) return;
  markers[idx] = { ...markers[idx], ...updates, id };
  await writeJson('markers.json', markers);
};

export const addCircle = async (circle: MapCircle): Promise<void> => {
  const circles = await getCircles();
  circles.push(circle);
  await writeJson('circles.json', circles);
};

export const removeCircle = async (id: string): Promise<void> => {
  const circles = await getCircles();
  const filtered = circles.filter((c) => c.id !== id);
  await writeJson('circles.json', filtered);
};

export const addCategory = async (category: MarkerCategory): Promise<void> => {
  const categories = await getCategories();
  categories.push(category);
  await writeJson('categories.json', categories);
};

export const removeCategory = async (id: string): Promise<void> => {
  const categories = await getCategories();
  const filtered = categories.filter((c) => c.id !== id);
  await writeJson('categories.json', filtered);
};

