const getClientScript = (state: MapState): string => `
(function() {
  var mapState = ${JSON.stringify(state)};
  var categories = mapState.categories;
  var categoryMap = {};
  categories.forEach(function(c) { categoryMap[c.id] = c; });

  var hiddenCategories = {};
  var leafletMarkers = {};
  var leafletCircles = {};
  var addingMarker = false;
  var addingCircle = false;

  var map = L.map('map').setView([40.7128, -74.0060], 12);

  L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
    attribution: '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors',
    maxZoom: 19
  }).addTo(map);

  function makeIcon(color) {
    return L.divIcon({
      className: '',
      html: '<div class="marker-icon" style="background:' + color + ';"></div>',
      iconSize: [24, 24],
      iconAnchor: [12, 24],
      popupAnchor: [0, -24]
    });
  }

  function addMarkerToMap(m) {
    var cat = categoryMap[m.categoryId] || { color: '#999' };
    var icon = makeIcon(cat.color);
    var lm = L.marker([m.position.lat, m.position.lng], { icon: icon })
      .bindPopup('<b>' + escapeHtml(m.title) + '</b>' + (m.description ? '<br>' + escapeHtml(m.description) : '') + '<br><small>' + (cat.name || '') + '</small>');
    if (!hiddenCategories[m.categoryId]) {
      lm.addTo(map);
    }
    leafletMarkers[m.id] = lm;
  }

  function addCircleToMap(c) {
    var lc = L.circle([c.center.lat, c.center.lng], {
      radius: c.radius,
      color: c.color,
      fillColor: c.color,
      fillOpacity: 0.15,
      weight: 2
    }).addTo(map);
    if (c.label) lc.bindPopup('<b>' + escapeHtml(c.label) + '</b><br>Radius: ' + c.radius + 'm');
    leafletCircles[c.id] = lc;
  }

  function escapeHtml(str) {
    var d = document.createElement('div');
    d.textContent = str;
    return d.innerHTML;
  }

  mapState.markers.forEach(addMarkerToMap);
  mapState.circles.forEach(addCircleToMap);

  // Search
  document.getElementById('searchForm').addEventListener('submit', function(e) {
    e.preventDefault();
    var q = document.getElementById('searchInput').value.trim();
    if (!q) return;
    fetch('https://nominatim.openstreetmap.org/search?format=json&q=' + encodeURIComponent(q))
      .then(function(r) { return r.json(); })
      .then(function(results) {
        if (results.length > 0) {
          var r = results[0];
          map.flyTo([parseFloat(r.lat), parseFloat(r.lon)], 14);
        } else {
          alert('Location not found');
        }
      })
      .catch(function() { alert('Search failed'); });
  });

  // Sidebar click-to-center
  document.getElementById('markerList').addEventListener('click', function(e) {
    var item = e.target.closest('[data-lat][data-lng]');
    if (!item) return;

    // Handle delete buttons
    var deleteBtn = e.target.closest('[p-trigger*="deleteMarker"]');
    if (deleteBtn) {
      e.stopPropagation();
      var id = deleteBtn.dataset.id;
      fetch('/api/markers/' + id, { method: 'DELETE' }).then(function() { location.reload(); });
      return;
    }
    var deleteCircleBtn = e.target.closest('[p-trigger*="deleteCircle"]');
    if (deleteCircleBtn) {
      e.stopPropagation();
      var cid = deleteCircleBtn.dataset.id;
      fetch('/api/circles/' + cid, { method: 'DELETE' }).then(function() { location.reload(); });
      return;
    }

    var lat = parseFloat(item.dataset.lat);
    var lng = parseFloat(item.dataset.lng);
    map.flyTo([lat, lng], 16);

    var mid = item.dataset.id;
    if (leafletMarkers[mid]) leafletMarkers[mid].openPopup();
  });

  // Category filters
  document.getElementById('filters').addEventListener('change', function(e) {
    var cb = e.target;
    if (!cb.dataset.categoryId) return;
    var catId = cb.dataset.categoryId;
    if (cb.checked) {
      delete hiddenCategories[catId];
      mapState.markers.forEach(function(m) {
        if (m.categoryId === catId && leafletMarkers[m.id]) {
          leafletMarkers[m.id].addTo(map);
        }
      });
    } else {
      hiddenCategories[catId] = true;
      mapState.markers.forEach(function(m) {
        if (m.categoryId === catId && leafletMarkers[m.id]) {
          map.removeLayer(leafletMarkers[m.id]);
        }
      });
    }
  });

  // Add Marker flow
  var markerModal = document.getElementById('markerModal');
  document.getElementById('addMarkerBtn').addEventListener('click', function() {
    addingMarker = true;
    addingCircle = false;
    markerModal.classList.add('open');
    document.getElementById('markerTitleInput').value = '';
    document.getElementById('markerDescInput').value = '';
    document.getElementById('markerLatInput').value = '';
    document.getElementById('markerLngInput').value = '';
  });
  document.getElementById('markerCancelBtn').addEventListener('click', function() {
    addingMarker = false;
    markerModal.classList.remove('open');
  });
  document.getElementById('markerSubmitBtn').addEventListener('click', function() {
    var title = document.getElementById('markerTitleInput').value.trim();
    var lat = parseFloat(document.getElementById('markerLatInput').value);
    var lng = parseFloat(document.getElementById('markerLngInput').value);
    if (!title || isNaN(lat) || isNaN(lng)) { alert('Title and valid coordinates are required'); return; }
    var body = {
      title: title,
      description: document.getElementById('markerDescInput').value.trim(),
      lat: lat,
      lng: lng,
      categoryId: document.getElementById('markerCategorySelect').value
    };
    fetch('/api/markers', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body)
    }).then(function() { location.reload(); });
  });

  // Add Circle flow
  var circleModal = document.getElementById('circleModal');
  document.getElementById('addCircleBtn').addEventListener('click', function() {
    addingCircle = true;
    addingMarker = false;
    circleModal.classList.add('open');
    document.getElementById('circleLabelInput').value = '';
    document.getElementById('circleLatInput').value = '';
    document.getElementById('circleLngInput').value = '';
    document.getElementById('circleRadiusInput').value = '500';
    document.getElementById('circleColorInput').value = '#2196F3';
  });
  document.getElementById('circleCancelBtn').addEventListener('click', function() {
    addingCircle = false;
    circleModal.classList.remove('open');
  });
  document.getElementById('circleSubmitBtn').addEventListener('click', function() {
    var lat = parseFloat(document.getElementById('circleLatInput').value);
    var lng = parseFloat(document.getElementById('circleLngInput').value);
    var radius = parseFloat(document.getElementById('circleRadiusInput').value);
    if (isNaN(lat) || isNaN(lng) || isNaN(radius)) { alert('Valid coordinates and radius are required'); return; }
    var body = {
      label: document.getElementById('circleLabelInput').value.trim(),
      lat: lat,
      lng: lng,
      radius: radius,
      color: document.getElementById('circleColorInput').value
    };
    fetch('/api/circles', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body)
    }).then(function() { location.reload(); });
  });

  // Map click to set coords in open modal
  map.on('click', function(e) {
    if (addingMarker) {
      document.getElementById('markerLatInput').value = e.latlng.lat.toFixed(6);
      document.getElementById('markerLngInput').value = e.latlng.lng.toFixed(6);
    }
    if (addingCircle) {
      document.getElementById('circleLatInput').value = e.latlng.lat.toFixed(6);
      document.getElementById('circleLngInput').value = e.latlng.lng.toFixed(6);
    }
  });
})();
`;

import {
  getState,
  addMarker,
  removeMarker,
  addCircle,
  removeCircle,
} from './store';
import { renderPage } from './render';
import type { MapMarker, MapCircle } from './types';

const generateId = (): string =>
  `${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`;

const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  });

export const handleGetPage = async (): Promise<Response> => {
  const state = await getState();
  const html = renderPage(state);
  return new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  });
};

export const handleGetState = async (): Promise<Response> => {
  const state = await getState();
  return jsonResponse(state);
};

export const handleAddMarker = async (req: Request): Promise<Response> => {
  const body = await req.json() as {
    title: string;
    description?: string;
    lat: number;
    lng: number;
    categoryId: string;
  };

  if (!body.title || typeof body.lat !== 'number' || typeof body.lng !== 'number') {
    return jsonResponse({ error: 'title, lat, and lng are required' }, 400);
  }

  const marker: MapMarker = {
    id: generateId(),
    position: { lat: body.lat, lng: body.lng },
    title: body.title,
    description: body.description ?? '',
    categoryId: body.categoryId || 'default',
    createdAt: new Date().toISOString(),
  };

  await addMarker(marker);
  return jsonResponse(marker, 201);
};

export const handleDeleteMarker = async (id: string): Promise<Response> => {
  await removeMarker(id);
  return jsonResponse({ ok: true });
};

export const handleAddCircle = async (req: Request): Promise<Response> => {
  const body = await req.json() as {
    label?: string;
    lat: number;
    lng: number;
    radius: number;
    color?: string;
  };

  if (typeof body.lat !== 'number' || typeof body.lng !== 'number' || typeof body.radius !== 'number') {
    return jsonResponse({ error: 'lat, lng, and radius are required' }, 400);
  }

  const circle: MapCircle = {
    id: generateId(),
    center: { lat: body.lat, lng: body.lng },
    radius: body.radius,
    label: body.label ?? '',
    color: body.color ?? '#2196F3',
    createdAt: new Date().toISOString(),
  };

  await addCircle(circle);
  return jsonResponse(circle, 201);
};

export const handleDeleteCircle = async (id: string): Promise<Response> => {
  await removeCircle(id);
  return jsonResponse({ ok: true });
};

import {
  handleGetPage,
  handleGetState,
  handleAddMarker,
  handleDeleteMarker,
  handleAddCircle,
  handleDeleteCircle,
} from './handlers';

const PORT = Number(process.env.PORT) || 3000;

const extractId = (pathname: string, prefix: string): string =>
  pathname.slice(prefix.length);

const server = Bun.serve({
  port: PORT,
  fetch: async (req) => {
    const url = new URL(req.url);
    const { pathname } = url;
    const method = req.method;

    // Page routes
    if (pathname === '/' && method === 'GET') {
      return handleGetPage();
    }

    // API routes
    if (pathname === '/api/state' && method === 'GET') {
      return handleGetState();
    }

    if (pathname === '/api/markers' && method === 'POST') {
      return handleAddMarker(req);
    }

    if (pathname.startsWith('/api/markers/') && method === 'DELETE') {
      const id = extractId(pathname, '/api/markers/');
      return handleDeleteMarker(id);
    }

    if (pathname === '/api/circles' && method === 'POST') {
      return handleAddCircle(req);
    }

    if (pathname.startsWith('/api/circles/') && method === 'DELETE') {
      const id = extractId(pathname, '/api/circles/');
      return handleDeleteCircle(id);
    }

    return new Response('Not Found', { status: 404 });
  },
});

