const DATA_PATH = `${import.meta.dir}/data/events.jsonl`

export const readEvents = async (): Promise<CalendarEvent[]> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return []

  const text = await file.text()
  return text
    .split('\n')
    .filter((line) => line.trim().length > 0)
    .map((line) => JSON.parse(line) as CalendarEvent)
}

export const writeEvents = async (events: CalendarEvent[]): Promise<void> => {
  const content = events.map((e) => JSON.stringify(e)).join('\n')
  await Bun.write(DATA_PATH, content + (events.length > 0 ? '\n' : ''))
}

