import type { DayCell, MonthGrid, EventCategory } from './types'

const MONTH_NAMES = [
  'January', 'February', 'March', 'April', 'May', 'June',
  'July', 'August', 'September', 'October', 'November', 'December',
]

const WEEKDAY_LABELS = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat']

const formatDate = (year: number, month: number, day: number): string => {
  const m = String(month + 1).padStart(2, '0')
  const d = String(day).padStart(2, '0')
  return `${year}-${m}-${d}`
}

const getTodayString = (): string => {
  const now = new Date()
  return formatDate(now.getFullYear(), now.getMonth(), now.getDate())
}

export const buildMonthGrid = (
  year: number,
  month: number,
  eventDateMap: Map<string, EventCategory[]>
): MonthGrid => {
  const today = getTodayString()
  const firstDay = new Date(year, month, 1)
  const startDow = firstDay.getDay() // 0=Sun
  const daysInMonth = new Date(year, month + 1, 0).getDate()

  // Previous month fill
  const prevMonthDays = new Date(year, month, 0).getDate()

  const weeks: DayCell[][] = []
  let currentDay = 1
  let nextMonthDay = 1

  for (let week = 0; week < 6; week++) {
    const row: DayCell[] = []
    for (let dow = 0; dow < 7; dow++) {
      const cellIndex = week * 7 + dow

      if (cellIndex < startDow) {
        // Previous month
        const day = prevMonthDays - startDow + cellIndex + 1
        const prevMonth = month === 0 ? 11 : month - 1
        const prevYear = month === 0 ? year - 1 : year
        const dateStr = formatDate(prevYear, prevMonth, day)
        const cats = eventDateMap.get(dateStr) ?? []
        row.push({
          date: dateStr,
          dayOfMonth: day,
          isCurrentMonth: false,
          isToday: dateStr === today,
          hasEvents: cats.length > 0,
          eventCategories: cats,
        })
      } else if (currentDay > daysInMonth) {
        // Next month
        const nextMonth = month === 11 ? 0 : month + 1
        const nextYear = month === 11 ? year + 1 : year
        const dateStr = formatDate(nextYear, nextMonth, nextMonthDay)
        const cats = eventDateMap.get(dateStr) ?? []
        row.push({
          date: dateStr,
          dayOfMonth: nextMonthDay,
          isCurrentMonth: false,
          isToday: dateStr === today,
          hasEvents: cats.length > 0,
          eventCategories: cats,
        })
        nextMonthDay++
      } else {
        const dateStr = formatDate(year, month, currentDay)
        const cats = eventDateMap.get(dateStr) ?? []
        row.push({
          date: dateStr,
          dayOfMonth: currentDay,
          isCurrentMonth: true,
          isToday: dateStr === today,
          hasEvents: cats.length > 0,
          eventCategories: cats,
        })
        currentDay++
      }
    }
    weeks.push(row)
  }

  return {
    year,
    month,
    label: `${MONTH_NAMES[month]} ${year}`,
    weeks,
  }
}

