import type { CalendarEvent } from './types'

const parseDate = (dateStr: string): Date => {
  const [y, m, d] = dateStr.split('-').map(Number)
  return new Date(y, m - 1, d)
}

const toDateString = (date: Date): string => {
  const y = date.getFullYear()
  const m = String(date.getMonth() + 1).padStart(2, '0')
  const d = String(date.getDate()).padStart(2, '0')
  return `${y}-${m}-${d}`
}

/**
 * Expand a recurring event into occurrences within a date range.
 * Returns synthetic event objects with parentId set.
 */
export const expandRecurrence = (
  event: CalendarEvent,
  rangeStart: string,
  rangeEnd: string
): CalendarEvent[] => {
  if (!event.recurrence) return []

  const occurrences: CalendarEvent[] = []
  const start = parseDate(event.date)
  const end = event.recurrenceEndDate
    ? parseDate(event.recurrenceEndDate)
    : parseDate(rangeEnd)
  const windowStart = parseDate(rangeStart)
  const windowEnd = parseDate(rangeEnd)

  const cursor = new Date(start)
  let safetyLimit = 366 // max one year of daily events

  while (cursor <= end && cursor <= windowEnd && safetyLimit-- > 0) {
    if (cursor >= windowStart && toDateString(cursor) !== event.date) {
      occurrences.push({
        ...event,
        id: `${event.id}_${toDateString(cursor)}`,
        date: toDateString(cursor),
        parentId: event.id,
      })
    }

    switch (event.recurrence) {
      case 'daily':
        cursor.setDate(cursor.getDate() + 1)
        break
      case 'weekly':
        cursor.setDate(cursor.getDate() + 7)
        break
      case 'monthly':
        cursor.setMonth(cursor.getMonth() + 1)
        break
    }
  }

  return occurrences
}

/**
 * Given all stored events and a date range, return every event
 * (including expanded recurring occurrences) that falls in the range.
 */
export const resolveEventsInRange = (
  events: CalendarEvent[],
  rangeStart: string,
  rangeEnd: string
): CalendarEvent[] => {
  const result: CalendarEvent[] = []

  for (const event of events) {
    // Include the original if it falls in range
    if (event.date >= rangeStart && event.date <= rangeEnd) {
      result.push(event)
    }
    // Expand recurrences
    if (event.recurrence) {
      result.push(...expandRecurrence(event, rangeStart, rangeEnd))
    }
  }

  return result
}

import type { CalendarEvent, EventCategory } from './types'
import { readEvents, writeEvents, generateId } from './store'
import { resolveEventsInRange } from './recurrence'

export type CreateEventInput = {
  title: string
  date: string
  startTime: string
  endTime: string
  description?: string
  category?: EventCategory
  recurrence?: CalendarEvent['recurrence']
  recurrenceEndDate?: string | null
}

export const createEvent = async (input: CreateEventInput): Promise<CalendarEvent> => {
  const events = await readEvents()
  const event: CalendarEvent = {
    id: generateId(),
    title: input.title,
    date: input.date,
    startTime: input.startTime,
    endTime: input.endTime,
    description: input.description ?? '',
    category: input.category ?? 'personal',
    recurrence: input.recurrence ?? null,
    recurrenceEndDate: input.recurrenceEndDate ?? null,
    parentId: null,
  }
  events.push(event)
  await writeEvents(events)
  return event
}

export const updateEvent = async (
  id: string,
  updates: Partial<Omit<CalendarEvent, 'id'>>
): Promise<CalendarEvent | null> => {
  const events = await readEvents()
  // If editing a recurrence instance, find or create an override
  const realId = id.includes('_') ? id.split('_')[0] : id
  const isRecurrenceInstance = id !== realId

  if (isRecurrenceInstance) {
    // Create a standalone copy detached from recurrence
    const parent = events.find((e) => e.id === realId)
    if (!parent) return null

    const instanceDate = id.replace(`${realId}_`, '')
    const override: CalendarEvent = {
      ...parent,
      ...updates,
      id: generateId(),
      date: updates.date ?? instanceDate,
      recurrence: null,
      recurrenceEndDate: null,
      parentId: realId,
    }
    events.push(override)
    await writeEvents(events)
    return override
  }

  const idx = events.findIndex((e) => e.id === id)
  if (idx === -1) return null

  events[idx] = { ...events[idx], ...updates }
  await writeEvents(events)
  return events[idx]
}

export const deleteEvent = async (id: string): Promise<boolean> => {
  const events = await readEvents()
  const realId = id.includes('_') ? id.split('_')[0] : id

  if (id !== realId) {
    // Deleting a recurrence instance is not supported in simple mode;
    // user should edit the parent's recurrence end date instead.
    return false
  }

  const idx = events.findIndex((e) => e.id === id)
  if (idx === -1) return false

  // Also remove any overrides linked to this event
  const filtered = events.filter((e) => e.id !== id && e.parentId !== id)
  await writeEvents(filtered)
  return true
}

export const getEventsForDate = async (date: string): Promise<CalendarEvent[]> => {
  const events = await readEvents()
  const resolved = resolveEventsInRange(events, date, date)

  // Remove duplicates where an override exists for a recurrence instance
  const overrideDates = new Set(
    resolved.filter((e) => e.parentId && !e.id.includes('_')).map((e) => `${e.parentId}_${e.date}`)
  )
  const deduped = resolved.filter((e) => {
    if (e.id.includes('_') && overrideDates.has(e.id)) return false
    return true
  })

  return deduped.sort((a, b) => a.startTime.localeCompare(b.startTime))
}

export const getEventsForMonth = async (
  year: number,
  month: number
): Promise<CalendarEvent[]> => {
  const startDate = `${year}-${String(month + 1).padStart(2, '0')}-01`
  const lastDay = new Date(year, month + 1, 0).getDate()
  const endDate = `${year}-${String(month + 1).padStart(2, '0')}-${String(lastDay).padStart(2, '0')}`

  const events = await readEvents()
  return resolveEventsInRange(events, startDate, endDate)
}

export const getEventById = async (id: string): Promise<CalendarEvent | null> => {
  const events = await readEvents()
  const realId = id.includes('_') ? id.split('_')[0] : id
  return events.find((e) => e.id === realId) ?? null
}

