export const renderMonthView = async (year: number, month: number) => {
  const monthEvents = await getEventsForMonth(year, month)

  // Build category map per date
  const dateMap = new Map<string, EventCategory[]>()
  for (const evt of monthEvents) {
    const existing = dateMap.get(evt.date) ?? []
    existing.push(evt.category)
    dateMap.set(evt.date, existing)
  }

  const grid = buildMonthGrid(year, month, dateMap)

  const prevMonth = month === 0 ? 11 : month - 1
  const prevYear = month === 0 ? year - 1 : year
  const nextMonth = month === 11 ? 0 : month + 1
  const nextYear = month === 11 ? year + 1 : year

  return h(
    'div',
    { style: styleToStr(styles.container) },
    h(
      'div',
      { style: styleToStr(styles.header) },
      h(
        'button',
        {
          style: styleToStr(styles.navBtn),
          'p-trigger': 'click:navigate-month',
          'data-year': String(prevYear),
          'data-month': String(prevMonth),
        },
        '\u2190 Prev'
      ),
      h('span', { style: styleToStr(styles.monthLabel) }, grid.label),
      h(
        'button',
        {
          style: styleToStr(styles.navBtn),
          'p-trigger': 'click:navigate-month',
          'data-year': String(nextYear),
          'data-month': String(nextMonth),
        },
        'Next \u2192'
      )
    ),
    h(
      'div',
      { style: styleToStr(styles.grid) },
      ...WEEKDAY_LABELS.map((day) =>
        h('div', { style: styleToStr(styles.weekdayHeader) }, day)
      ),
      ...grid.weeks.flatMap((week) => week.map(renderDayCell))
    )
  )
}

