export const renderToHTML = async (state: AppState): Promise<string> => {
  let template

  switch (state.currentView) {
    case 'month':
      template = await renderMonthView(state.viewYear, state.viewMonth)
      break
    case 'day':
      template = state.selectedDate
        ? await renderDayView(state.selectedDate)
        : await renderMonthView(state.viewYear, state.viewMonth)
      break
    case 'event-form':
      template = renderEventForm(
        state.selectedDate ? { date: state.selectedDate } : undefined
      )
      break
    default:
      template = await renderMonthView(state.viewYear, state.viewMonth)
  }

  const ssr = createSSR()
  return ssr(template)
}

