const now = new Date()

const defaultState: AppState = {
  currentView: 'month',
  viewYear: now.getFullYear(),
  viewMonth: now.getMonth(),
  selectedDate: null,
  editingEventId: null,
}

const parseBody = async (req: Request): Promise<Record<string, string>> => {
  const ct = req.headers.get('content-type') ?? ''
  if (ct.includes('application/json')) {
    return req.json()
  }
  const form = await req.formData()
  const obj: Record<string, string> = {}
  form.forEach((val, key) => {
    obj[key] = String(val)
  })
  return obj
}

const serve = Bun.serve({
  port: 3000,

  fetch: async (req) => {
    const url = new URL(req.url)
    const method = req.method

    // ── API Routes ──────────────────────────────────────────────

    if (url.pathname === '/api/events' && method === 'POST') {
      const body = await parseBody(req) as unknown as CreateEventInput
      const event = await createEvent(body)
      return Response.json(event, { status: 201 })
    }

    if (url.pathname.startsWith('/api/events/') && method === 'PUT') {
      const id = url.pathname.split('/').pop()!
      const body = await parseBody(req)
      const updated = await updateEvent(id, body)
      if (!updated) return Response.json({ error: 'Not found' }, { status: 404 })
      return Response.json(updated)
    }

    if (url.pathname.startsWith('/api/events/') && method === 'DELETE') {
      const id = url.pathname.split('/').pop()!
      const ok = await deleteEvent(id)
      if (!ok) return Response.json({ error: 'Not found' }, { status: 404 })
      return Response.json({ ok: true })
    }

    // ── View Routes ─────────────────────────────────────────────

    const year = parseInt(url.searchParams.get('year') ?? String(defaultState.viewYear), 10)
    const month = parseInt(url.searchParams.get('month') ?? String(defaultState.viewMonth), 10)
    const date = url.searchParams.get('date')
    const view = url.searchParams.get('view') ?? 'month'
    const editId = url.searchParams.get('edit')

    let state: AppState = {
      currentView: view as AppState['currentView'],
      viewYear: year,
      viewMonth: month,
      selectedDate: date,
      editingEventId: editId,
    }

    if (view === 'event-form' && editId) {
      const event = await getEventById(editId)
      if (event) {
        const html = await renderToHTML({
          ...state,
          currentView: 'event-form',
        })
        return new Response(html, {
          headers: { 'Content-Type': 'text/html; charset=utf-8' },
        })
      }
    }

    const html = await renderToHTML(state)
    return new Response(html, {
      headers: { 'Content-Type': 'text/html; charset=utf-8' },
    })
  },
})

