import type { CalendarEvent, CreateEventInput, UpdateEventInput } from './types'

const DATA_PATH = `${import.meta.dir}/data/events.jsonl`

const generateId = (): string => crypto.randomUUID()

const readEvents = async (): Promise<CalendarEvent[]> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return []
  const text = await file.text()
  return text
    .trim()
    .split('\n')
    .filter(Boolean)
    .map((line) => JSON.parse(line) as CalendarEvent)
}

const writeEvents = async (events: CalendarEvent[]): Promise<void> => {
  const content = events.map((e) => JSON.stringify(e)).join('\n')
  await Bun.write(DATA_PATH, content + (events.length ? '\n' : ''))
}

export const getAllEvents = async (): Promise<CalendarEvent[]> => {
  return readEvents()
}

export const getEventById = async (id: string): Promise<CalendarEvent | undefined> => {
  const events = await readEvents()
  return events.find((e) => e.id === id)
}

export const createEvent = async (input: CreateEventInput): Promise<CalendarEvent> => {
  const events = await readEvents()
  const newEvent: CalendarEvent = {
    id: generateId(),
    title: input.title,
    date: input.date,
    startTime: input.startTime,
    endTime: input.endTime,
    description: input.description ?? '',
    category: input.category ?? 'personal',
    recurrence: input.recurrence ?? 'none',
    createdAt: new Date().toISOString(),
  }
  events.push(newEvent)
  await writeEvents(events)
  return newEvent
}

export const updateEvent = async (
  id: string,
  updates: UpdateEventInput,
): Promise<CalendarEvent | undefined> => {
  const events = await readEvents()
  const index = events.findIndex((e) => e.id === id)
  if (index === -1) return undefined
  events[index] = { ...events[index], ...updates }
  await writeEvents(events)
  return events[index]
}

export const deleteEvent = async (id: string): Promise<boolean> => {
  const events = await readEvents()
  const filtered = events.filter((e) => e.id !== id)
  if (filtered.length === events.length) return false
  await writeEvents(filtered)
  return true
}

import type { CalendarEvent, CalendarDay, MonthGrid, Recurrence } from './types'

const formatDate = (year: number, month: number, day: number): string => {
  const m = String(month).padStart(2, '0')
  const d = String(day).padStart(2, '0')
  return `${year}-${m}-${d}`
}

const parseDate = (dateStr: string): { year: number; month: number; day: number } => {
  const [year, month, day] = dateStr.split('-').map(Number)
  return { year, month, day }
}

const daysInMonth = (year: number, month: number): number =>
  new Date(year, month, 0).getDate()

const dayOfWeek = (year: number, month: number, day: number): number =>
  new Date(year, month - 1, day).getDay()

const isSameDay = (a: string, b: string): boolean => a === b

const todayStr = (): string => {
  const now = new Date()
  return formatDate(now.getFullYear(), now.getMonth() + 1, now.getDate())
}

/** Check if a recurring event falls on a given target date */
export const eventOccursOn = (event: CalendarEvent, targetDate: string): boolean => {
  if (event.recurrence === 'none') {
    return isSameDay(event.date, targetDate)
  }

  const origin = parseDate(event.date)
  const target = parseDate(targetDate)
  const originMs = new Date(origin.year, origin.month - 1, origin.day).getTime()
  const targetMs = new Date(target.year, target.month - 1, target.day).getTime()

  // Recurrence only applies on or after the original date
  if (targetMs < originMs) return false

  switch (event.recurrence) {
    case 'daily':
      return true
    case 'weekly': {
      const diffDays = Math.round((targetMs - originMs) / (1000 * 60 * 60 * 24))
      return diffDays % 7 === 0
    }
    case 'monthly':
      return target.day === origin.day
    default:
      return isSameDay(event.date, targetDate)
  }
}

/** Get all events that occur on a specific date */
export const getEventsForDate = (
  events: CalendarEvent[],
  date: string,
): CalendarEvent[] => {
  return events
    .filter((e) => eventOccursOn(e, date))
    .sort((a, b) => a.startTime.localeCompare(b.startTime))
}

/** Build a full month grid (6 weeks max) with event data */
export const buildMonthGrid = (
  year: number,
  month: number,
  events: CalendarEvent[],
): MonthGrid => {
  const totalDays = daysInMonth(year, month)
  const firstDow = dayOfWeek(year, month, 1)
  const today = todayStr()

  const days: CalendarDay[] = []

  // Previous month padding
  const prevMonth = month === 1 ? 12 : month - 1
  const prevYear = month === 1 ? year - 1 : year
  const prevDays = daysInMonth(prevYear, prevMonth)
  for (let i = firstDow - 1; i >= 0; i--) {
    const d = prevDays - i
    const date = formatDate(prevYear, prevMonth, d)
    days.push({
      date,
      dayOfMonth: d,
      isCurrentMonth: false,
      isToday: isSameDay(date, today),
      events: getEventsForDate(events, date),
    })
  }

  // Current month days
  for (let d = 1; d <= totalDays; d++) {
    const date = formatDate(year, month, d)
    days.push({
      date,
      dayOfMonth: d,
      isCurrentMonth: true,
      isToday: isSameDay(date, today),
      events: getEventsForDate(events, date),
    })
  }

  // Next month padding to fill remaining cells (complete last week)
  const nextMonth = month === 12 ? 1 : month + 1
  const nextYear = month === 12 ? year + 1 : year
  const remaining = 7 - (days.length % 7)
  if (remaining < 7) {
    for (let d = 1; d <= remaining; d++) {
      const date = formatDate(nextYear, nextMonth, d)
      days.push({
        date,
        dayOfMonth: d,
        isCurrentMonth: false,
        isToday: isSameDay(date, today),
        events: getEventsForDate(events, date),
      })
    }
  }

  // Split into weeks
  const weeks: CalendarDay[][] = []
  for (let i = 0; i < days.length; i += 7) {
    weeks.push(days.slice(i, i + 7))
  }

  return { year, month, weeks }
}

/** Navigate month: returns { year, month } */
export const navigateMonth = (
  year: number,
  month: number,
  direction: 'prev' | 'next',
): { year: number; month: number } => {
  if (direction === 'prev') {
    return month === 1 ? { year: year - 1, month: 12 } : { year, month: month - 1 }
  }
  return month === 12 ? { year: year + 1, month: 1 } : { year, month: month + 1 }
}

const MONTH_NAMES = [
  'January', 'February', 'March', 'April', 'May', 'June',
  'July', 'August', 'September', 'October', 'November', 'December',
]

export const getMonthName = (month: number): string => MONTH_NAMES[month - 1]

export const formatTime = (time24: string): string => {
  const [h, m] = time24.split(':').map(Number)
  const period = h >= 12 ? 'PM' : 'AM'
  const hour12 = h === 0 ? 12 : h > 12 ? h - 12 : h
  return `${hour12}:${String(m).padStart(2, '0')} ${period}`
}

