const styleStr = (obj: Record<string, string | number>): string =>
  Object.entries(obj)
    .map(([k, v]) => {
      const prop = k.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`)
      return `${prop}:${typeof v === 'number' ? `${v}px` : v}`
    })
    .join(';')

/** Render event indicator dots for a calendar day cell */
const renderEventDots = (events: CalendarEvent[]) => {
  const seen = new Set<EventCategory>()
  const dots = events
    .filter((e) => {
      if (seen.has(e.category)) return false
      seen.add(e.category)
      return true
    })
    .slice(0, 4)

  return h(
    'div',
    { style: styleStr(styles.eventDots) },
    ...dots.map((e) =>
      h('span', {
        style: styleStr({ ...styles.eventDot, backgroundColor: CATEGORY_COLORS[e.category] }),
      }),
    ),
  )
}

/** Render a single day cell in the month grid */
const renderDayCell = (day: CalendarDay) => {
  const cellStyle = {
    ...styles.dayCell,
    ...(day.isCurrentMonth ? {} : styles.dayCellMuted),
    ...(day.isToday ? styles.dayCellToday : {}),
  }

  const numberEl = day.isToday
    ? h('div', { style: styleStr(styles.dayNumberToday) }, String(day.dayOfMonth))
    : h('div', { style: styleStr(styles.dayNumber) }, String(day.dayOfMonth))

  return h(
    'div',
    {
      style: styleStr(cellStyle),
      'p-trigger': `click:selectDay:${day.date}`,
    },
    numberEl,
    day.events.length > 0 ? renderEventDots(day.events) : h(Fragment, null),
  )
}

/** Render the monthly calendar grid */
export const renderMonthView = (grid: MonthGrid) => {
  const title = `${getMonthName(grid.month)} ${grid.year}`

  const headerRow = DAY_NAMES.map((name) =>
    h('div', { style: styleStr(styles.dayHeader) }, name),
  )

  const dayCells = grid.weeks.flatMap((week) => week.map(renderDayCell))

  return h(
    'div',
    { style: styleStr(styles.container) },
    h(
      'div',
      { style: styleStr(styles.header) },
      h(
        'button',
        { style: styleStr(styles.navBtn), 'p-trigger': 'click:prevMonth' },
        '\u25C0 Prev',
      ),
      h('h2', { style: styleStr(styles.headerTitle) }, title),
      h(
