import { createSSR } from 'plaited'
import type {
  CalendarState,
  CreateEventInput,
  UpdateEventInput,
  EventCategory,
  Recurrence,
} from './types'
import { getAllEvents, getEventById, createEvent, updateEvent, deleteEvent } from './store'
import { buildMonthGrid, getEventsForDate, navigateMonth, getMonthName } from './calendar'
import {
  renderMonthView,
  renderDayView,
  renderEventForm,
  renderCategoryLegend,
} from './render'

/** Initialize calendar state to the current month */
const createInitialState = (): CalendarState => {
  const now = new Date()
  const year = now.getFullYear()
  const month = now.getMonth() + 1
  const day = String(now.getDate()).padStart(2, '0')
  const m = String(month).padStart(2, '0')
  return {
    viewMode: 'month',
    selectedDate: `${year}-${m}-${day}`,
    year,
    month,
  }
}

/** Render the full month view as an HTML string */
export const renderMonth = async (year: number, month: number): Promise<string> => {
  const events = await getAllEvents()
  const grid = buildMonthGrid(year, month, events)
  const ssr = createSSR()
  const monthHtml = ssr(renderMonthView(grid))
  const legendHtml = ssr(renderCategoryLegend())
  return monthHtml + legendHtml
}

/** Render the day view as an HTML string */
export const renderDay = async (date: string): Promise<string> => {
  const events = await getAllEvents()
  const dayEvents = getEventsForDate(events, date)
  const ssr = createSSR()
  return ssr(renderDayView(date, dayEvents))
}

/** Render the event creation form as an HTML string */
export const renderCreateForm = async (prefillDate?: string): Promise<string> => {
  const ssr = createSSR()
  return ssr(renderEventForm(undefined, prefillDate))
}

/** Render the event edit form as an HTML string */
export const renderEditForm = async (eventId: string): Promise<string> => {
  const event = await getEventById(eventId)
  if (!event) return '<p>Event not found.</p>'
  const ssr = createSSR()
  return ssr(renderEventForm(event))
}

/** Handle creating a new event */
export const handleCreateEvent = async (input: CreateEventInput) => {
  return createEvent(input)
}

/** Handle updating an existing event */
export const handleUpdateEvent = async (id: string, updates: UpdateEventInput) => {
  return updateEvent(id, updates)
}

/** Handle deleting an event */
export const handleDeleteEvent = async (id: string) => {
  return deleteEvent(id)
}

/** Navigate to the previous or next month */
export const handleNavigateMonth = (
  year: number,
  month: number,
  direction: 'prev' | 'next',
) => {
  return navigateMonth(year, month, direction)
}

/** Get events for a specific date, including recurring ones */
export const getDateEvents = async (date: string) => {
  const events = await getAllEvents()
  return getEventsForDate(events, date)
}

/** Get a summary of events for a month (for external consumers) */
export const getMonthSummary = async (year: number, month: number) => {
  const events = await getAllEvents()
  const grid = buildMonthGrid(year, month, events)
  const daysWithEvents = grid.weeks
    .flat()
    .filter((d) => d.isCurrentMonth && d.events.length > 0)
    .map((d) => ({
      date: d.date,
      dayOfMonth: d.dayOfMonth,
      eventCount: d.events.length,
      categories: [...new Set(d.events.map((e) => e.category))],
    }))

  return {
    year,
    month,
    monthName: getMonthName(month),
    totalEvents: events.length,
    daysWithEvents,
  }
}

// Default export for module consumers
export default {
  createInitialState,
  renderMonth,
  renderDay,
  renderCreateForm,
  renderEditForm,
  handleCreateEvent,
  handleUpdateEvent,
  handleDeleteEvent,
  handleNavigateMonth,
  getDateEvents,
  getMonthSummary,
}

{
  "name": "@node/calendar",
  "version": "1.0.0",
  "description": "Scheduling and calendar module with monthly grid, day view, event CRUD, recurrence, and category color-coding",
  "modnet": {
    "contentType": "tools",
    "structure": "steps",
    "mechanics": ["sort", "filter", "track"],
    "boundary": "none",
    "scale": 2
  },
  "dependencies": {
    "plaited": "latest"
  }
}

export type EventCategory = 'work' | 'personal' | 'health' | 'social';

export type RecurrenceRule = 'none' | 'daily' | 'weekly' | 'monthly';

export type CalendarEvent = {
  id: string;
  title: string;
  date: string; // YYYY-MM-DD
  startTime: string; // HH:MM
  endTime: string; // HH:MM
  description: string;
  category: EventCategory;
  recurrence: RecurrenceRule;
  createdAt: string; // ISO timestamp
};

export type CalendarView = 'month' | 'day';

export type CalendarState = {
  view: CalendarView;
  selectedDate: string; // YYYY-MM-DD
  currentMonth: number; // 0-11
  currentYear: number;
  filterCategory: EventCategory | 'all';
};

export type DayCell = {
  date: string; // YYYY-MM-DD
  dayNumber: number;
  isCurrentMonth: boolean;
  isToday: boolean;
  hasEvents: boolean;
  eventCategories: EventCategory[];
};

export const CATEGORY_COLORS: Record<EventCategory, string> = {
  work: '#3b82f6',
  personal: '#8b5cf6',
  health: '#10b981',
  social: '#f59e0b',
};

export const CATEGORY_LABELS: Record<EventCategory, string> = {
  work: 'Work',
  personal: 'Personal',
  health: 'Health',
  social: 'Social',
};

export const DAYS_OF_WEEK = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'] as const;

export const MONTHS = [
  'January', 'February', 'March', 'April', 'May', 'June',
  'July', 'August', 'September', 'October', 'November', 'December',
] as const;

import type { CalendarEvent } from './types';

const DATA_PATH = `${import.meta.dir}/data/events.json`;

export const loadEvents = async (): Promise<CalendarEvent[]> => {
  const file = Bun.file(DATA_PATH);
  const exists = await file.exists();
  if (!exists) {
    await Bun.write(DATA_PATH, '[]');
    return [];
  }
  const text = await file.text();
  return JSON.parse(text) as CalendarEvent[];
};

export const saveEvents = async (events: CalendarEvent[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(events, null, 2));
};

export const generateId = (): string => {
  return `evt_${Date.now()}_${Math.random().toString(36).slice(2, 9)}`;
};

export const addEvent = async (event: Omit<CalendarEvent, 'id' | 'createdAt'>): Promise<CalendarEvent> => {
  const events = await loadEvents();
  const newEvent: CalendarEvent = {
    ...event,
    id: generateId(),
    createdAt: new Date().toISOString(),
  };
  events.push(newEvent);
  await saveEvents(events);
  return newEvent;
};

export const updateEvent = async (id: string, updates: Partial<Omit<CalendarEvent, 'id' | 'createdAt'>>): Promise<CalendarEvent | null> => {
  const events = await loadEvents();
  const index = events.findIndex((e) => e.id === id);
  if (index === -1) return null;
  events[index] = { ...events[index], ...updates };
  await saveEvents(events);
  return events[index];
};

export const deleteEvent = async (id: string): Promise<boolean> => {
  const events = await loadEvents();
  const filtered = events.filter((e) => e.id !== id);
  if (filtered.length === events.length) return false;
  await saveEvents(filtered);
  return true;
};

export const getEventById = async (id: string): Promise<CalendarEvent | null> => {
  const events = await loadEvents();
  return events.find((e) => e.id === id) ?? null;
};

import type { CalendarEvent, DayCell, EventCategory, RecurrenceRule } from './types';

export const formatDate = (year: number, month: number, day: number): string => {
  const m = String(month + 1).padStart(2, '0');
  const d = String(day).padStart(2, '0');
  return `${year}-${m}-${d}`;
};

export const parseDate = (dateStr: string): { year: number; month: number; day: number } => {
  const [year, month, day] = dateStr.split('-').map(Number);
  return { year, month: month - 1, day };
};

export const getTodayStr = (): string => {
  const now = new Date();
  return formatDate(now.getFullYear(), now.getMonth(), now.getDate());
};

export const getDaysInMonth = (year: number, month: number): number => {
  return new Date(year, month + 1, 0).getDate();
};

export const getFirstDayOfMonth = (year: number, month: number): number => {
  return new Date(year, month, 1).getDay();
};

export const buildMonthGrid = (
  year: number,
  month: number,
  eventsByDate: Map<string, EventCategory[]>
): DayCell[] => {
  const today = getTodayStr();
  const daysInMonth = getDaysInMonth(year, month);
  const firstDay = getFirstDayOfMonth(year, month);

  const prevMonth = month === 0 ? 11 : month - 1;
  const prevYear = month === 0 ? year - 1 : year;
  const daysInPrevMonth = getDaysInMonth(prevYear, prevMonth);

  const cells: DayCell[] = [];

  // Previous month trailing days
  for (let i = firstDay - 1; i >= 0; i--) {
    const dayNum = daysInPrevMonth - i;
    const dateStr = formatDate(prevYear, prevMonth, dayNum);
    const categories = eventsByDate.get(dateStr) ?? [];
    cells.push({
      date: dateStr,
      dayNumber: dayNum,
      isCurrentMonth: false,
      isToday: dateStr === today,
      hasEvents: categories.length > 0,
      eventCategories: categories,
    });
  }

  // Current month days
  for (let day = 1; day <= daysInMonth; day++) {
    const dateStr = formatDate(year, month, day);
    const categories = eventsByDate.get(dateStr) ?? [];
    cells.push({
      date: dateStr,
      dayNumber: day,
      isCurrentMonth: true,
      isToday: dateStr === today,
      hasEvents: categories.length > 0,
      eventCategories: categories,
    });
  }

  // Next month leading days to fill grid to 42 cells (6 rows)
  const nextMonth = month === 11 ? 0 : month + 1;
  const nextYear = month === 11 ? year + 1 : year;
  const remaining = 42 - cells.length;
  for (let day = 1; day <= remaining; day++) {
    const dateStr = formatDate(nextYear, nextMonth, day);
    const categories = eventsByDate.get(dateStr) ?? [];
    cells.push({
      date: dateStr,
      dayNumber: day,
      isCurrentMonth: false,
      isToday: dateStr === today,
      hasEvents: categories.length > 0,
      eventCategories: categories,
    });
  }

  return cells;
};

export const doesEventOccurOnDate = (event: CalendarEvent, targetDate: string): boolean => {
  if (event.recurrence === 'none') {
    return event.date === targetDate;
  }

  const eventParsed = parseDate(event.date);
  const targetParsed = parseDate(targetDate);

  const eventD = new Date(eventParsed.year, eventParsed.month, eventParsed.day);
  const targetD = new Date(targetParsed.year, targetParsed.month, targetParsed.day);

  // Recurrence only applies on or after the original date
  if (targetD < eventD) return false;

  switch (event.recurrence) {
    case 'daily':
      return true;
    case 'weekly': {
      const diffMs = targetD.getTime() - eventD.getTime();
      const diffDays = Math.round(diffMs / (1000 * 60 * 60 * 24));
      return diffDays % 7 === 0;
    }
    case 'monthly':
      return targetParsed.day === eventParsed.day;
    default:
      return false;
  }
};

export const getEventsForDate = (events: CalendarEvent[], targetDate: string): CalendarEvent[] => {
  return events
    .filter((event) => doesEventOccurOnDate(event, targetDate))
    .sort((a, b) => a.startTime.localeCompare(b.startTime));
};

export const getEventCategoriesForDateRange = (
  events: CalendarEvent[],
  year: number,
  month: number
): Map<string, EventCategory[]> => {
  const map = new Map<string, EventCategory[]>();
  const daysInMonth = getDaysInMonth(year, month);

  // Also check a few days in surrounding months for the grid
  const startDate = new Date(year, month, 1);
  startDate.setDate(startDate.getDate() - 6);
  const endDate = new Date(year, month, daysInMonth);
  endDate.setDate(endDate.getDate() + 7);

  const current = new Date(startDate);
  while (current <= endDate) {
    const dateStr = formatDate(current.getFullYear(), current.getMonth(), current.getDate());
    const categories: EventCategory[] = [];
    for (const event of events) {
      if (doesEventOccurOnDate(event, dateStr) && !categories.includes(event.category)) {
        categories.push(event.category);
      }
    }
    if (categories.length > 0) {
      map.set(dateStr, categories);
    }
    current.setDate(current.getDate() + 1);
  }

  return map;
};

export const navigateMonth = (
  year: number,
  month: number,
  direction: 'prev' | 'next'
): { year: number; month: number } => {
  if (direction === 'prev') {
    return month === 0 ? { year: year - 1, month: 11 } : { year, month: month - 1 };
  }
  return month === 11 ? { year: year + 1, month: 0 } : { year, month: month + 1 };
};

export const formatTimeDisplay = (time: string): string => {
  const [h, m] = time.split(':').map(Number);
  const period = h >= 12 ? 'PM' : 'AM';
  const hour12 = h === 0 ? 12 : h > 12 ? h - 12 : h;
  return `${hour12}:${String(m).padStart(2, '0')} ${period}`;
};

