export const renderCalendar = (state: CalendarState, events: CalendarEvent[]) => {
  const filteredEvents = state.filterCategory === 'all'
    ? events
    : events.filter((e) => e.category === state.filterCategory);

  if (state.view === 'month') {
    const categoryMap = getEventCategoriesForDateRange(filteredEvents, state.currentYear, state.currentMonth);
    const cells = buildMonthGrid(state.currentYear, state.currentMonth, categoryMap);

    return h('div', { style: s.containerStyle },
      renderMonthHeader(state.currentYear, state.currentMonth),
      renderFilterBar(state.filterCategory),
      renderMonthGrid(cells),
    );
  }

  // Day view
  const dayEvents = getEventsForDate(filteredEvents, state.selectedDate);
  return h('div', { style: s.containerStyle },
    renderFilterBar(state.filterCategory),
    renderDayView(state.selectedDate, dayEvents),
  );
};

