export type FormData = {
  title: string;
  date: string;
  startTime: string;
  endTime: string;
  description: string;
  category: EventCategory;
  recurrence: RecurrenceRule;
};

export const validateFormData = (data: FormData): string | null => {
  if (!data.title.trim()) return 'Title is required';
  if (!data.date) return 'Date is required';
  if (!data.startTime) return 'Start time is required';
  if (!data.endTime) return 'End time is required';
  if (data.startTime >= data.endTime) return 'End time must be after start time';
  return null;
};

export const handleNavigation = (
  state: CalendarState,
  direction: 'prev' | 'next'
): CalendarState => {
  const { year, month } = navigateMonth(state.currentYear, state.currentMonth, direction);
  return { ...state, currentYear: year, currentMonth: month };
};

export const handleSelectDate = (state: CalendarState, date: string): CalendarState => {
  return { ...state, view: 'day', selectedDate: date };
};

export const handleBackToMonth = (state: CalendarState): CalendarState => {
  return { ...state, view: 'month' };
};

export const handleFilter = (state: CalendarState, category: EventCategory | 'all'): CalendarState => {
  return { ...state, filterCategory: category };
};

export const handleCreateEvent = async (data: FormData): Promise<CalendarEvent> => {
  return addEvent({
    title: data.title.trim(),
    date: data.date,
    startTime: data.startTime,
    endTime: data.endTime,
    description: data.description.trim(),
    category: data.category,
    recurrence: data.recurrence,
  });
};

export const handleUpdateEvent = async (
  id: string,
  data: Partial<FormData>
): Promise<CalendarEvent | null> => {
  return updateEvent(id, data);
};

export const handleDeleteEvent = async (id: string): Promise<boolean> => {
  return deleteEvent(id);
};

export const renderPage = async (state: CalendarState): Promise<string> => {
  const events = await loadEvents();
  const template = renderCalendar(state, events);
  const ssr = createSSR();
  return ssr(template);
};

export const renderEventFormPage = async (
  state: CalendarState,
  eventId?: string
): Promise<string> => {
  let existing: CalendarEvent | undefined;
  if (eventId) {
    const events = await loadEvents();
    existing = events.find((e) => e.id === eventId);
  }
  const template = renderEventForm(state.selectedDate, existing);
  const ssr = createSSR();
  return ssr(template);
};

