import type { HistoryEntry } from './types'

export type HistoryManager = {
  push: (entry: HistoryEntry) => void
  undo: () => HistoryEntry | null
  redo: () => HistoryEntry | null
  canUndo: () => boolean
  canRedo: () => boolean
  clear: () => void
}

export const createHistoryManager = (maxSize = 50): HistoryManager => {
  const undoStack: HistoryEntry[] = []
  const redoStack: HistoryEntry[] = []

  const deepClone = <T>(obj: T): T => JSON.parse(JSON.stringify(obj))

  const push = (entry: HistoryEntry) => {
    undoStack.push(deepClone(entry))
    if (undoStack.length > maxSize) {
      undoStack.shift()
    }
    redoStack.length = 0
  }

  const undo = (): HistoryEntry | null => {
    const entry = undoStack.pop()
    if (!entry) return null
    redoStack.push(deepClone(entry))
    return undoStack.length > 0 ? deepClone(undoStack[undoStack.length - 1]) : null
  }

  const redo = (): HistoryEntry | null => {
    const entry = redoStack.pop()
    if (!entry) return null
    undoStack.push(deepClone(entry))
    return deepClone(entry)
  }

  const canUndo = () => undoStack.length > 1
  const canRedo = () => redoStack.length > 0
  const clear = () => {
    undoStack.length = 0
    redoStack.length = 0
  }

  return { push, undo, redo, canUndo, canRedo, clear }
}

import type { Layer, Stroke } from './types'

let layerCounter = 0

export const createLayer = (name?: string): Layer => {
  layerCounter += 1
  return {
    id: `layer-${layerCounter}-${Date.now()}`,
    name: name ?? `Layer ${layerCounter}`,
    visible: true,
    strokes: [],
    thumbnail: '',
  }
}

export const addStrokeToLayer = (layer: Layer, stroke: Stroke): Layer => ({
  ...layer,
  strokes: [...layer.strokes, stroke],
})

export const removeStrokeFromLayer = (layer: Layer, strokeId: string): Layer => ({
  ...layer,
  strokes: layer.strokes.filter((s) => s.id !== strokeId),
})

export const toggleLayerVisibility = (layer: Layer): Layer => ({
  ...layer,
  visible: !layer.visible,
})

export const renameLayer = (layer: Layer, name: string): Layer => ({
  ...layer,
  name,
})

export const clearLayer = (layer: Layer): Layer => ({
  ...layer,
  strokes: [],
  thumbnail: '',
})

export const reorderLayers = (layers: Layer[], fromIndex: number, toIndex: number): Layer[] => {
  const result = [...layers]
  const [moved] = result.splice(fromIndex, 1)
  result.splice(toIndex, 0, moved)
  return result
}

import type { CanvasState, Layer, Point, Stroke, ShapeStroke } from './types'

export type RenderContext = {
  canvas: HTMLCanvasElement
  ctx: CanvasRenderingContext2D
}

export const createRenderContext = (canvas: HTMLCanvasElement): RenderContext | null => {
  const ctx = canvas.getContext('2d')
  if (!ctx) return null
  return { canvas, ctx }
}

const renderPenStroke = (ctx: CanvasRenderingContext2D, stroke: Stroke) => {
  if (stroke.points.length < 2) return
  ctx.beginPath()
  ctx.strokeStyle = stroke.color
  ctx.lineWidth = stroke.size
  ctx.lineCap = 'round'
  ctx.lineJoin = 'round'
  ctx.moveTo(stroke.points[0].x, stroke.points[0].y)
  for (let i = 1; i < stroke.points.length; i++) {
    const prev = stroke.points[i - 1]
    const curr = stroke.points[i]
    const midX = (prev.x + curr.x) / 2
    const midY = (prev.y + curr.y) / 2
    ctx.quadraticCurveTo(prev.x, prev.y, midX, midY)
  }
  ctx.stroke()
}

const renderEraserStroke = (ctx: CanvasRenderingContext2D, stroke: Stroke) => {
  if (stroke.points.length < 2) return
  ctx.save()
  ctx.globalCompositeOperation = 'destination-out'
  ctx.beginPath()
  ctx.strokeStyle = 'rgba(0,0,0,1)'
  ctx.lineWidth = stroke.size
  ctx.lineCap = 'round'
  ctx.lineJoin = 'round'
  ctx.moveTo(stroke.points[0].x, stroke.points[0].y)
  for (let i = 1; i < stroke.points.length; i++) {
    ctx.lineTo(stroke.points[i].x, stroke.points[i].y)
  }
  ctx.stroke()
  ctx.restore()
}

const renderRectangle = (ctx: CanvasRenderingContext2D, stroke: ShapeStroke) => {
  const { startPoint, endPoint, color, size } = stroke
  ctx.strokeStyle = color
  ctx.lineWidth = size
  ctx.lineCap = 'round'
  const x = Math.min(startPoint.x, endPoint.x)
  const y = Math.min(startPoint.y, endPoint.y)
  const w = Math.abs(endPoint.x - startPoint.x)
  const h = Math.abs(endPoint.y - startPoint.y)
  ctx.strokeRect(x, y, w, h)
}

const renderCircle = (ctx: CanvasRenderingContext2D, stroke: ShapeStroke) => {
  const { startPoint, endPoint, color, size } = stroke
  ctx.strokeStyle = color
  ctx.lineWidth = size
  const cx = (startPoint.x + endPoint.x) / 2
  const cy = (startPoint.y + endPoint.y) / 2
  const rx = Math.abs(endPoint.x - startPoint.x) / 2
  const ry = Math.abs(endPoint.y - startPoint.y) / 2
  ctx.beginPath()
  ctx.ellipse(cx, cy, rx, ry, 0, 0, Math.PI * 2)
  ctx.stroke()
}

const renderLine = (ctx: CanvasRenderingContext2D, stroke: ShapeStroke) => {
  const { startPoint, endPoint, color, size } = stroke
  ctx.strokeStyle = color
  ctx.lineWidth = size
  ctx.lineCap = 'round'
  ctx.beginPath()
  ctx.moveTo(startPoint.x, startPoint.y)
  ctx.lineTo(endPoint.x, endPoint.y)
  ctx.stroke()
}

const renderStroke = (ctx: CanvasRenderingContext2D, stroke: Stroke) => {
  switch (stroke.tool) {
    case 'pen':
      renderPenStroke(ctx, stroke)
      break
    case 'eraser':
      renderEraserStroke(ctx, stroke)
      break
    case 'rectangle':
      renderRectangle(ctx, stroke as ShapeStroke)
      break
    case 'circle':
      renderCircle(ctx, stroke as ShapeStroke)
      break
    case 'line':
      renderLine(ctx, stroke as ShapeStroke)
      break
  }
}

export const renderLayer = (ctx: CanvasRenderingContext2D, layer: Layer) => {
  if (!layer.visible) return
  for (const stroke of layer.strokes) {
    renderStroke(ctx, stroke)
  }
}

export const renderAll = (renderCtx: RenderContext, state: CanvasState) => {
  const { ctx, canvas } = renderCtx
  ctx.clearRect(0, 0, canvas.width, canvas.height)
  for (const layer of state.layers) {
    renderLayer(ctx, layer)
  }
}

export const renderPreviewStroke = (ctx: CanvasRenderingContext2D, stroke: Stroke) => {
  renderStroke(ctx, stroke)
}

export const generateLayerThumbnail = (
  layer: Layer,
  width: number,
  height: number,
  thumbWidth = 60,
  thumbHeight = 40,
): string => {
  if (typeof document === 'undefined') return ''
  const offscreen = document.createElement('canvas')
  offscreen.width = thumbWidth
  offscreen.height = thumbHeight
  const ctx = offscreen.getContext('2d')
  if (!ctx) return ''
  ctx.fillStyle = '#ffffff'
  ctx.fillRect(0, 0, thumbWidth, thumbHeight)
  ctx.scale(thumbWidth / width, thumbHeight / height)
  for (const stroke of layer.strokes) {
    renderStroke(ctx, stroke)
  }
  return offscreen.toDataURL('image/png')
}

import type { CanvasState, DrawingFile } from './types'

const DATA_DIR = './data'

const generateId = (): string => `drawing-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`

export const saveDrawingState = async (state: CanvasState, name: string, existingId?: string): Promise<DrawingFile> => {
  const now = new Date().toISOString()
  const drawing: DrawingFile = {
    id: existingId ?? generateId(),
    name,
    state,
    createdAt: existingId ? (await loadDrawing(existingId))?.createdAt ?? now : now,
    updatedAt: now,
  }
  const filePath = `${DATA_DIR}/${drawing.id}.json`
  await Bun.write(filePath, JSON.stringify(drawing, null, 2))
  await updateIndex(drawing)
  return drawing
}

export const loadDrawing = async (id: string): Promise<DrawingFile | null> => {
  const filePath = `${DATA_DIR}/${id}.json`
  const file = Bun.file(filePath)
  if (!(await file.exists())) return null
  const text = await file.text()
  return JSON.parse(text) as DrawingFile
}

export const listDrawings = async (): Promise<Array<{ id: string; name: string; updatedAt: string }>> => {
  const indexPath = `${DATA_DIR}/index.json`
  const file = Bun.file(indexPath)
  if (!(await file.exists())) return []
  const text = await file.text()
  return JSON.parse(text)
}

export const deleteDrawing = async (id: string): Promise<boolean> => {
  const filePath = `${DATA_DIR}/${id}.json`
  const file = Bun.file(filePath)
  if (!(await file.exists())) return false
  const { unlink } = await import('node:fs/promises')
  await unlink(filePath)
  const index = await listDrawings()
  const filtered = index.filter((d) => d.id !== id)
  await Bun.write(`${DATA_DIR}/index.json`, JSON.stringify(filtered, null, 2))
  return true
}

const updateIndex = async (drawing: DrawingFile) => {
  const index = await listDrawings()
  const existing = index.findIndex((d) => d.id === drawing.id)
  const entry = { id: drawing.id, name: drawing.name, updatedAt: drawing.updatedAt }
  if (existing >= 0) {
    index[existing] = entry
  } else {
    index.push(entry)
  }
  await Bun.write(`${DATA_DIR}/index.json`, JSON.stringify(index, null, 2))
}

export const exportCanvasToPng = (canvas: HTMLCanvasElement): string => {
  return canvas.toDataURL('image/png')
}

export const downloadPng = (canvas: HTMLCanvasElement, filename = 'drawing.png') => {
  const dataUrl = exportCanvasToPng(canvas)
  const link = document.createElement('a')
  link.download = filename
  link.href = dataUrl
  link.click()
}

export const loadImageToCanvas = (
  ctx: CanvasRenderingContext2D,
  dataUrl: string,
  width: number,
  height: number,
): Promise<void> => {
  return new Promise((resolve, reject) => {
    const img = new Image()
    img.onload = () => {
      ctx.clearRect(0, 0, width, height)
      ctx.drawImage(img, 0, 0, width, height)
      resolve()
    }
    img.onerror = reject
    img.src = dataUrl
  })
}

import type { CanvasState, Point, Stroke, ShapeStroke, ToolKind } from './types'
import { createLayer, addStrokeToLayer } from './layers'
import { createHistoryManager, type HistoryManager } from './history'
import { createRenderContext, renderAll, renderPreviewStroke, generateLayerThumbnail, type RenderContext } from './renderer'

let strokeCounter = 0

const generateStrokeId = (): string => {
  strokeCounter += 1
  return `stroke-${strokeCounter}-${Date.now()}`
}

export type CanvasEngine = {
  getState: () => CanvasState
  setState: (state: CanvasState) => void
  setTool: (tool: ToolKind) => void
  setColor: (color: string) => void
  setBrushSize: (size: number) => void
  addLayer: (name?: string) => void
  removeLayer: (layerId: string) => void
  setActiveLayer: (layerId: string) => void
  toggleLayerVisibility: (layerId: string) => void
  clearCanvas: () => void
  clearActiveLayer: () => void
  undo: () => void
  redo: () => void
  canUndo: () => boolean
  canRedo: () => boolean
  onPointerDown: (point: Point) => void
  onPointerMove: (point: Point) => void
  onPointerUp: (point: Point) => void
  render: () => void
  getLayerThumbnails: () => Array<{ id: string; name: string; visible: boolean; thumbnail: string }>
  getRenderContext: () => RenderContext | null
}

export const createCanvasEngine = (
  canvas: HTMLCanvasElement,
  width = 800,
  height = 600,
  onChange?: (state: CanvasState) => void,
): CanvasEngine => {
  canvas.width = width
  canvas.height = height

  const renderCtx = createRenderContext(canvas)
  const history: HistoryManager = createHistoryManager()

  const initialLayer = createLayer('Background')

  let state: CanvasState = {
    layers: [initialLayer],
    activeLayerId: initialLayer.id,
    activeTool: 'pen',
    activeColor: '#000000',
    brushSize: 3,
    width,
    height,
  }

  let isDrawing = false
  let currentStroke: Stroke | null = null
  let startPoint: Point | null = null

  const pushHistory = () => {
    history.push({
      layers: JSON.parse(JSON.stringify(state.layers)),
      activeLayerId: state.activeLayerId,
    })
  }

  pushHistory()

  const notifyChange = () => {
    onChange?.(state)
  }

  const getActiveLayer = () => state.layers.find((l) => l.id === state.activeLayerId)

  const isShapeTool = (tool: ToolKind): boolean =>
    tool === 'rectangle' || tool === 'circle' || tool === 'line'

  const getState = () => state

  const setState = (newState: CanvasState) => {
    state = newState
    render()
    notifyChange()
  }

  const setTool = (tool: ToolKind) => {
    state = { ...state, activeTool: tool }
    notifyChange()
  }

  const setColor = (color: string) => {
    state = { ...state, activeColor: color }
    notifyChange()
  }

  const setBrushSize = (size: number) => {
    state = { ...state, brushSize: Math.max(1, Math.min(100, size)) }
    notifyChange()
  }

  const addLayer = (name?: string) => {
    const layer = createLayer(name)
    state = {
      ...state,
      layers: [...state.layers, layer],
      activeLayerId: layer.id,
    }
    pushHistory()
    render()
    notifyChange()
  }

  const removeLayer = (layerId: string) => {
    if (state.layers.length <= 1) return
    const filtered = state.layers.filter((l) => l.id !== layerId)
    state = {
      ...state,
      layers: filtered,
      activeLayerId: state.activeLayerId === layerId ? filtered[filtered.length - 1].id : state.activeLayerId,
    }
    pushHistory()
    render()
    notifyChange()
  }

  const setActiveLayer = (layerId: string) => {
    state = { ...state, activeLayerId: layerId }
    notifyChange()
  }

  const toggleLayerVisibility = (layerId: string) => {
    state = {
      ...state,
      layers: state.layers.map((l) =>
        l.id === layerId ? { ...l, visible: !l.visible } : l,
      ),
    }
    render()
    notifyChange()
  }

  const clearCanvas = () => {
    state = {
      ...state,
      layers: state.layers.map((l) => ({ ...l, strokes: [], thumbnail: '' })),
    }
    pushHistory()
    render()
    notifyChange()
  }

  const clearActiveLayer = () => {
    state = {
      ...state,
      layers: state.layers.map((l) =>
        l.id === state.activeLayerId ? { ...l, strokes: [], thumbnail: '' } : l,
      ),
    }
    pushHistory()
    render()
    notifyChange()
  }

  const undo = () => {
    const entry = history.undo()
    if (!entry) return
    state = { ...state, layers: entry.layers, activeLayerId: entry.activeLayerId }
    render()
    notifyChange()
  }

  const redo = () => {
    const entry = history.redo()
    if (!entry) return
    state = { ...state, layers: entry.layers, activeLayerId: entry.activeLayerId }
    render()
    notifyChange()
  }

  const canUndo = () => history.canUndo()
  const canRedo = () => history.canRedo()

  const onPointerDown = (point: Point) => {
    isDrawing = true
    startPoint = point
    currentStroke = {
      id: generateStrokeId(),
      tool: state.activeTool,
      points: [point],
      color: state.activeColor,
      size: state.brushSize,
      layerId: state.activeLayerId,
    }
  }

  const onPointerMove = (point: Point) => {
    if (!isDrawing || !currentStroke || !renderCtx) return

    if (isShapeTool(state.activeTool) && startPoint) {
      render()
      const preview: ShapeStroke = {
        ...currentStroke,
        tool: state.activeTool as 'rectangle' | 'circle' | 'line',
        startPoint,
        endPoint: point,
        points: [startPoint, point],
      }
      renderPreviewStroke(renderCtx.ctx, preview)
    } else {
      currentStroke.points.push(point)
      renderPreviewStroke(renderCtx.ctx, currentStroke)
    }
  }

  const onPointerUp = (point: Point) => {
    if (!isDrawing || !currentStroke) return
    isDrawing = false

    const activeLayer = getActiveLayer()
    if (!activeLayer) return

    let finalStroke: Stroke

    if (isShapeTool(state.activeTool) && startPoint) {
      finalStroke = {
        ...currentStroke,
        tool: state.activeTool as 'rectangle' | 'circle' | 'line',
        startPoint,
        endPoint: point,
        points: [startPoint, point],
      } as ShapeStroke
    } else {
      currentStroke.points.push(point)
      finalStroke = currentStroke
    }

    const updatedLayer = addStrokeToLayer(activeLayer, finalStroke)
    state = {
      ...state,
      layers: state.layers.map((l) => (l.id === updatedLayer.id ? updatedLayer : l)),
    }

    currentStroke = null
    startPoint = null
    pushHistory()
    render()
    notifyChange()
  }

  const render = () => {
    if (!renderCtx) return
    renderAll(renderCtx, state)
  }

  const getLayerThumbnails = () =>
    state.layers.map((layer) => ({
      id: layer.id,
      name: layer.name,
      visible: layer.visible,
      thumbnail: generateLayerThumbnail(layer, width, height),
    }))

  const getRenderContext = () => renderCtx

  return {
    getState,
    setState,
    setTool,
    setColor,
    setBrushSize,
    addLayer,
    removeLayer,
    setActiveLayer,
    toggleLayerVisibility,
    clearCanvas,
    clearActiveLayer,
    undo,
    redo,
    canUndo,
    canRedo,
    onPointerDown,
    onPointerMove,
    onPointerUp,
    render,
    getLayerThumbnails,
    getRenderContext,
  }
}

