import { renderApp } from './ui'

export const mountDrawingCanvas = (
  rootElement: HTMLElement,
  canvasWidth = 800,
  canvasHeight = 600,
) => {
  const canvas = document.createElement('canvas')
  const engine = createCanvasEngine(canvas, canvasWidth, canvasHeight, (state) => {
    updateUI()
  })

  const updateUI = () => {
    const state = engine.getState()
    const thumbnails = engine.getLayerThumbnails()

    const toolbarProps = {
      activeTool: state.activeTool,
      activeColor: state.activeColor,
      brushSize: state.brushSize,
      canUndo: engine.canUndo(),
      canRedo: engine.canRedo(),
    }

    const layerItems = thumbnails.map((t) => ({
      ...t,
      active: t.id === state.activeLayerId,
    }))

    const appTemplate = renderApp(toolbarProps, layerItems)
    rootElement.innerHTML = ''

    const wrapper = document.createElement('div')
    wrapper.innerHTML = typeof appTemplate === 'string' ? appTemplate : String(appTemplate)
    rootElement.appendChild(wrapper)

    const canvasTarget = rootElement.querySelector('[p-target="drawing-canvas"]')
    if (canvasTarget) {
      canvasTarget.replaceWith(canvas)
    }

    bindEvents(rootElement)
  }

  const getCanvasPoint = (e: PointerEvent): { x: number; y: number } => {
    const rect = canvas.getBoundingClientRect()
    return {
      x: e.clientX - rect.left,
      y: e.clientY - rect.top,
    }
  }

  canvas.addEventListener('pointerdown', (e) => {
    canvas.setPointerCapture(e.pointerId)
    engine.onPointerDown(getCanvasPoint(e))
  })

  canvas.addEventListener('pointermove', (e) => {
    engine.onPointerMove(getCanvasPoint(e))
  })

  canvas.addEventListener('pointerup', (e) => {
    engine.onPointerUp(getCanvasPoint(e))
  })

  const bindEvents = (root: HTMLElement) => {
    root.querySelectorAll('[p-trigger]').forEach((el) => {
      const triggers = JSON.parse(el.getAttribute('p-trigger') ?? '{}')

      for (const [event, action] of Object.entries(triggers)) {
        if (typeof action !== 'string') continue

        el.addEventListener(event, ((e: Event) => {
          if (action.startsWith('tool-select-')) {
            const tool = action.replace('tool-select-', '')
            engine.setTool(tool as Parameters<typeof engine.setTool>[0])
            updateUI()
          } else if (action === 'undo') {
            engine.undo()
            updateUI()
          } else if (action === 'redo') {
            engine.redo()
            updateUI()
          } else if (action === 'color-change') {
            engine.setColor((e.target as HTMLInputElement).value)
          } else if (action === 'brush-size-change') {
            engine.setBrushSize(Number((e.target as HTMLInputElement).value))
            updateUI()
          } else if (action === 'clear-canvas') {
            engine.clearCanvas()
            updateUI()
          } else if (action === 'save-png') {
            downloadPng(canvas, 'drawing.png')
          } else if (action === 'load-image') {
            const input = document.createElement('input')
            input.type = 'file'
            input.accept = 'image/*'
            input.onchange = () => {
              const file = input.files?.[0]
              if (!file) return
              const reader = new FileReader()
              reader.onload = async () => {
                const ctx = canvas.getContext('2d')
                if (ctx && typeof reader.result === 'string') {
                  await loadImageToCanvas(ctx, reader.result, canvasWidth, canvasHeight)
                }
              }
              reader.readAsDataURL(file)
            }
            input.click()
          } else if (action === 'layer-add') {
            engine.addLayer()
            updateUI()
          } else if (action.startsWith('layer-select-')) {
            const layerId = action.replace('layer-select-', '')
            engine.setActiveLayer(layerId)
            updateUI()
          } else if (action.startsWith('layer-toggle-')) {
            const layerId = action.replace('layer-toggle-', '')
            engine.toggleLayerVisibility(layerId)
            updateUI()
          }
        }) as EventListener)
      }
    })
  }

  updateUI()

  return engine
}

