import type { HistoryEntry, Layer } from './types'

const MAX_HISTORY = 50

export type HistoryManager = {
  push: (entry: HistoryEntry) => void
  undo: () => HistoryEntry | null
  redo: () => HistoryEntry | null
  canUndo: () => boolean
  canRedo: () => boolean
  clear: () => void
}

const cloneLayers = (layers: Layer[]): Layer[] =>
  layers.map((l) => ({
    ...l,
    strokes: l.strokes.map((s) =>
      s.kind === 'brush' || s.kind === 'eraser'
        ? { ...s, points: s.points.map((p) => ({ ...p })) }
        : { ...s, start: { ...s.start }, end: { ...s.end } }
    ),
  }))

export const createHistoryManager = (): HistoryManager => {
  const undoStack: HistoryEntry[] = []
  const redoStack: HistoryEntry[] = []

  const push = (entry: HistoryEntry) => {
    undoStack.push({
      layers: cloneLayers(entry.layers),
      activeLayerId: entry.activeLayerId,
    })
    if (undoStack.length > MAX_HISTORY) {
      undoStack.shift()
    }
    redoStack.length = 0
  }

  const undo = (): HistoryEntry | null => {
    const entry = undoStack.pop()
    if (!entry) return null
    redoStack.push(entry)
    const previous = undoStack[undoStack.length - 1] ?? null
    return previous
      ? { layers: cloneLayers(previous.layers), activeLayerId: previous.activeLayerId }
      : null
  }

  const redo = (): HistoryEntry | null => {
    const entry = redoStack.pop()
    if (!entry) return null
    undoStack.push(entry)
    return { layers: cloneLayers(entry.layers), activeLayerId: entry.activeLayerId }
  }

  const canUndo = () => undoStack.length > 1
  const canRedo = () => redoStack.length > 0
  const clear = () => {
    undoStack.length = 0
    redoStack.length = 0
  }

  return { push, undo, redo, canUndo, canRedo, clear }
}

import type { Layer, Stroke } from './types'

let layerCounter = 0

export const createLayer = (name?: string): Layer => {
  layerCounter++
  return {
    id: `layer-${layerCounter}-${Date.now()}`,
    name: name ?? `Layer ${layerCounter}`,
    visible: true,
    strokes: [],
    thumbnail: '',
  }
}

export const addStrokeToLayer = (layer: Layer, stroke: Stroke): Layer => ({
  ...layer,
  strokes: [...layer.strokes, stroke],
})

export const toggleLayerVisibility = (layer: Layer): Layer => ({
  ...layer,
  visible: !layer.visible,
})

export const removeLayer = (layers: Layer[], id: string): Layer[] =>
  layers.filter((l) => l.id !== id)

export const reorderLayers = (layers: Layer[], fromIndex: number, toIndex: number): Layer[] => {
  const result = [...layers]
  const [moved] = result.splice(fromIndex, 1)
  result.splice(toIndex, 0, moved)
  return result
}

export const renameLayer = (layer: Layer, name: string): Layer => ({
  ...layer,
  name,
})

