}

export const beginFreehandStroke = (
  kind: 'brush' | 'eraser',
  point: Point,
  color: string,
  width: number
): FreehandStroke => ({
  kind,
  points: [point],
  color: kind === 'eraser' ? '#ffffff' : color,
  width,
})

export const continueFreehandStroke = (stroke: FreehandStroke, point: Point): FreehandStroke => ({
  ...stroke,
  points: [...stroke.points, point],
})

export const beginShapeStroke = (
  kind: 'rectangle' | 'circle' | 'line',
  start: Point,
  color: string,
  width: number
): ShapeStroke => ({
  kind,
  start,
  end: start,
  color,
  width,
})

export const updateShapeStroke = (stroke: ShapeStroke, end: Point): ShapeStroke => ({
  ...stroke,
  end,
})

export const isFreehandTool = (tool: ToolKind): tool is 'brush' | 'eraser' =>
  tool === 'brush' || tool === 'eraser'

export const isShapeTool = (tool: ToolKind): tool is 'rectangle' | 'circle' | 'line' =>
  tool === 'rectangle' || tool === 'circle' || tool === 'line'

import type { CanvasState, Layer, Stroke, FreehandStroke, ShapeStroke, Point, ToolState } from './types'
import { createLayer, addStrokeToLayer } from './layers'
import { createHistoryManager, type HistoryManager } from './history'
import {
  beginFreehandStroke,
  continueFreehandStroke,
  beginShapeStroke,
  updateShapeStroke,
  isFreehandTool,
  isShapeTool,
} from './tools'

export type CanvasEngine = {
  getState: () => CanvasState
  getToolState: () => ToolState
  setTool: (tool: ToolState['activeTool']) => void
  setColor: (color: string) => void
  setBrushSize: (size: number) => void
  addLayer: (name?: string) => void
  removeLayer: (id: string) => void
  setActiveLayer: (id: string) => void
  toggleLayerVisibility: (id: string) => void
  renameLayer: (id: string, name: string) => void
  onPointerDown: (point: Point) => void
  onPointerMove: (point: Point) => void
  onPointerUp: () => void
  undo: () => void
  redo: () => void
  canUndo: () => boolean
  canRedo: () => boolean
  clearCanvas: () => void
  exportToPNG: (renderFn: (state: CanvasState) => string) => string
  importFromPNG: (dataUrl: string, layerName?: string) => void
  toJSON: () => string
  fromJSON: (json: string) => void
  renderStrokeToContext: (ctx: OffscreenCanvasContext, stroke: Stroke) => void
}

type OffscreenCanvasContext = {
  beginPath: () => void
  moveTo: (x: number, y: number) => void
  lineTo: (x: number, y: number) => void
  stroke: () => void
  arc: (x: number, y: number, r: number, start: number, end: number) => void
  rect: (x: number, y: number, w: number, h: number) => void
  strokeStyle: string
  lineWidth: number
  lineCap: string
  globalCompositeOperation: string
}

export const createCanvasEngine = (width = 800, height = 600): CanvasEngine => {
  const initialLayer = createLayer('Background')

  let state: CanvasState = {
    layers: [initialLayer],
    activeLayerId: initialLayer.id,
    width,
    height,
  }

  let toolState: ToolState = {
    activeTool: 'brush',
    color: '#000000',
    brushSize: 3,
  }

  let currentStroke: Stroke | null = null
  const history: HistoryManager = createHistoryManager()

  // Push initial state
  history.push({ layers: state.layers, activeLayerId: state.activeLayerId })

  const getActiveLayer = (): Layer | undefined =>
    state.layers.find((l) => l.id === state.activeLayerId)

  const updateLayer = (id: string, updater: (layer: Layer) => Layer) => {
    state = {
      ...state,
      layers: state.layers.map((l) => (l.id === id ? updater(l) : l)),
    }
  }

  const pushHistory = () => {
    history.push({ layers: state.layers, activeLayerId: state.activeLayerId })
  }

  const getState = () => state
  const getToolState = () => toolState

  const setTool = (tool: ToolState['activeTool']) => {
    toolState = { ...toolState, activeTool: tool }
  }

  const setColor = (color: string) => {
    toolState = { ...toolState, color }
  }

  const setBrushSize = (size: number) => {
    toolState = { ...toolState, brushSize: Math.max(1, Math.min(50, size)) }
  }

  const addLayer = (name?: string) => {
    const layer = createLayer(name)
    state = {
      ...state,
      layers: [...state.layers, layer],
      activeLayerId: layer.id,
    }
    pushHistory()
  }

  const removeLayerById = (id: string) => {
    if (state.layers.length <= 1) return
    const filtered = state.layers.filter((l) => l.id !== id)
    state = {
      ...state,
      layers: filtered,
      activeLayerId:
        state.activeLayerId === id ? filtered[filtered.length - 1].id : state.activeLayerId,
    }
    pushHistory()
  }

  const setActiveLayer = (id: string) => {
    if (state.layers.some((l) => l.id === id)) {
      state = { ...state, activeLayerId: id }
    }
  }

  const toggleLayerVis = (id: string) => {
    updateLayer(id, (l) => ({ ...l, visible: !l.visible }))
  }

  const renameLayerById = (id: string, name: string) => {
    updateLayer(id, (l) => ({ ...l, name }))
  }

  const onPointerDown = (point: Point) => {
    const layer = getActiveLayer()
    if (!layer || !layer.visible) return

    const { activeTool, color, brushSize } = toolState

    if (isFreehandTool(activeTool)) {
      currentStroke = beginFreehandStroke(activeTool, point, color, brushSize)
    } else if (isShapeTool(activeTool)) {
      currentStroke = beginShapeStroke(activeTool, point, color, brushSize)
    }
  }

  const onPointerMove = (point: Point) => {
    if (!currentStroke) return

    if (currentStroke.kind === 'brush' || currentStroke.kind === 'eraser') {
      currentStroke = continueFreehandStroke(currentStroke as FreehandStroke, point)
    } else {
      currentStroke = updateShapeStroke(currentStroke as ShapeStroke, point)
    }
  }

  const onPointerUp = () => {
    if (!currentStroke) return
    const layer = getActiveLayer()
    if (layer) {
      updateLayer(layer.id, (l) => addStrokeToLayer(l, currentStroke!))
      pushHistory()
    }
    currentStroke = null
  }

  const undo = () => {
    const entry = history.undo()
    if (entry) {
      state = { ...state, layers: entry.layers, activeLayerId: entry.activeLayerId }
    }
  }

  const redo = () => {
    const entry = history.redo()
    if (entry) {
      state = { ...state, layers: entry.layers, activeLayerId: entry.activeLayerId }
    }
  }

  const clearCanvas = () => {
    state = {
      ...state,
      layers: state.layers.map((l) => ({ ...l, strokes: [] })),
    }
    pushHistory()
  }

  const exportToPNG = (renderFn: (state: CanvasState) => string): string => renderFn(state)

  const importFromPNG = (dataUrl: string, layerName?: string) => {
    const layer = createLayer(layerName ?? 'Imported')
    // Store the data URL as a special stroke for rendering
    const importStroke: FreehandStroke = {
      kind: 'brush',
      points: [{ x: 0, y: 0 }],
      color: dataUrl, // data URL stored in color field for import tracking
      width: 0, // width 0 signals this is an imported image
    }
    state = {
      ...state,
      layers: [...state.layers, { ...layer, strokes: [importStroke] }],
      activeLayerId: layer.id,
    }
    pushHistory()
  }

  const renderStrokeToContext = (ctx: OffscreenCanvasContext, stroke: Stroke) => {
    ctx.strokeStyle = stroke.color
    ctx.lineWidth = stroke.width
    ctx.lineCap = 'round'

    if (stroke.kind === 'eraser') {
      ctx.globalCompositeOperation = 'destination-out'
    }

    if (stroke.kind === 'brush' || stroke.kind === 'eraser') {
      const freehand = stroke as FreehandStroke
      if (freehand.points.length < 2) return
      ctx.beginPath()
      ctx.moveTo(freehand.points[0].x, freehand.points[0].y)
      for (let i = 1; i < freehand.points.length; i++) {
        ctx.lineTo(freehand.points[i].x, freehand.points[i].y)
      }
      ctx.stroke()
    } else {
      const shape = stroke as ShapeStroke
      ctx.beginPath()
      if (shape.kind === 'rectangle') {
        const w = shape.end.x - shape.start.x
        const h = shape.end.y - shape.start.y
        ctx.rect(shape.start.x, shape.start.y, w, h)
        ctx.stroke()
      } else if (shape.kind === 'circle') {
        const dx = shape.end.x - shape.start.x
        const dy = shape.end.y - shape.start.y
        const radius = Math.sqrt(dx * dx + dy * dy)
        ctx.arc(shape.start.x, shape.start.y, radius, 0, Math.PI * 2)
        ctx.stroke()
      } else if (shape.kind === 'line') {
        ctx.moveTo(shape.start.x, shape.start.y)
        ctx.lineTo(shape.end.x, shape.end.y)
        ctx.stroke()
      }
    }

    if (stroke.kind === 'eraser') {
      ctx.globalCompositeOperation = 'source-over'
    }
  }

  const toJSON = (): string =>
    JSON.stringify({
      ...state,
      toolState,
    })

  const fromJSON = (json: string) => {
    const parsed = JSON.parse(json)
    state = {
      layers: parsed.layers,
      activeLayerId: parsed.activeLayerId,
      width: parsed.width,
      height: parsed.height,
    }
    if (parsed.toolState) {
      toolState = parsed.toolState
    }
    history.clear()
    history.push({ layers: state.layers, activeLayerId: state.activeLayerId })
  }

  return {
    getState,
    getToolState,
    setTool,
    setColor,
    setBrushSize,
    addLayer,
    removeLayer: removeLayerById,
    setActiveLayer,
    toggleLayerVisibility: toggleLayerVis,
    renameLayer: renameLayerById,
    onPointerDown,
    onPointerMove,
    onPointerUp,
    undo,
    redo,
    canUndo: () => history.canUndo(),
    canRedo: () => history.canRedo(),
    clearCanvas,
    exportToPNG,
    importFromPNG,
    toJSON,
    fromJSON,
    renderStrokeToContext,
  }
}

import type { DrawingMetadata } from './types'

const DATA_DIR = './data'
const METADATA_FILE = `${DATA_DIR}/drawings.json`

const ensureDataDir = async () => {
  const dir = Bun.file(DATA_DIR)
  try {
    await Bun.write(`${DATA_DIR}/.keep`, '')
  } catch {
    // directory already exists
  }
}

export const listDrawings = async (): Promise<DrawingMetadata[]> => {
  await ensureDataDir()
  const file = Bun.file(METADATA_FILE)
  if (!(await file.exists())) return []
  const text = await file.text()
  return JSON.parse(text) as DrawingMetadata[]
}

export const saveDrawing = async (
  id: string,
  name: string,
  canvasJson: string,
  pngDataUrl?: string
): Promise<DrawingMetadata> => {
  await ensureDataDir()

  const drawings = await listDrawings()
  const now = new Date().toISOString()
  const existing = drawings.find((d) => d.id === id)

  const parsed = JSON.parse(canvasJson)

  const metadata: DrawingMetadata = existing
    ? { ...existing, name, updatedAt: now, width: parsed.width, height: parsed.height }
    : { id, name, createdAt: now, updatedAt: now, width: parsed.width, height: parsed.height }

  const updated = existing ? drawings.map((d) => (d.id === id ? metadata : d)) : [...drawings, metadata]

  await Bun.write(METADATA_FILE, JSON.stringify(updated, null, 2))
  await Bun.write(`${DATA_DIR}/${id}.json`, canvasJson)

  if (pngDataUrl) {
    await Bun.write(`${DATA_DIR}/${id}.png.txt`, pngDataUrl)
  }

  return metadata
}

export const loadDrawing = async (id: string): Promise<string | null> => {
  const file = Bun.file(`${DATA_DIR}/${id}.json`)
  if (!(await file.exists())) return null
  return file.text()
}

export const loadDrawingPng = async (id: string): Promise<string | null> => {
  const file = Bun.file(`${DATA_DIR}/${id}.png.txt`)
  if (!(await file.exists())) return null
  return file.text()
}

export const deleteDrawing = async (id: string): Promise<boolean> => {
  const drawings = await listDrawings()
  const filtered = drawings.filter((d) => d.id !== id)
  if (filtered.length === drawings.length) return false

  await Bun.write(METADATA_FILE, JSON.stringify(filtered, null, 2))

  try {
    const { $ } = Bun
    await $`rm -f ${DATA_DIR}/${id}.json ${DATA_DIR}/${id}.png.txt`
  } catch {
    // files may not exist
  }

  return true
}

