export type { CanvasEngine } from './canvas'
export type { CanvasState, ToolState, Layer, Stroke, Point, ToolKind, DrawingMetadata } from './types'
export { createCanvasEngine } from './canvas'
export { createHistoryManager } from './history'
export { createLayer, addStrokeToLayer, toggleLayerVisibility } from './layers'
export { TOOL_LABELS, isFreehandTool, isShapeTool } from './tools'
