type ServerOptions = {
  port?: number
  width?: number
  height?: number
}

export const createDrawingServer = (options: ServerOptions = {}) => {
  const { port = 3000, width = 800, height = 600 } = options
  const engine = createCanvasEngine(width, height)

  const generatePage = (): string => {
    const state = engine.getState()
    const toolState = engine.getToolState()
    const content = renderToHTML(state, toolState, engine.canUndo(), engine.canRedo())

    return `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Drawing Canvas</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { overflow: hidden; }
  </style>
</head>
<body>
  ${content}
  <script>
    const canvas = document.querySelector('[p-target="drawing-canvas"]');
    const ctx = canvas.getContext('2d');
    let drawing = false;
    let activeTool = 'brush';
    let color = '#000000';
    let brushSize = 3;
    let strokes = [];
    let currentStroke = null;
    let undoStack = [];
    let redoStack = [];
    let layers = [{ id: 'default', name: 'Background', visible: true, strokes: [], imageData: null }];
    let activeLayerIndex = 0;

    const saveState = () => {
      undoStack.push(JSON.parse(JSON.stringify(layers)));
      if (undoStack.length > 50) undoStack.shift();
      redoStack = [];
    };

    saveState();

    const getPos = (e) => {
      const rect = canvas.getBoundingClientRect();
      const touch = e.touches ? e.touches[0] : e;
      return {
        x: touch.clientX - rect.left,
        y: touch.clientY - rect.top,
      };
    };

    const redrawAll = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      ctx.fillStyle = '#ffffff';
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      layers.forEach((layer) => {
        if (!layer.visible) return;
        layer.strokes.forEach((stroke) => renderStroke(stroke));
      });
    };

    const renderStroke = (stroke) => {
      ctx.save();
      ctx.strokeStyle = stroke.color;
      ctx.lineWidth = stroke.width;
      ctx.lineCap = 'round';
      ctx.lineJoin = 'round';

      if (stroke.kind === 'eraser') {
        ctx.strokeStyle = '#ffffff';
      }

      if (stroke.kind === 'brush' || stroke.kind === 'eraser') {
        if (stroke.points.length < 2) { ctx.restore(); return; }
        ctx.beginPath();
        ctx.moveTo(stroke.points[0].x, stroke.points[0].y);
        for (let i = 1; i < stroke.points.length; i++) {
          ctx.lineTo(stroke.points[i].x, stroke.points[i].y);
        }
        ctx.stroke();
      } else if (stroke.kind === 'rectangle') {
        const w = stroke.end.x - stroke.start.x;
        const h = stroke.end.y - stroke.start.y;
        ctx.strokeRect(stroke.start.x, stroke.start.y, w, h);
      } else if (stroke.kind === 'circle') {
        const dx = stroke.end.x - stroke.start.x;
        const dy = stroke.end.y - stroke.start.y;
        const radius = Math.sqrt(dx * dx + dy * dy);
        ctx.beginPath();
        ctx.arc(stroke.start.x, stroke.start.y, radius, 0, Math.PI * 2);
        ctx.stroke();
      } else if (stroke.kind === 'line') {
        ctx.beginPath();
        ctx.moveTo(stroke.start.x, stroke.start.y);
        ctx.lineTo(stroke.end.x, stroke.end.y);
        ctx.stroke();
      }
      ctx.restore();
    };

    const updateLayerThumbnails = () => {
      layers.forEach((layer, i) => {
        const thumbEl = document.querySelector('[p-target="layer-thumb-' + layer.id + '"]');
        if (!thumbEl) return;
        // Create a mini canvas for thumbnail
        const tc = document.createElement('canvas');
        tc.width = 64; tc.height = 48;
        const tctx = tc.getContext('2d');
        tctx.fillStyle = '#ffffff';
        tctx.fillRect(0, 0, 64, 48);
        tctx.scale(64 / canvas.width, 48 / canvas.height);
        if (layer.visible) {
          layer.strokes.forEach((s) => {
            tctx.save();
            tctx.strokeStyle = s.kind === 'eraser' ? '#ffffff' : s.color;
            tctx.lineWidth = s.width;
            tctx.lineCap = 'round';
            tctx.lineJoin = 'round';
            if (s.kind === 'brush' || s.kind === 'eraser') {
              if (s.points.length >= 2) {
                tctx.beginPath();
                tctx.moveTo(s.points[0].x, s.points[0].y);
                for (let j = 1; j < s.points.length; j++) tctx.lineTo(s.points[j].x, s.points[j].y);
                tctx.stroke();
              }
            } else if (s.kind === 'rectangle') {
              tctx.strokeRect(s.start.x, s.start.y, s.end.x - s.start.x, s.end.y - s.start.y);
            } else if (s.kind === 'circle') {
              const dx = s.end.x - s.start.x, dy = s.end.y - s.start.y;
              tctx.beginPath();
              tctx.arc(s.start.x, s.start.y, Math.sqrt(dx*dx+dy*dy), 0, Math.PI*2);
              tctx.stroke();
            } else if (s.kind === 'line') {
              tctx.beginPath();
              tctx.moveTo(s.start.x, s.start.y);
              tctx.lineTo(s.end.x, s.end.y);
              tctx.stroke();
            }
            tctx.restore();
          });
        }
        thumbEl.style.backgroundImage = 'url(' + tc.toDataURL() + ')';
        thumbEl.style.backgroundSize = 'cover';
      });
    };

    // Pointer events
    canvas.addEventListener('pointerdown', (e) => {
      drawing = true;
      const pos = getPos(e);
      const isFreehand = activeTool === 'brush' || activeTool === 'eraser';
      currentStroke = isFreehand
        ? { kind: activeTool, points: [pos], color, width: brushSize }
        : { kind: activeTool, start: pos, end: pos, color, width: brushSize };
      canvas.setPointerCapture(e.pointerId);
    });

    canvas.addEventListener('pointermove', (e) => {
      if (!drawing || !currentStroke) return;
      const pos = getPos(e);
      if (currentStroke.kind === 'brush' || currentStroke.kind === 'eraser') {
        currentStroke.points.push(pos);
      } else {
        currentStroke.end = pos;
      }
      redrawAll();
      renderStroke(currentStroke);
    });

    const finishStroke = () => {
      if (!drawing || !currentStroke) return;
      drawing = false;
      layers[activeLayerIndex].strokes.push(currentStroke);
      currentStroke = null;
      saveState();
      redrawAll();
      updateLayerThumbnails();
    };

    canvas.addEventListener('pointerup', finishStroke);
    canvas.addEventListener('pointerleave', finishStroke);

    // Event delegation for toolbar buttons
    document.addEventListener('click', (e) => {
      const trigger = e.target.closest('[p-trigger]');
      if (!trigger) return;
      const action = trigger.getAttribute('p-trigger');

      if (action.startsWith('tool-select:')) {
        activeTool = action.split(':')[1];
        document.querySelectorAll('[p-trigger^="tool-select"]').forEach((btn) => {
          const t = btn.getAttribute('p-trigger').split(':')[1];
          btn.style.backgroundColor = t === activeTool ? '#e94560' : '#16213e';
          btn.style.borderColor = t === activeTool ? '#e94560' : '#0f3460';
          btn.style.color = '#ffffff';
        });
      }

      if (action === 'undo' && undoStack.length > 1) {
        redoStack.push(undoStack.pop());
        layers = JSON.parse(JSON.stringify(undoStack[undoStack.length - 1]));
        activeLayerIndex = Math.min(activeLayerIndex, layers.length - 1);
        redrawAll();
        updateLayerThumbnails();
      }

      if (action === 'redo' && redoStack.length > 0) {
        const state = redoStack.pop();
        undoStack.push(state);
        layers = JSON.parse(JSON.stringify(state));
        activeLayerIndex = Math.min(activeLayerIndex, layers.length - 1);
        redrawAll();
        updateLayerThumbnails();
      }

      if (action === 'clear-canvas') {
        layers.forEach((l) => l.strokes = []);
        saveState();
        redrawAll();
        updateLayerThumbnails();
      }

      if (action === 'save-png') {
        const link = document.createElement('a');
        link.download = 'drawing.png';
        link.href = canvas.toDataURL('image/png');
        link.click();
      }

      if (action === 'load-png') {
        const input = document.createElement('input');
        input.type = 'file';
        input.accept = 'image/png,image/jpeg,image/webp';
        input.onchange = () => {
          const file = input.files[0];
          if (!file) return;
          const reader = new FileReader();
          reader.onload = () => {
            const img = new Image();
            img.onload = () => {
              const newLayer = {
                id: 'layer-' + Date.now(),
                name: file.name,
                visible: true,
                strokes: [],
              };
              layers.push(newLayer);
              activeLayerIndex = layers.length - 1;
              // Draw image directly, treating it as a background
              ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
              // Capture as imageData for that layer
              newLayer.imageData = canvas.toDataURL();
              saveState();
              redrawAll();
              // Redraw the imported image on the new layer
              ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
              updateLayerThumbnails();
            };
            img.src = reader.result;
          };
          reader.readAsDataURL(file);
        };
        input.click();
      }

      if (action === 'add-layer') {
        const newId = 'layer-' + Date.now();
        layers.push({ id: newId, name: 'Layer ' + layers.length, visible: true, strokes: [] });
        activeLayerIndex = layers.length - 1;
        saveState();
        // Re-render sidebar (simplified: refresh page state)
        location.reload();
      }

      if (action.startsWith('select-layer:')) {
        const id = action.split(':')[1];
        const idx = layers.findIndex((l) => l.id === id);
        if (idx >= 0) {
          activeLayerIndex = idx;
          document.querySelectorAll('[p-trigger^="select-layer"]').forEach((el) => {
            el.style.borderColor = el.getAttribute('p-trigger') === action ? '#e94560' : 'transparent';
          });
        }
      }

      if (action.startsWith('toggle-layer:')) {
        const id = action.split(':')[1];
        const layer = layers.find((l) => l.id === id);
        if (layer) {
          layer.visible = !layer.visible;
          redrawAll();
          updateLayerThumbnails();
          const btn = trigger;
          btn.textContent = layer.visible ? '\\u{1F441}' : '\\u{1F441}\\u200D\\u{1F5E8}';
        }
      }

      if (action.startsWith('delete-layer:')) {
        const id = action.split(':')[1];
        if (layers.length <= 1) return;
        layers = layers.filter((l) => l.id !== id);
        activeLayerIndex = Math.min(activeLayerIndex, layers.length - 1);
        saveState();
        redrawAll();
        location.reload();
      }

      if (action === 'save-drawing') {
        const data = JSON.stringify({ layers, activeLayerIndex });
        const name = prompt('Drawing name:', 'My Drawing');
        if (!name) return;
        fetch('/api/save', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            id: 'drawing-' + Date.now(),
            name,
            canvasJson: data,
            pngDataUrl: canvas.toDataURL('image/png'),
          }),
        }).then(() => alert('Drawing saved!'));
      }

      if (action === 'load-drawing') {
        fetch('/api/list').then(r => r.json()).then((drawings) => {
          if (drawings.length === 0) { alert('No saved drawings.'); return; }
          const choice = prompt('Enter drawing name to load:\\n' + drawings.map((d) => d.name).join('\\n'));
          const match = drawings.find((d) => d.name === choice);
          if (!match) return;
          fetch('/api/load/' + match.id).then(r => r.json()).then((data) => {
            layers = data.layers || [];
            activeLayerIndex = data.activeLayerIndex || 0;
            saveState();
            redrawAll();
            updateLayerThumbnails();
          });
        });
      }
    });

    // Color & brush size inputs
    document.addEventListener('input', (e) => {
      const target = e.target.closest('[p-trigger]');
      if (!target) return;
      const action = target.getAttribute('p-trigger');

      if (action === 'color-change') {
        color = target.value;
      }
      if (action === 'brush-size-change') {
        brushSize = parseInt(target.value, 10);
        const label = document.querySelector('[p-target="brush-size-label"]');
        if (label) label.textContent = brushSize + 'px';
      }
    });

    // Keyboard shortcuts
    document.addEventListener('keydown', (e) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'z') {
        e.preventDefault();
        if (e.shiftKey) {
          document.querySelector('[p-trigger="redo"]')?.click();
        } else {
          document.querySelector('[p-trigger="undo"]')?.click();
        }
      }
    });

    // Initial render
    ctx.fillStyle = '#ffffff';
    ctx.fillRect(0, 0, canvas.width, canvas.height);
    updateLayerThumbnails();
  </script>
</body>
</html>`
  }

  const handleApiRequest = async (req: Request): Promise<Response> => {
    const url = new URL(req.url)

    if (url.pathname === '/api/save' && req.method === 'POST') {
      const body = await req.json()
      const metadata = await saveDrawing(body.id, body.name, body.canvasJson, body.pngDataUrl)
      return Response.json(metadata)
    }

    if (url.pathname === '/api/list') {
      const drawings = await listDrawings()
      return Response.json(drawings)
    }

    if (url.pathname.startsWith('/api/load/')) {
      const id = url.pathname.replace('/api/load/', '')
      const data = await loadDrawing(id)
      if (!data) return new Response('Not found', { status: 404 })
      return new Response(data, { headers: { 'Content-Type': 'application/json' } })
    }

    if (url.pathname.startsWith('/api/png/')) {
      const id = url.pathname.replace('/api/png/', '')
      const png = await loadDrawingPng(id)
      if (!png) return new Response('Not found', { status: 404 })
      return new Response(png, { headers: { 'Content-Type': 'text/plain' } })
    }

    if (url.pathname.startsWith('/api/delete/') && req.method === 'DELETE') {
      const id = url.pathname.replace('/api/delete/', '')
      const deleted = await deleteDrawing(id)
      return Response.json({ deleted })
    }

    return new Response('Not found', { status: 404 })
  }

  const server = Bun.serve({
    port,
    fetch: async (req) => {
      const url = new URL(req.url)

      if (url.pathname.startsWith('/api/')) {
        return handleApiRequest(req)
      }

      return new Response(generatePage(), {
        headers: { 'Content-Type': 'text/html' },
      })
    },
  })

  console.log(`Drawing Canvas running at http://localhost:${server.port}`)

  return { server, engine }
}

