import type { Layer, Stroke } from './types'

let layerCounter = 0

const generateId = (): string => `layer_${Date.now()}_${++layerCounter}`

export const createLayer = (name?: string): Layer => ({
  id: generateId(),
  name: name ?? `Layer ${layerCounter}`,
  visible: true,
  strokes: [],
  thumbnail: '',
})

export const addStrokeToLayer = (layer: Layer, stroke: Stroke): Layer => ({
  ...layer,
  strokes: [...layer.strokes, stroke],
})

export const removeLastStroke = (layer: Layer): Layer => ({
  ...layer,
  strokes: layer.strokes.slice(0, -1),
})

export const toggleLayerVisibility = (layer: Layer): Layer => ({
  ...layer,
  visible: !layer.visible,
})

export const clearLayer = (layer: Layer): Layer => ({
  ...layer,
  strokes: [],
  thumbnail: '',
})

export const cloneLayers = (layers: Layer[]): Layer[] =>
  layers.map((l) => ({
    ...l,
    strokes: l.strokes.map((s) => ({
      ...s,
      points: [...s.points],
      startPoint: { ...s.startPoint },
      endPoint: { ...s.endPoint },
    })),
  }))

import type { CanvasState, HistoryEntry } from './types'
import { cloneLayers } from './layers'

const MAX_HISTORY = 50

export const pushHistory = (state: CanvasState, action: string): CanvasState => {
  const entry: HistoryEntry = {
    action,
    layerSnapshots: cloneLayers(state.layers),
  }

  const truncatedHistory = state.history.slice(0, state.historyIndex + 1)
  const newHistory = [...truncatedHistory, entry].slice(-MAX_HISTORY)

  return {
    ...state,
    history: newHistory,
    historyIndex: newHistory.length - 1,
  }
}

export const undo = (state: CanvasState): CanvasState => {
  if (state.historyIndex <= 0) return state

  const newIndex = state.historyIndex - 1
  const entry = state.history[newIndex]

  return {
    ...state,
    layers: cloneLayers(entry.layerSnapshots),
    historyIndex: newIndex,
  }
}

export const redo = (state: CanvasState): CanvasState => {
  if (state.historyIndex >= state.history.length - 1) return state

  const newIndex = state.historyIndex + 1
  const entry = state.history[newIndex]

  return {
    ...state,
    layers: cloneLayers(entry.layerSnapshots),
    historyIndex: newIndex,
  }
}

export const canUndo = (state: CanvasState): boolean => state.historyIndex > 0

export const canRedo = (state: CanvasState): boolean =>
  state.historyIndex < state.history.length - 1

import type { CanvasState, Layer, Stroke, Point } from './types'

export const renderStroke = (ctx: CanvasRenderingContext2D, stroke: Stroke): void => {
  ctx.save()

  if (stroke.tool === 'eraser') {
    ctx.globalCompositeOperation = 'destination-out'
  } else {
    ctx.globalCompositeOperation = 'source-over'
  }

  ctx.strokeStyle = stroke.tool === 'eraser' ? 'rgba(0,0,0,1)' : stroke.color
  ctx.lineWidth = stroke.size
  ctx.lineCap = 'round'
  ctx.lineJoin = 'round'

  switch (stroke.tool) {
    case 'pen':
    case 'eraser':
      renderFreehand(ctx, stroke.points)
      break
    case 'rectangle':
      renderRectangle(ctx, stroke.startPoint, stroke.endPoint, stroke.color, stroke.size)
      break
    case 'circle':
      renderCircle(ctx, stroke.startPoint, stroke.endPoint, stroke.color, stroke.size)
      break
    case 'line':
      renderLine(ctx, stroke.startPoint, stroke.endPoint)
      break
  }

  ctx.restore()
}

const renderFreehand = (ctx: CanvasRenderingContext2D, points: Point[]): void => {
  if (points.length < 2) {
    if (points.length === 1) {
      ctx.beginPath()
      ctx.arc(points[0].x, points[0].y, ctx.lineWidth / 2, 0, Math.PI * 2)
      ctx.fill()
    }
    return
  }

  ctx.beginPath()
  ctx.moveTo(points[0].x, points[0].y)

  for (let i = 1; i < points.length - 1; i++) {
    const midX = (points[i].x + points[i + 1].x) / 2
    const midY = (points[i].y + points[i + 1].y) / 2
    ctx.quadraticCurveTo(points[i].x, points[i].y, midX, midY)
  }

  const last = points[points.length - 1]
  ctx.lineTo(last.x, last.y)
  ctx.stroke()
}

const renderRectangle = (
  ctx: CanvasRenderingContext2D,
  start: Point,
  end: Point,
  color: string,
  size: number,
): void => {
  ctx.strokeStyle = color
  ctx.lineWidth = size
  const x = Math.min(start.x, end.x)
  const y = Math.min(start.y, end.y)
  const w = Math.abs(end.x - start.x)
  const h = Math.abs(end.y - start.y)
  ctx.strokeRect(x, y, w, h)
}

const renderCircle = (
  ctx: CanvasRenderingContext2D,
  start: Point,
  end: Point,
  color: string,
  size: number,
): void => {
  ctx.strokeStyle = color
  ctx.lineWidth = size
  const cx = (start.x + end.x) / 2
  const cy = (start.y + end.y) / 2
  const rx = Math.abs(end.x - start.x) / 2
  const ry = Math.abs(end.y - start.y) / 2
  ctx.beginPath()
  ctx.ellipse(cx, cy, rx, ry, 0, 0, Math.PI * 2)
  ctx.stroke()
}

const renderLine = (ctx: CanvasRenderingContext2D, start: Point, end: Point): void => {
  ctx.beginPath()
  ctx.moveTo(start.x, start.y)
  ctx.lineTo(end.x, end.y)
  ctx.stroke()
}

export const renderLayer = (ctx: CanvasRenderingContext2D, layer: Layer): void => {
  if (!layer.visible) return
  for (const stroke of layer.strokes) {
    renderStroke(ctx, stroke)
  }
}

export const renderAllLayers = (
  ctx: CanvasRenderingContext2D,
  state: CanvasState,
): void => {
  ctx.clearRect(0, 0, state.canvasWidth, state.canvasHeight)

  for (const layer of state.layers) {
    renderLayer(ctx, layer)
  }
}

export const generateThumbnail = (
  layer: Layer,
  canvasWidth: number,
  canvasHeight: number,
  thumbWidth = 60,
  thumbHeight = 40,
): string => {
  if (typeof document === 'undefined') return ''

  const offscreen = document.createElement('canvas')
  offscreen.width = thumbWidth
  offscreen.height = thumbHeight
  const ctx = offscreen.getContext('2d')
  if (!ctx) return ''

  ctx.fillStyle = '#ffffff'
  ctx.fillRect(0, 0, thumbWidth, thumbHeight)

  ctx.scale(thumbWidth / canvasWidth, thumbHeight / canvasHeight)
  renderLayer(ctx, { ...layer, visible: true })

  return offscreen.toDataURL('image/png')
}

import type { CanvasState, DrawingFile } from './types'
import { cloneLayers } from './layers'

const DATA_DIR = './data'

export const saveDrawingState = async (state: CanvasState, filename: string): Promise<void> => {
  const drawing: DrawingFile = {
    version: '1.0.0',
    state: {
      ...state,
      layers: cloneLayers(state.layers),
      history: [],
      historyIndex: -1,
    },
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  }

  const filePath = `${DATA_DIR}/${filename}.json`
  await Bun.write(filePath, JSON.stringify(drawing, null, 2))
}

export const loadDrawingState = async (filename: string): Promise<CanvasState | null> => {
  const filePath = `${DATA_DIR}/${filename}.json`
  const file = Bun.file(filePath)

  if (!(await file.exists())) return null

  const text = await file.text()
  const drawing: DrawingFile = JSON.parse(text)

  return drawing.state
}

export const listSavedDrawings = async (): Promise<string[]> => {
  const glob = new Bun.Glob('*.json')
  const files: string[] = []

  for await (const path of glob.scan({ cwd: DATA_DIR })) {
    files.push(path.replace('.json', ''))
  }

  return files
}

export const exportCanvasToPng = (canvas: HTMLCanvasElement): string => {
  return canvas.toDataURL('image/png')
}

export const downloadPng = (dataUrl: string, filename: string): void => {
  const link = document.createElement('a')
  link.download = `${filename}.png`
  link.href = dataUrl
  link.click()
}

export const loadPngToCanvas = (
  file: File,
  ctx: CanvasRenderingContext2D,
  width: number,
  height: number,
): Promise<void> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader()
    reader.onload = (e) => {
      const img = new Image()
      img.onload = () => {
        ctx.clearRect(0, 0, width, height)
        ctx.drawImage(img, 0, 0, width, height)
        resolve()
      }
      img.onerror = reject
      img.src = e.target?.result as string
    }
    reader.onerror = reject
    reader.readAsDataURL(file)
  })
}

import type { CanvasState, Point, Stroke, ToolKind } from './types'
import { createLayer, addStrokeToLayer, cloneLayers } from './layers'
import { pushHistory, undo, redo } from './history'
import { renderAllLayers, generateThumbnail } from './renderer'

let strokeCounter = 0
const generateStrokeId = (): string => `stroke_${Date.now()}_${++strokeCounter}`

export const createInitialState = (width = 800, height = 600): CanvasState => {
  const baseLayer = createLayer('Background')
  const state: CanvasState = {
    layers: [baseLayer],
    activeLayerId: baseLayer.id,
    history: [],
    historyIndex: -1,
    currentTool: 'pen',
    currentColor: '#000000',
    brushSize: 3,
    canvasWidth: width,
    canvasHeight: height,
  }

  return pushHistory(state, 'initial')
}

export type CanvasEngine = {
  getState: () => CanvasState
  setTool: (tool: ToolKind) => void
  setColor: (color: string) => void
  setBrushSize: (size: number) => void
  startStroke: (point: Point) => void
  continueStroke: (point: Point) => void
  endStroke: (point: Point) => void
  undo: () => void
  redo: () => void
  clear: () => void
  addLayer: () => void
  removeLayer: (layerId: string) => void
  setActiveLayer: (layerId: string) => void
  toggleLayerVisibility: (layerId: string) => void
  render: () => void
  getCanvas: () => HTMLCanvasElement | null
  setCanvas: (canvas: HTMLCanvasElement) => void
  updateThumbnails: () => void
  onStateChange: (cb: (state: CanvasState) => void) => void
}

export const createCanvasEngine = (
  initialWidth = 800,
  initialHeight = 600,
): CanvasEngine => {
  let state = createInitialState(initialWidth, initialHeight)
  let canvas: HTMLCanvasElement | null = null
  let ctx: CanvasRenderingContext2D | null = null
  let currentStroke: Stroke | null = null
  let changeListeners: Array<(state: CanvasState) => void> = []

  const notifyChange = (): void => {
    for (const cb of changeListeners) {
      cb(state)
    }
  }

  const getActiveLayer = () =>
    state.layers.find((l) => l.id === state.activeLayerId) ?? state.layers[0]

  const updateLayer = (layerId: string, updater: (l: typeof state.layers[0]) => typeof state.layers[0]): void => {
    state = {
      ...state,
      layers: state.layers.map((l) => (l.id === layerId ? updater(l) : l)),
    }
  }

  const engine: CanvasEngine = {
    getState: () => state,

    setCanvas: (c: HTMLCanvasElement) => {
      canvas = c
      ctx = c.getContext('2d')
    },

    getCanvas: () => canvas,

    setTool: (tool: ToolKind) => {
      state = { ...state, currentTool: tool }
      notifyChange()
    },

    setColor: (color: string) => {
      state = { ...state, currentColor: color }
      notifyChange()
    },

    setBrushSize: (size: number) => {
      state = { ...state, brushSize: Math.max(1, Math.min(100, size)) }
      notifyChange()
    },

    startStroke: (point: Point) => {
      currentStroke = {
        id: generateStrokeId(),
        tool: state.currentTool,
        points: [point],
        color: state.currentColor,
        size: state.brushSize,
        startPoint: point,
        endPoint: point,
      }
    },

    continueStroke: (point: Point) => {
      if (!currentStroke || !ctx) return

      currentStroke.points.push(point)
      currentStroke.endPoint = point

      renderAllLayers(ctx, state)

      // Render the in-progress stroke
      ctx.save()
      if (currentStroke.tool === 'eraser') {
        ctx.globalCompositeOperation = 'destination-out'
        ctx.strokeStyle = 'rgba(0,0,0,1)'
      } else {
        ctx.globalCompositeOperation = 'source-over'
        ctx.strokeStyle = currentStroke.color
      }
      ctx.lineWidth = currentStroke.size
      ctx.lineCap = 'round'
      ctx.lineJoin = 'round'

      const { tool, points, startPoint, endPoint } = currentStroke

      if (tool === 'pen' || tool === 'eraser') {
        if (points.length > 1) {
          ctx.beginPath()
          ctx.moveTo(points[0].x, points[0].y)
          for (let i = 1; i < points.length - 1; i++) {
            const midX = (points[i].x + points[i + 1].x) / 2
            const midY = (points[i].y + points[i + 1].y) / 2
            ctx.quadraticCurveTo(points[i].x, points[i].y, midX, midY)
          }
          ctx.lineTo(points[points.length - 1].x, points[points.length - 1].y)
          ctx.stroke()
        }
      } else if (tool === 'rectangle') {
        const x = Math.min(startPoint.x, endPoint.x)
        const y = Math.min(startPoint.y, endPoint.y)
        const w = Math.abs(endPoint.x - startPoint.x)
        const h = Math.abs(endPoint.y - startPoint.y)
        ctx.strokeRect(x, y, w, h)
      } else if (tool === 'circle') {
        const cx = (startPoint.x + endPoint.x) / 2
        const cy = (startPoint.y + endPoint.y) / 2
        const rx = Math.abs(endPoint.x - startPoint.x) / 2
        const ry = Math.abs(endPoint.y - startPoint.y) / 2
        ctx.beginPath()
        ctx.ellipse(cx, cy, rx, ry, 0, 0, Math.PI * 2)
        ctx.stroke()
      } else if (tool === 'line') {
        ctx.beginPath()
        ctx.moveTo(startPoint.x, startPoint.y)
        ctx.lineTo(endPoint.x, endPoint.y)
        ctx.stroke()
      }

      ctx.restore()
    },

    endStroke: (_point: Point) => {
      if (!currentStroke) return

      state = pushHistory(state, `draw:${currentStroke.tool}`)
      const activeLayer = getActiveLayer()
      updateLayer(activeLayer.id, (l) => addStrokeToLayer(l, currentStroke!))

      currentStroke = null
      engine.render()
      engine.updateThumbnails()
      notifyChange()
    },

    undo: () => {
      state = undo(state)
      engine.render()
      engine.updateThumbnails()
      notifyChange()
    },

    redo: () => {
      state = redo(state)
      engine.render()
      engine.updateThumbnails()
      notifyChange()
    },

    clear: () => {
      state = pushHistory(state, 'clear')
      state = {
        ...state,
        layers: state.layers.map((l) => ({ ...l, strokes: [], thumbnail: '' })),
      }
      engine.render()
      engine.updateThumbnails()
      notifyChange()
    },

    addLayer: () => {
      state = pushHistory(state, 'add-layer')
      const newLayer = createLayer()
      state = {
        ...state,
        layers: [...state.layers, newLayer],
        activeLayerId: newLayer.id,
      }
      engine.updateThumbnails()
      notifyChange()
    },

    removeLayer: (layerId: string) => {
      if (state.layers.length <= 1) return

      state = pushHistory(state, 'remove-layer')
      const filtered = state.layers.filter((l) => l.id !== layerId)
      state = {
        ...state,
        layers: filtered,
        activeLayerId:
          state.activeLayerId === layerId ? filtered[0].id : state.activeLayerId,
      }
      engine.render()
      engine.updateThumbnails()
      notifyChange()
    },

    setActiveLayer: (layerId: string) => {
      state = { ...state, activeLayerId: layerId }
      notifyChange()
    },

    toggleLayerVisibility: (layerId: string) => {
      updateLayer(layerId, (l) => ({ ...l, visible: !l.visible }))
      engine.render()
      engine.updateThumbnails()
      notifyChange()
    },

    render: () => {
      if (!ctx) return
      renderAllLayers(ctx, state)
    },

    updateThumbnails: () => {
      state = {
        ...state,
        layers: state.layers.map((l) => ({
          ...l,
          thumbnail: generateThumbnail(l, state.canvasWidth, state.canvasHeight),
        })),
      }
    },

    onStateChange: (cb: (state: CanvasState) => void) => {
      changeListeners.push(cb)
    },
  }

  return engine
}

