export const renderLayersPanel = (state: CanvasState) => {
  const layerItems = [...state.layers].reverse().map((layer) => {
    const isActive = layer.id === state.activeLayerId
    const itemStyle = isActive
      ? { ...styles.layerItem, ...styles.layerItemActive }
      : styles.layerItem

    const thumbnail = layer.thumbnail
      ? h('img', { src: layer.thumbnail, style: styles.layerThumbnail, alt: layer.name })
