import { createCanvasEngine } from './canvas-engine'
import type { ToolKind, Point } from './types'
import { exportCanvasToPng, downloadPng, loadPngToCanvas } from './storage'

const engine = createCanvasEngine(800, 600)

const init = (): void => {
  const canvasEl = document.querySelector<HTMLCanvasElement>('[p-target="drawing-canvas"]')
  if (!canvasEl) return

  engine.setCanvas(canvasEl)
  engine.render()

  const getCanvasPoint = (e: MouseEvent): Point => {
    const rect = canvasEl.getBoundingClientRect()
    return {
      x: e.clientX - rect.left,
      y: e.clientY - rect.top,
    }
  }

  let isDrawing = false

  canvasEl.addEventListener('mousedown', (e) => {
    isDrawing = true
    engine.startStroke(getCanvasPoint(e))
  })

  canvasEl.addEventListener('mousemove', (e) => {
    if (!isDrawing) return
    engine.continueStroke(getCanvasPoint(e))
  })

  canvasEl.addEventListener('mouseup', (e) => {
    if (!isDrawing) return
    isDrawing = false
    engine.endStroke(getCanvasPoint(e))
  })

  canvasEl.addEventListener('mouseleave', (e) => {
    if (!isDrawing) return
    isDrawing = false
    engine.endStroke(getCanvasPoint(e))
  })

  // Touch support
  canvasEl.addEventListener('touchstart', (e) => {
    e.preventDefault()
    const touch = e.touches[0]
    const rect = canvasEl.getBoundingClientRect()
    isDrawing = true
    engine.startStroke({ x: touch.clientX - rect.left, y: touch.clientY - rect.top })
  }, { passive: false })

  canvasEl.addEventListener('touchmove', (e) => {
    e.preventDefault()
    if (!isDrawing) return
    const touch = e.touches[0]
    const rect = canvasEl.getBoundingClientRect()
    engine.continueStroke({ x: touch.clientX - rect.left, y: touch.clientY - rect.top })
  }, { passive: false })

  canvasEl.addEventListener('touchend', (e) => {
    e.preventDefault()
    if (!isDrawing) return
    isDrawing = false
    const rect = canvasEl.getBoundingClientRect()
    const touch = e.changedTouches[0]
    engine.endStroke({ x: touch.clientX - rect.left, y: touch.clientY - rect.top })
  }, { passive: false })

  // Delegated click handler for toolbar and layer panel interactions
  document.addEventListener('click', (e) => {
    const target = e.target as HTMLElement
    const trigger = target.getAttribute('p-trigger')
    if (!trigger) return

    if (trigger.startsWith('tool:')) {
      const tool = trigger.replace('tool:', '') as ToolKind
      engine.setTool(tool)
      updateToolbarUI()
    } else if (trigger === 'color:change') {
      const input = target as HTMLInputElement
      engine.setColor(input.value)
    } else if (trigger === 'brush:size') {
      const input = target as HTMLInputElement
      engine.setBrushSize(Number(input.value))
      updateBrushLabel()
    } else if (trigger === 'action:undo') {
      engine.undo()
      updateLayersUI()
    } else if (trigger === 'action:redo') {
      engine.redo()
      updateLayersUI()
    } else if (trigger === 'action:clear') {
      engine.clear()
      updateLayersUI()
    } else if (trigger === 'action:save-png') {
      const canvas = engine.getCanvas()
      if (canvas) {
        const dataUrl = exportCanvasToPng(canvas)
        downloadPng(dataUrl, `drawing_${Date.now()}`)
      }
    } else if (trigger === 'action:load-png') {
      const fileInput = document.querySelector<HTMLInputElement>('[p-target="file-input"]')
      fileInput?.click()
    } else if (trigger.startsWith('layer:select:')) {
      const layerId = trigger.replace('layer:select:', '')
      engine.setActiveLayer(layerId)
      updateLayersUI()
    } else if (trigger.startsWith('layer:visibility:')) {
      const layerId = trigger.replace('layer:visibility:', '')
      engine.toggleLayerVisibility(layerId)
      updateLayersUI()
    } else if (trigger === 'layer:add') {
      engine.addLayer()
      updateLayersUI()
    }
  })

  // Listen for input events (range slider, color picker)
  document.addEventListener('input', (e) => {
    const target = e.target as HTMLInputElement
    const trigger = target.getAttribute('p-trigger')

    if (trigger === 'color:change') {
      engine.setColor(target.value)
    } else if (trigger === 'brush:size') {
      engine.setBrushSize(Number(target.value))
      updateBrushLabel()
    }
  })

  // File input change
  document.addEventListener('change', (e) => {
    const target = e.target as HTMLInputElement
    const trigger = target.getAttribute('p-trigger')

    if (trigger === 'file:selected' && target.files?.[0]) {
      const canvas = engine.getCanvas()
      if (!canvas) return
      const ctx = canvas.getContext('2d')
      if (!ctx) return
      loadPngToCanvas(target.files[0], ctx, engine.getState().canvasWidth, engine.getState().canvasHeight)
    }
  })

  // Keyboard shortcuts
  document.addEventListener('keydown', (e) => {
    if ((e.metaKey || e.ctrlKey) && e.key === 'z') {
      e.preventDefault()
      if (e.shiftKey) {
        engine.redo()
      } else {
        engine.undo()
      }
      updateLayersUI()
    }
  })
}

const updateToolbarUI = (): void => {
  const state = engine.getState()
  const buttons = document.querySelectorAll<HTMLButtonElement>('[p-trigger^="tool:"]')

  buttons.forEach((btn) => {
    const trigger = btn.getAttribute('p-trigger') ?? ''
    const tool = trigger.replace('tool:', '')
    const isActive = tool === state.currentTool

    btn.style.backgroundColor = isActive ? '#094771' : '#2d2d2d'
    btn.style.borderColor = isActive ? '#007acc' : '#3c3c3c'
    btn.style.color = isActive ? '#fff' : '#ccc'
  })
}

const updateBrushLabel = (): void => {
  const state = engine.getState()
  const labels = document.querySelectorAll('div')
  for (const label of labels) {
    if (label.textContent?.endsWith('px') && label.style.fontSize === '12px') {
      label.textContent = `${state.brushSize}px`
      break
    }
  }
}

const updateLayersUI = (): void => {
  const state = engine.getState()
  const panel = document.querySelector<HTMLElement>('[p-target="layers-panel"]')
  if (!panel) return

  // Update layer items
  const layerItems = panel.querySelectorAll<HTMLElement>('[p-trigger^="layer:select:"]')
  layerItems.forEach((item) => {
    const trigger = item.getAttribute('p-trigger') ?? ''
    const layerId = trigger.replace('layer:select:', '')
    const isActive = layerId === state.activeLayerId

    item.style.borderColor = isActive ? '#007acc' : '#3c3c3c'
    item.style.backgroundColor = isActive ? '#094771' : '#2d2d2d'

    // Update thumbnail
    const layer = state.layers.find((l) => l.id === layerId)
    if (layer) {
      const img = item.querySelector('img')
      if (img && layer.thumbnail) {
        img.src = layer.thumbnail
      }

      // Update visibility button
      const visBtn = item.querySelector<HTMLButtonElement>(`[p-trigger="layer:visibility:${layerId}"]`)
      if (visBtn) {
        visBtn.textContent = layer.visible ? 'V' : 'H'
        visBtn.title = layer.visible ? 'Hide' : 'Show'
      }
    }
  })
}

document.addEventListener('DOMContentLoaded', init)

import { renderPage } from './ui'
import { createInitialState } from './canvas-engine'
import { saveDrawingState, loadDrawingState, listSavedDrawings } from './storage'

const PORT = 3000

const state = createInitialState(800, 600)

const server = Bun.serve({
  port: PORT,
  fetch: async (req) => {
    const url = new URL(req.url)

    if (url.pathname === '/' || url.pathname === '/index.html') {
      const html = renderPage(state)
      return new Response(html, {
        headers: { 'Content-Type': 'text/html' },
      })
    }

    if (url.pathname === '/client.ts') {
      const file = Bun.file('./client.ts')
      const code = await file.text()
      return new Response(code, {
        headers: { 'Content-Type': 'application/typescript' },
      })
    }

    // API: save drawing state
    if (url.pathname === '/api/save' && req.method === 'POST') {
      const body = await req.json() as { name: string }
      await saveDrawingState(state, body.name)
      return Response.json({ ok: true })
    }

    // API: load drawing state
    if (url.pathname === '/api/load' && req.method === 'GET') {
      const name = url.searchParams.get('name')
      if (!name) return Response.json({ error: 'name required' }, { status: 400 })
      const loaded = await loadDrawingState(name)
      if (!loaded) return Response.json({ error: 'not found' }, { status: 404 })
      return Response.json(loaded)
    }

    // API: list saved drawings
    if (url.pathname === '/api/drawings' && req.method === 'GET') {
      const drawings = await listSavedDrawings()
      return Response.json({ drawings })
    }

    return new Response('Not Found', { status: 404 })
  },
})

