// Physics engine for Newton's laws simulations

export type Vec2 = { x: number; y: number }

export type SimState = {
  time: number
  position: Vec2
  velocity: Vec2
  acceleration: Vec2
}

// --- Pendulum ---

export type PendulumParams = {
  length: number    // meters
  gravity: number   // m/s²
  theta0: number    // initial angle (rad)
}

export type PendulumState = {
  time: number
  theta: number       // angular position (rad)
  omega: number       // angular velocity (rad/s)
  alpha: number       // angular acceleration (rad/s²)
  bobX: number        // cartesian x of bob
  bobY: number        // cartesian y of bob
}

const DEFAULT_PENDULUM: PendulumParams = {
  length: 2.0,
  gravity: 9.81,
  theta0: Math.PI / 4,
}

export const createPendulumState = (params: Partial<PendulumParams> = {}): PendulumState => {
  const p = { ...DEFAULT_PENDULUM, ...params }
  return {
    time: 0,
    theta: p.theta0,
    omega: 0,
    alpha: -(p.gravity / p.length) * Math.sin(p.theta0),
    bobX: p.length * Math.sin(p.theta0),
    bobY: p.length * Math.cos(p.theta0),
  }
}

export const stepPendulum = (
  state: PendulumState,
  params: PendulumParams,
  dt: number,
): PendulumState => {
  const { theta, omega } = state
  const { length, gravity } = params

  // Runge-Kutta 4th order for accuracy
  const f = (th: number, om: number): [number, number] => [
    om,
    -(gravity / length) * Math.sin(th),
  ]

  const [k1a, k1b] = f(theta, omega)
  const [k2a, k2b] = f(theta + 0.5 * dt * k1a, omega + 0.5 * dt * k1b)
  const [k3a, k3b] = f(theta + 0.5 * dt * k2a, omega + 0.5 * dt * k2b)
  const [k4a, k4b] = f(theta + dt * k3a, omega + dt * k3b)

  const newTheta = theta + (dt / 6) * (k1a + 2 * k2a + 2 * k3a + k4a)
  const newOmega = omega + (dt / 6) * (k1b + 2 * k2b + 2 * k3b + k4b)
  const newAlpha = -(gravity / length) * Math.sin(newTheta)

  return {
    time: state.time + dt,
    theta: newTheta,
    omega: newOmega,
    alpha: newAlpha,
    bobX: length * Math.sin(newTheta),
    bobY: length * Math.cos(newTheta),
  }
}

// --- Projectile Motion ---

export type ProjectileParams = {
  angle: number       // launch angle (degrees)
  velocity: number    // initial velocity (m/s)
  gravity: number     // m/s²
}

export type ProjectileState = {
  time: number
  x: number
  y: number
  vx: number
  vy: number
  ax: number
  ay: number
  trail: Vec2[]
  landed: boolean
}

const DEFAULT_PROJECTILE: ProjectileParams = {
  angle: 45,
  velocity: 20,
  gravity: 9.81,
}

export const createProjectileState = (params: Partial<ProjectileParams> = {}): ProjectileState => {
  const p = { ...DEFAULT_PROJECTILE, ...params }
  const rad = (p.angle * Math.PI) / 180
  return {
    time: 0,
    x: 0,
    y: 0,
    vx: p.velocity * Math.cos(rad),
    vy: p.velocity * Math.sin(rad),
    ax: 0,
    ay: -p.gravity,
    trail: [{ x: 0, y: 0 }],
    landed: false,
  }
}

export const stepProjectile = (
  state: ProjectileState,
  params: ProjectileParams,
  dt: number,
): ProjectileState => {
  if (state.landed) return state

  const { x, y, vx, vy, trail } = state
  const { gravity } = params

  const newVx = vx
  const newVy = vy - gravity * dt
  const newX = x + vx * dt + 0.5 * 0 * dt * dt
  const newY = y + vy * dt - 0.5 * gravity * dt * dt

  const landed = newY <= 0 && state.time > 0

  const clampedY = landed ? 0 : newY
  const clampedVy = landed ? 0 : newVy
  const clampedVx = landed ? 0 : newVx

  const newTrail = [...trail, { x: newX, y: clampedY }]
  // Keep trail manageable
  const trimmedTrail = newTrail.length > 500 ? newTrail.slice(-500) : newTrail

  return {
    time: state.time + dt,
    x: newX,
    y: clampedY,
    vx: clampedVx,
    vy: clampedVy,
    ax: 0,
    ay: landed ? 0 : -gravity,
    trail: trimmedTrail,
    landed,
  }
}

// --- Spring-Mass System ---

export type SpringParams = {
  k: number         // spring constant (N/m)
  mass: number      // mass (kg)
  x0: number        // initial displacement (m)
}

export type SpringState = {
  time: number
  x: number         // displacement from equilibrium
  v: number         // velocity
  a: number         // acceleration
  trail: Vec2[]     // time-displacement trace
}

const DEFAULT_SPRING: SpringParams = {
  k: 10,
  mass: 1,
  x0: 1.5,
}

export const createSpringState = (params: Partial<SpringParams> = {}): SpringState => {
  const p = { ...DEFAULT_SPRING, ...params }
  return {
    time: 0,
    x: p.x0,
    v: 0,
    a: -(p.k / p.mass) * p.x0,
    trail: [{ x: 0, y: p.x0 }],
  }
}

export const stepSpring = (
  state: SpringState,
  params: SpringParams,
  dt: number,
): SpringState => {
  const { x, v } = state
  const { k, mass } = params

  // RK4
  const f = (pos: number, vel: number): [number, number] => [
    vel,
    -(k / mass) * pos,
  ]

  const [k1a, k1b] = f(x, v)
  const [k2a, k2b] = f(x + 0.5 * dt * k1a, v + 0.5 * dt * k1b)
  const [k3a, k3b] = f(x + 0.5 * dt * k2a, v + 0.5 * dt * k2b)
  const [k4a, k4b] = f(x + dt * k3a, v + dt * k3b)

  const newX = x + (dt / 6) * (k1a + 2 * k2a + 2 * k3a + k4a)
  const newV = v + (dt / 6) * (k1b + 2 * k2b + 2 * k3b + k4b)
  const newA = -(k / mass) * newX

  const newTime = state.time + dt
  const newTrail = [...state.trail, { x: newTime, y: newX }]
  const trimmedTrail = newTrail.length > 500 ? newTrail.slice(-500) : newTrail

  return {
    time: newTime,
    x: newX,
    v: newV,
    a: newA,
    trail: trimmedTrail,
  }
}

// --- Utility ---

export const getDefaultPendulumParams = (): PendulumParams => ({ ...DEFAULT_PENDULUM })
export const getDefaultProjectileParams = (): ProjectileParams => ({ ...DEFAULT_PROJECTILE })
export const getDefaultSpringParams = (): SpringParams => ({ ...DEFAULT_SPRING })

export const formatNum = (n: number, decimals = 3): string => n.toFixed(decimals)

