import {
  type PendulumParams,
  type PendulumState,
  type ProjectileParams,
  type ProjectileState,
  type SpringParams,
  type SpringState,
  createPendulumState,
  createProjectileState,
  createSpringState,
  stepPendulum,
  stepProjectile,
  stepSpring,
  getDefaultPendulumParams,
  getDefaultProjectileParams,
  getDefaultSpringParams,
} from './physics.ts'
import {
  type SimTab,
  type SimControls,
  renderPage,
} from './renderer.ts'

export type AppState = {
  controls: SimControls
  pendulum: { state: PendulumState; params: PendulumParams }
  projectile: { state: ProjectileState; params: ProjectileParams }
  spring: { state: SpringState; params: SpringParams }
}

const BASE_DT = 1 / 60

export const createInitialState = (): AppState => {
  const pendulumParams = getDefaultPendulumParams()
  const projectileParams = getDefaultProjectileParams()
  const springParams = getDefaultSpringParams()

  return {
    controls: {
      playing: false,
      speed: 1,
      activeTab: 'pendulum',
    },
    pendulum: {
      state: createPendulumState(pendulumParams),
      params: pendulumParams,
    },
    projectile: {
      state: createProjectileState(projectileParams),
      params: projectileParams,
    },
    spring: {
      state: createSpringState(springParams),
      params: springParams,
    },
  }
}

export const tick = (app: AppState): AppState => {
  if (!app.controls.playing) return app

  const dt = BASE_DT * app.controls.speed

  return {
    ...app,
    pendulum: {
      ...app.pendulum,
      state: stepPendulum(app.pendulum.state, app.pendulum.params, dt),
    },
    projectile: {
      ...app.projectile,
      state: stepProjectile(app.projectile.state, app.projectile.params, dt),
    },
    spring: {
      ...app.spring,
      state: stepSpring(app.spring.state, app.spring.params, dt),
    },
  }
}

export const handleAction = (app: AppState, action: string, value?: string): AppState => {
  switch (action) {
    case 'toggle-play':
      return {
        ...app,
        controls: { ...app.controls, playing: !app.controls.playing },
      }

    case 'reset':
      return {
        ...app,
        controls: { ...app.controls, playing: false },
        pendulum: {
          ...app.pendulum,
          state: createPendulumState(app.pendulum.params),
        },
        projectile: {
          ...app.projectile,
          state: createProjectileState(app.projectile.params),
        },
        spring: {
          ...app.spring,
          state: createSpringState(app.spring.params),
        },
      }

    case 'speed-change': {
      const speed = parseFloat(value ?? '1')
      return {
        ...app,
        controls: { ...app.controls, speed },
      }
    }

    case 'tab-pendulum':
    case 'tab-projectile':
    case 'tab-spring': {
      const tab = action.replace('tab-', '') as SimTab
      return {
        ...app,
        controls: { ...app.controls, activeTab: tab },
      }
    }

    // Pendulum params
    case 'pendulum-length': {
      const length = parseFloat(value ?? '2')
      const params = { ...app.pendulum.params, length }
      return {
        ...app,
        pendulum: { params, state: createPendulumState(params) },
        controls: { ...app.controls, playing: false },
      }
    }
    case 'pendulum-gravity': {
      const gravity = parseFloat(value ?? '9.81')
      const params = { ...app.pendulum.params, gravity }
      return {
        ...app,
        pendulum: { params, state: createPendulumState(params) },
        controls: { ...app.controls, playing: false },
      }
    }
    case 'pendulum-angle': {
      const degrees = parseFloat(value ?? '45')
      const params = { ...app.pendulum.params, theta0: (degrees * Math.PI) / 180 }
      return {
        ...app,
        pendulum: { params, state: createPendulumState(params) },
        controls: { ...app.controls, playing: false },
      }
    }

    // Projectile params
    case 'projectile-angle': {
      const angle = parseFloat(value ?? '45')
      const params = { ...app.projectile.params, angle }
      return {
        ...app,
        projectile: { params, state: createProjectileState(params) },
        controls: { ...app.controls, playing: false },
      }
    }
    case 'projectile-velocity': {
      const velocity = parseFloat(value ?? '20')
      const params = { ...app.projectile.params, velocity }
      return {
        ...app,
        projectile: { params, state: createProjectileState(params) },
        controls: { ...app.controls, playing: false },
      }
    }

    // Spring params
    case 'spring-k': {
      const k = parseFloat(value ?? '10')
      const params = { ...app.spring.params, k }
      return {
        ...app,
        spring: { params, state: createSpringState(params) },
        controls: { ...app.controls, playing: false },
      }
    }
    case 'spring-mass': {
      const mass = parseFloat(value ?? '1')
      const params = { ...app.spring.params, mass }
      return {
        ...app,
        spring: { params, state: createSpringState(params) },
        controls: { ...app.controls, playing: false },
      }
    }
    case 'spring-x0': {
      const x0 = parseFloat(value ?? '1.5')
      const params = { ...app.spring.params, x0 }
      return {
        ...app,
        spring: { params, state: createSpringState(params) },
        controls: { ...app.controls, playing: false },
      }
    }

    default:
      return app
  }
}

export const render = (app: AppState): string =>
  renderPage(
    app.controls,
    app.pendulum.state,
    app.pendulum.params,
    app.projectile.state,
    app.projectile.params,
    app.spring.state,
    app.spring.params,
  )

// --- Server entry point ---

export const createApp = () => {
  let state = createInitialState()

  return {
    getState: () => state,
    dispatch: (action: string, value?: string) => {
      state = handleAction(state, action, value)
    },
    tick: () => {
      state = tick(state)
    },
    render: () => render(state),
    reset: () => {
      state = createInitialState()
    },
  }
}

// --- Bun server ---

const startServer = () => {
  const app = createApp()

  const htmlTemplate = (body: string) => `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Newton's Laws Simulator</title>
  <style>
    * { box-sizing: border-box; margin: 0; padding: 0; }
    body { background: #09090b; min-height: 100vh; display: flex; justify-content: center; padding: 40px 16px; }
    @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&family=JetBrains+Mono:wght@400;700&display=swap');
  </style>
</head>
<body>
  <div id="app">${body}</div>
  <script>
    let state = null;
    let playing = false;
    let speed = 1;
    let activeTab = 'pendulum';

    const refresh = async () => {
      const res = await fetch('/render');
      const html = await res.text();
      document.getElementById('app').innerHTML = html;
      attachEvents();
    };

    const dispatch = async (action, value) => {
      await fetch('/action', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action, value }),
      });
      const stateRes = await fetch('/state');
      const st = await stateRes.json();
      playing = st.controls.playing;
      speed = st.controls.speed;
      activeTab = st.controls.activeTab;
      await refresh();
    };

    const attachEvents = () => {
      document.querySelectorAll('[p-trigger]').forEach(el => {
        const trigger = el.getAttribute('p-trigger');
        if (el.tagName === 'SELECT') {
          el.onchange = () => dispatch(trigger, el.value);
        } else if (el.tagName === 'INPUT' && el.type === 'range') {
          el.oninput = () => dispatch(trigger, el.value);
        } else {
          el.onclick = () => dispatch(trigger);
        }
      });
    };

    const loop = async () => {
      if (playing) {
        await fetch('/tick', { method: 'POST' });
        await refresh();
      }
      requestAnimationFrame(loop);
    };

    refresh().then(() => {
      loop();
    });
  </script>
</body>
</html>`

  Bun.serve({
    port: 3000,
    fetch: async (req) => {
      const url = new URL(req.url)

      if (url.pathname === '/' || url.pathname === '') {
        return new Response(htmlTemplate(app.render()), {
          headers: { 'Content-Type': 'text/html' },
        })
      }

      if (url.pathname === '/render') {
        return new Response(app.render(), {
          headers: { 'Content-Type': 'text/html' },
        })
      }

      if (url.pathname === '/state') {
        return Response.json(app.getState())
      }

      if (url.pathname === '/tick' && req.method === 'POST') {
        app.tick()
        return new Response('ok')
      }

      if (url.pathname === '/action' && req.method === 'POST') {
        const body = await req.json() as { action: string; value?: string }
        app.dispatch(body.action, body.value)
        return new Response('ok')
      }

      return new Response('Not found', { status: 404 })
    },
  })

  console.log('Newton\'s Laws Simulator running at http://localhost:3000')
}

// Auto-start if run directly
if (import.meta.main) {
  startServer()
}

