import type {
  PendulumParams,
  PendulumState,
  ProjectileParams,
  ProjectileState,
  SpringParams,
  SpringState,
} from './types';

// --- Pendulum Physics ---
// Uses Euler-Cromer (symplectic Euler) for energy conservation
// θ'' = -(g/L) * sin(θ)

export const createPendulumState = (params: PendulumParams): PendulumState => ({
  theta: params.initialAngle,
  omega: 0,
  alpha: -(params.gravity / params.length) * Math.sin(params.initialAngle),
});

export const stepPendulum = (
  state: PendulumState,
  params: PendulumParams,
  dt: number,
): PendulumState => {
  const alpha = -(params.gravity / params.length) * Math.sin(state.theta);
  const omega = state.omega + alpha * dt;
  const theta = state.theta + omega * dt;
  return { theta, omega, alpha };
};

export const getPendulumPosition = (
  state: PendulumState,
  params: PendulumParams,
): { x: number; y: number } => ({
  x: params.length * Math.sin(state.theta),
  y: params.length * Math.cos(state.theta),
});

export const getPendulumKinematics = (
  state: PendulumState,
  params: PendulumParams,
) => ({
  angularPosition: state.theta,
  angularVelocity: state.omega,
  tangentialAcceleration: state.alpha * params.length,
  velocity: Math.abs(state.omega * params.length),
});

// --- Projectile Physics ---
// x = v0*cos(α)*t, y = v0*sin(α)*t - ½g*t²

export const createProjectileState = (params: ProjectileParams): ProjectileState => {
  const rad = (params.angle * Math.PI) / 180;
  return {
    x: 0,
    y: 0,
    vx: params.velocity * Math.cos(rad),
    vy: params.velocity * Math.sin(rad),
    ax: 0,
    ay: -params.gravity,
    trail: [{ x: 0, y: 0 }],
    landed: false,
  };
};

export const stepProjectile = (
  state: ProjectileState,
  params: ProjectileParams,
  dt: number,
): ProjectileState => {
  if (state.landed) return state;

  const vx = state.vx;
  const vy = state.vy + state.ay * dt;
  const x = state.x + vx * dt;
  const y = state.y + state.vy * dt + 0.5 * state.ay * dt * dt;

  const landed = y <= 0 && state.y > 0;
  const clampedY = landed ? 0 : y;

  const trail = [...state.trail, { x, y: clampedY }];
  // Keep trail manageable
  const trimmedTrail = trail.length > 2000 ? trail.slice(trail.length - 2000) : trail;

  return {
    x,
    y: clampedY,
    vx,
    vy: landed ? 0 : vy,
    ax: 0,
    ay: -params.gravity,
    trail: trimmedTrail,
    landed,
  };
};

export const getProjectileKinematics = (state: ProjectileState) => ({
  positionX: state.x,
  positionY: Math.max(0, state.y),
  velocityX: state.vx,
  velocityY: state.vy,
  speed: Math.sqrt(state.vx ** 2 + state.vy ** 2),
  acceleration: Math.abs(state.ay),
});

// --- Spring-Mass Physics ---
// F = -kx => a = -(k/m)*x
// Uses Euler-Cromer for stability

export const createSpringState = (params: SpringParams): SpringState => ({
  x: params.initialDisplacement,
  v: 0,
  a: -(params.springConstant / params.mass) * params.initialDisplacement,
});

export const stepSpring = (
  state: SpringState,
  params: SpringParams,
  dt: number,
): SpringState => {
  const a = -(params.springConstant / params.mass) * state.x;
  const v = state.v + a * dt;
  const x = state.x + v * dt;
  return { x, v, a };
};

export const getSpringKinematics = (state: SpringState) => ({
  displacement: state.x,
  velocity: state.v,
  acceleration: state.a,
});

// Analytical values for validation
export const getSpringPeriod = (params: SpringParams): number =>
  2 * Math.PI * Math.sqrt(params.mass / params.springConstant);

export const getPendulumPeriod = (params: PendulumParams): number =>
  2 * Math.PI * Math.sqrt(params.length / params.gravity);

export const getProjectileRange = (params: ProjectileParams): number => {
  const rad = (params.angle * Math.PI) / 180;
  return (params.velocity ** 2 * Math.sin(2 * rad)) / params.gravity;
};

export const getProjectileMaxHeight = (params: ProjectileParams): number => {
  const rad = (params.angle * Math.PI) / 180;
  return (params.velocity * Math.sin(rad)) ** 2 / (2 * params.gravity);
};

