// --- Pendulum SVG ---

export const renderPendulumCanvas = (
  state: PendulumState,
  params: PendulumParams,
) => {
  const W = 820;
  const H = 350;
  const pivotX = W / 2;
  const pivotY = 60;
  const scale = 100; // px per meter
  const pos = getPendulumPosition(state, params);
  const bobX = pivotX + pos.x * scale;
  const bobY = pivotY + pos.y * scale;

  // Ghost trail: arc of max swing
  const arcRadius = params.length * scale;

  return h('div', { style: styles.canvas, 'p-target': 'canvas' },
    h('svg', {
      viewBox: `0 0 ${W} ${H}`,
      style: styles.svg,
      xmlns: 'http://www.w3.org/2000/svg',
    },
      // Background grid
      ...Array.from({ length: 9 }, (_, i) =>
        h('line', {
          x1: String((i + 1) * W / 10), y1: '0',
          x2: String((i + 1) * W / 10), y2: String(H),
          stroke: '#1a2744', 'stroke-width': '1',
        }),
      ),
      ...Array.from({ length: 6 }, (_, i) =>
        h('line', {
          x1: '0', y1: String((i + 1) * H / 7),
          x2: String(W), y2: String((i + 1) * H / 7),
          stroke: '#1a2744', 'stroke-width': '1',
        }),
      ),
      // Arc guide
      h('path', {
        d: `M ${pivotX - arcRadius} ${pivotY} A ${arcRadius} ${arcRadius} 0 0 1 ${pivotX + arcRadius} ${pivotY}`,
        fill: 'none',
        stroke: '#233554',
        'stroke-width': '1',
        'stroke-dasharray': '4,4',
      }),
      // Pivot
      h('circle', { cx: String(pivotX), cy: String(pivotY), r: '5', fill: '#8892b0' }),
      // Rod
      h('line', {
        x1: String(pivotX), y1: String(pivotY),
        x2: String(bobX), y2: String(bobY),
        stroke: '#ccd6f6', 'stroke-width': '2',
      }),
      // Bob
      h('circle', {
        cx: String(bobX), cy: String(bobY), r: '16',
        fill: '#64ffda', opacity: '0.9',
      }),
      h('circle', {
        cx: String(bobX), cy: String(bobY), r: '16',
        fill: 'none', stroke: '#64ffda', 'stroke-width': '2',
      }),
      // Velocity vector
      h('line', {
        x1: String(bobX), y1: String(bobY),
        x2: String(bobX + state.omega * params.length * scale * 0.5 * Math.cos(state.theta)),
        y2: String(bobY - state.omega * params.length * scale * 0.5 * Math.sin(state.theta)),
        stroke: '#e6c07b', 'stroke-width': '2',
        'stroke-linecap': 'round',
      }),
      // Angle indicator
      h('text', {
        x: String(pivotX + 30), y: String(pivotY + 20),
        fill: '#8892b0', 'font-size': '12', 'font-family': 'monospace',
      }, `${(state.theta * 180 / Math.PI).toFixed(1)}deg`),
    ),
  );
};

// --- Projectile SVG ---

export const renderProjectileCanvas = (
  state: ProjectileState,
  params: ProjectileParams,
) => {
  const W = 820;
  const H = 350;
  const margin = 40;
  const range = getProjectileRange(params);
  const maxH = getProjectileMaxHeight(params);
  const scaleX = (W - 2 * margin) / Math.max(range * 1.1, 1);
  const scaleY = (H - 2 * margin) / Math.max(maxH * 1.3, 1);
  const groundY = H - margin;

  const toScreenX = (x: number) => margin + x * scaleX;
  const toScreenY = (y: number) => groundY - y * scaleY;

  // Build trail path
  const trailPoints = state.trail
    .filter(p => p.y >= 0)
    .map(p => `${toScreenX(p.x)},${toScreenY(p.y)}`);
  const trailPath = trailPoints.length > 1
    ? `M ${trailPoints[0]} L ${trailPoints.slice(1).join(' L ')}`
    : '';

  // Predicted path (analytical)
  const rad = (params.angle * Math.PI) / 180;
  const predPoints: string[] = [];
  const steps = 60;
  for (let i = 0; i <= steps; i++) {
    const t = (i / steps) * (2 * params.velocity * Math.sin(rad) / params.gravity);
    const px = params.velocity * Math.cos(rad) * t;
    const py = params.velocity * Math.sin(rad) * t - 0.5 * params.gravity * t * t;
    if (py >= 0) predPoints.push(`${toScreenX(px)},${toScreenY(py)}`);
  }
  const predPath = predPoints.length > 1
    ? `M ${predPoints[0]} L ${predPoints.slice(1).join(' L ')}`
    : '';

  const projX = toScreenX(state.x);
  const projY = toScreenY(Math.max(0, state.y));

  return h('div', { style: styles.canvas, 'p-target': 'canvas' },
    h('svg', {
      viewBox: `0 0 ${W} ${H}`,
      style: styles.svg,
      xmlns: 'http://www.w3.org/2000/svg',
    },
      // Ground
      h('line', {
        x1: '0', y1: String(groundY),
        x2: String(W), y2: String(groundY),
        stroke: '#3d5a80', 'stroke-width': '2',
      }),
      // Grid
      ...Array.from({ length: 5 }, (_, i) => {
        const gy = groundY - (i + 1) * (H - 2 * margin) / 5;
        return h('line', {
          x1: String(margin), y1: String(gy),
          x2: String(W - margin), y2: String(gy),
          stroke: '#1a2744', 'stroke-width': '1',
        });
      }),
      // Predicted trajectory (dashed)
      predPath ? h('path', {
        d: predPath,
        fill: 'none',
        stroke: '#233554',
        'stroke-width': '1.5',
        'stroke-dasharray': '6,4',
      }) : h(Fragment, {}),
      // Actual trail
      trailPath ? h('path', {
        d: trailPath,
        fill: 'none',
        stroke: '#64ffda',
        'stroke-width': '2',
        opacity: '0.7',
      }) : h(Fragment, {}),
      // Projectile
      h('circle', {
        cx: String(projX), cy: String(projY), r: '10',
        fill: state.landed ? '#e06c75' : '#64ffda',
      }),
      // Velocity vector
      !state.landed ? h('line', {
        x1: String(projX), y1: String(projY),
        x2: String(projX + state.vx * 1.5),
        y2: String(projY - state.vy * 1.5),
        stroke: '#e6c07b', 'stroke-width': '2',
        'stroke-linecap': 'round',
      }) : h(Fragment, {}),
      // Range marker
      h('text', {
        x: String(toScreenX(range)), y: String(groundY + 16),
        fill: '#8892b0', 'font-size': '11', 'font-family': 'monospace',
        'text-anchor': 'middle',
      }, `${range.toFixed(1)}m`),
      // Height marker
      h('text', {
        x: String(margin - 5), y: String(toScreenY(maxH) - 5),
        fill: '#8892b0', 'font-size': '11', 'font-family': 'monospace',
        'text-anchor': 'end',
      }, `${maxH.toFixed(1)}m`),
    ),
  );
};

// --- Spring SVG ---

export const renderSpringCanvas = (
  state: SpringState,
  params: SpringParams,
) => {
  const W = 820;
  const H = 350;
  const wallX = 80;
  const centerY = H / 2;
  const restX = W / 2;
  const scale = 120; // px per meter
  const massX = restX + state.x * scale;
  const massW = 50;
  const massH = 50;

  // Draw spring as zigzag
  const coils = 12;
  const springStartX = wallX;
  const springEndX = massX - massW / 2;
  const springLen = springEndX - springStartX;
  const coilWidth = springLen / coils;
  const amplitude = 14;
  const springPath: string[] = [`M ${springStartX} ${centerY}`];
  for (let i = 0; i < coils; i++) {
    const x1 = springStartX + (i + 0.25) * coilWidth;
    const x2 = springStartX + (i + 0.75) * coilWidth;
    const x3 = springStartX + (i + 1) * coilWidth;
    const dir = i % 2 === 0 ? -1 : 1;
    springPath.push(`L ${x1} ${centerY + dir * amplitude}`);
    springPath.push(`L ${x2} ${centerY - dir * amplitude}`);
    springPath.push(`L ${x3} ${centerY}`);
  }

  // Equilibrium position marker
  const eqX = restX;

  return h('div', { style: styles.canvas, 'p-target': 'canvas' },
    h('svg', {
      viewBox: `0 0 ${W} ${H}`,
      style: styles.svg,
      xmlns: 'http://www.w3.org/2000/svg',
    },
      // Background grid
      ...Array.from({ length: 9 }, (_, i) =>
        h('line', {
          x1: String((i + 1) * W / 10), y1: '0',
          x2: String((i + 1) * W / 10), y2: String(H),
          stroke: '#1a2744', 'stroke-width': '1',
        }),
      ),
      // Wall
      h('rect', {
        x: String(wallX - 10), y: String(centerY - 80),
        width: '10', height: '160',
        fill: '#3d5a80',
      }),
      // Wall hatching
      ...Array.from({ length: 8 }, (_, i) =>
        h('line', {
          x1: String(wallX - 10), y1: String(centerY - 80 + i * 20),
          x2: String(wallX), y2: String(centerY - 60 + i * 20),
          stroke: '#5a7da8', 'stroke-width': '1',
        }),
      ),
      // Equilibrium line
      h('line', {
        x1: String(eqX), y1: String(centerY - 60),
        x2: String(eqX), y2: String(centerY + 60),
        stroke: '#233554', 'stroke-width': '1',
        'stroke-dasharray': '4,4',
      }),
      h('text', {
        x: String(eqX), y: String(centerY + 80),
        fill: '#5a7a9a', 'font-size': '11', 'font-family': 'monospace',
        'text-anchor': 'middle',
      }, 'equilibrium'),
      // Spring
      h('path', {
        d: springPath.join(' '),
        fill: 'none',
        stroke: '#8892b0',
        'stroke-width': '2',
        'stroke-linejoin': 'round',
      }),
      // Mass block
      h('rect', {
        x: String(massX - massW / 2), y: String(centerY - massH / 2),
        width: String(massW), height: String(massH),
        rx: '6', ry: '6',
        fill: '#64ffda', opacity: '0.9',
      }),
      h('rect', {
        x: String(massX - massW / 2), y: String(centerY - massH / 2),
        width: String(massW), height: String(massH),
        rx: '6', ry: '6',
        fill: 'none', stroke: '#64ffda', 'stroke-width': '2',
      }),
      h('text', {
        x: String(massX), y: String(centerY + 5),
        fill: '#1a1a2e', 'font-size': '13', 'font-weight': 'bold',
        'font-family': 'monospace', 'text-anchor': 'middle',
      }, `${params.mass}kg`),
      // Displacement arrow
      state.x !== 0 ? h('line', {
        x1: String(eqX), y1: String(centerY + 50),
        x2: String(massX), y2: String(centerY + 50),
        stroke: '#e6c07b', 'stroke-width': '2',
        'marker-end': 'url(#arrowhead)',
      }) : h(Fragment, {}),
      // Arrow marker definition
      h('defs', {},
        h('marker', {
          id: 'arrowhead', markerWidth: '8', markerHeight: '6',
          refX: '8', refY: '3', orient: 'auto',
        },
          h('polygon', { points: '0 0, 8 3, 0 6', fill: '#e6c07b' }),
        ),
      ),
      // Displacement label
      state.x !== 0 ? h('text', {
        x: String((eqX + massX) / 2), y: String(centerY + 45),
        fill: '#e6c07b', 'font-size': '11', 'font-family': 'monospace',
        'text-anchor': 'middle',
      }, `${state.x.toFixed(2)}m`) : h(Fragment, {}),
    ),
  );
};

