// --- Full page ---

export const renderPage = (
  simState: SimState,
  pendulumState: PendulumState,
  pendulumParams: PendulumParams,
  projectileState: ProjectileState,
  projectileParams: ProjectileParams,
  springState: SpringState,
  springParams: SpringParams,
) => {
  const canvasContent = (() => {
    switch (simState.activeTab) {
      case 'pendulum':
        return h(Fragment, {},
          renderPendulumCanvas(pendulumState, pendulumParams),
          renderPendulumSliders(pendulumParams),
          renderPendulumReadouts(pendulumState, pendulumParams),
        );
      case 'projectile':
        return h(Fragment, {},
          renderProjectileCanvas(projectileState, projectileParams),
          renderProjectileSliders(projectileParams),
          renderProjectileReadouts(projectileState, projectileParams),
        );
      case 'spring':
        return h(Fragment, {},
          renderSpringCanvas(springState, springParams),
          renderSpringSliders(springParams),
          renderSpringReadouts(springState, springParams),
        );
    }
  })();

  return h('div', { style: styles.container },
    h('div', { style: styles.title }, "Newton's Laws Simulator"),
    renderTabs(simState.activeTab),
    renderControls(simState),
    canvasContent,
  );
};

import { h, createSSR } from 'plaited';
import type {
  SimState,
  SimulationType,
  PendulumParams,
  PendulumState,
  ProjectileParams,
  ProjectileState,
  SpringParams,
  SpringState,
} from './types';
import {
  createPendulumState,
  stepPendulum,
  createProjectileState,
  stepProjectile,
  createSpringState,
  stepSpring,
} from './physics';
import { renderPage } from './render';

// --- Default parameters ---

const DEFAULT_PENDULUM_PARAMS: PendulumParams = {
  length: 1.5,
  gravity: 9.81,
  initialAngle: (30 * Math.PI) / 180,
};

const DEFAULT_PROJECTILE_PARAMS: ProjectileParams = {
  angle: 45,
  velocity: 25,
  gravity: 9.81,
};

const DEFAULT_SPRING_PARAMS: SpringParams = {
  springConstant: 10,
  mass: 1.0,
  initialDisplacement: 1.0,
};

// --- Simulation engine ---

type SimulationEngine = {
  simState: SimState;
  pendulumState: PendulumState;
  pendulumParams: PendulumParams;
  projectileState: ProjectileState;
  projectileParams: ProjectileParams;
  springState: SpringState;
  springParams: SpringParams;
  animFrameId: number | null;
  lastTimestamp: number | null;
};

const createEngine = (): SimulationEngine => ({
  simState: {
    running: false,
    time: 0,
    speed: 1,
    activeTab: 'pendulum',
  },
  pendulumParams: { ...DEFAULT_PENDULUM_PARAMS },
  pendulumState: createPendulumState(DEFAULT_PENDULUM_PARAMS),
  projectileParams: { ...DEFAULT_PROJECTILE_PARAMS },
  projectileState: createProjectileState(DEFAULT_PROJECTILE_PARAMS),
  springParams: { ...DEFAULT_SPRING_PARAMS },
  springState: createSpringState(DEFAULT_SPRING_PARAMS),
  animFrameId: null,
  lastTimestamp: null,
});

// Physics timestep (fixed at 1ms for accuracy)
const PHYSICS_DT = 0.001;

const stepEngine = (engine: SimulationEngine, elapsed: number): void => {
  const dt = elapsed * engine.simState.speed;
  const steps = Math.min(Math.floor(dt / PHYSICS_DT), 50); // cap to avoid spiral of death

  for (let i = 0; i < steps; i++) {
    switch (engine.simState.activeTab) {
      case 'pendulum':
        engine.pendulumState = stepPendulum(engine.pendulumState, engine.pendulumParams, PHYSICS_DT);
        break;
      case 'projectile':
        engine.projectileState = stepProjectile(engine.projectileState, engine.projectileParams, PHYSICS_DT);
        break;
      case 'spring':
        engine.springState = stepSpring(engine.springState, engine.springParams, PHYSICS_DT);
        break;
    }
  }

  engine.simState.time += dt;
};

// --- Event handling ---

type EventHandler = (engine: SimulationEngine, value?: string) => void;

const handlers: Record<string, EventHandler> = {
  'toggle-play': (engine) => {
    engine.simState.running = !engine.simState.running;
    engine.lastTimestamp = null;
  },

  'reset': (engine) => {
    engine.simState.running = false;
    engine.simState.time = 0;
    engine.lastTimestamp = null;
    engine.pendulumState = createPendulumState(engine.pendulumParams);
    engine.projectileState = createProjectileState(engine.projectileParams);
    engine.springState = createSpringState(engine.springParams);
  },

  'tab-pendulum': (engine) => {
    engine.simState.activeTab = 'pendulum';
  },
  'tab-projectile': (engine) => {
    engine.simState.activeTab = 'projectile';
  },
  'tab-spring': (engine) => {
    engine.simState.activeTab = 'spring';
  },
};

// Speed handlers
[0.25, 0.5, 1, 2, 4].forEach(s => {
  handlers[`speed-${s}`] = (engine) => {
    engine.simState.speed = s;
  };
});

// Slider handlers for pendulum
const pendulumSliderHandlers: Record<string, (engine: SimulationEngine, val: number) => void> = {
  'slider-length': (engine, val) => {
    engine.pendulumParams.length = val;
    engine.pendulumState = createPendulumState(engine.pendulumParams);
    engine.simState.time = 0;
  },
  'slider-gravity': (engine, val) => {
    if (engine.simState.activeTab === 'pendulum') {
      engine.pendulumParams.gravity = val;
      engine.pendulumState = createPendulumState(engine.pendulumParams);
      engine.simState.time = 0;
    } else if (engine.simState.activeTab === 'projectile') {
      engine.projectileParams.gravity = val;
      engine.projectileState = createProjectileState(engine.projectileParams);
      engine.simState.time = 0;
    }
  },
  'slider-initialAngle': (engine, val) => {
    engine.pendulumParams.initialAngle = (val * Math.PI) / 180;
    engine.pendulumState = createPendulumState(engine.pendulumParams);
    engine.simState.time = 0;
  },
};

// Slider handlers for projectile
const projectileSliderHandlers: Record<string, (engine: SimulationEngine, val: number) => void> = {
  'slider-angle': (engine, val) => {
    engine.projectileParams.angle = val;
    engine.projectileState = createProjectileState(engine.projectileParams);
    engine.simState.time = 0;
  },
  'slider-velocity': (engine, val) => {
    engine.projectileParams.velocity = val;
    engine.projectileState = createProjectileState(engine.projectileParams);
    engine.simState.time = 0;
  },
};

// Slider handlers for spring
const springSliderHandlers: Record<string, (engine: SimulationEngine, val: number) => void> = {
  'slider-springConstant': (engine, val) => {
    engine.springParams.springConstant = val;
    engine.springState = createSpringState(engine.springParams);
    engine.simState.time = 0;
  },
  'slider-mass': (engine, val) => {
    engine.springParams.mass = val;
    engine.springState = createSpringState(engine.springParams);
    engine.simState.time = 0;
  },
  'slider-initialDisplacement': (engine, val) => {
    engine.springParams.initialDisplacement = val;
    engine.springState = createSpringState(engine.springParams);
    engine.simState.time = 0;
  },
};

const handleEvent = (engine: SimulationEngine, trigger: string, value?: string): void => {
  const handler = handlers[trigger];
  if (handler) {
    handler(engine, value);
    return;
  }

  const numVal = value !== undefined ? parseFloat(value) : NaN;
  if (!isNaN(numVal)) {
    const sliderHandler =
      pendulumSliderHandlers[trigger] ??
      projectileSliderHandlers[trigger] ??
      springSliderHandlers[trigger];
    if (sliderHandler) {
      sliderHandler(engine, numVal);
    }
  }
};

// --- SSR Render ---

const render = (engine: SimulationEngine): string => {
  const template = renderPage(
    engine.simState,
    engine.pendulumState,
    engine.pendulumParams,
    engine.projectileState,
    engine.projectileParams,
    engine.springState,
    engine.springParams,
  );
  return createSSR(template);
};

// --- Animation loop (for browser context) ---

const startAnimationLoop = (engine: SimulationEngine, onFrame: (html: string) => void): void => {
  const loop = (timestamp: number) => {
    if (engine.simState.running) {
      if (engine.lastTimestamp !== null) {
        const elapsed = Math.min((timestamp - engine.lastTimestamp) / 1000, 0.05);
        stepEngine(engine, elapsed);
      }
      engine.lastTimestamp = timestamp;
    }

    onFrame(render(engine));
    engine.animFrameId = requestAnimationFrame(loop);
  };

  engine.animFrameId = requestAnimationFrame(loop);
};

const stopAnimationLoop = (engine: SimulationEngine): void => {
  if (engine.animFrameId !== null) {
    cancelAnimationFrame(engine.animFrameId);
    engine.animFrameId = null;
  }
};

// --- Server-side step (for headless/API use) ---

const stepAndRender = (engine: SimulationEngine, dtSeconds: number): string => {
  if (engine.simState.running) {
    stepEngine(engine, dtSeconds);
  }
  return render(engine);
};

// --- HTTP Server ---

const serveSimulator = async (port = 3000) => {
  const engine = createEngine();

  const htmlPage = (body: string) => `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Newton's Laws Simulator</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { background: #0f0f23; min-height: 100vh; display: flex; justify-content: center; padding: 20px; }
    input[type="range"] { -webkit-appearance: none; height: 6px; border-radius: 3px; background: #233554; outline: none; }
    input[type="range"]::-webkit-slider-thumb { -webkit-appearance: none; width: 16px; height: 16px; border-radius: 50%; background: #64ffda; cursor: pointer; }
    button:hover { opacity: 0.85; }
  </style>
</head>
<body>
  <div id="app">${body}</div>
  <script>
    const state = {
      running: false,
      speed: 1,
      activeTab: 'pendulum',
      lastTimestamp: null,
    };

    const refresh = async () => {
      const res = await fetch('/render?' + new URLSearchParams({ t: Date.now().toString() }));
      document.getElementById('app').innerHTML = await res.text();
      bindEvents();
    };

    const bindEvents = () => {
      document.querySelectorAll('[p-trigger]').forEach(el => {
        const trigger = el.getAttribute('p-trigger');
        if (el.tagName === 'INPUT') {
          el.addEventListener('input', async (e) => {
            await fetch('/event', {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({ trigger, value: e.target.value }),
            });
            await refresh();
          });
        } else {
          el.addEventListener('click', async () => {
            const res = await fetch('/event', {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({ trigger }),
            });
            const data = await res.json();
            state.running = data.running;
            await refresh();
          });
        }
      });
    };

    let animFrame = null;
    const loop = async () => {
      if (state.running) {
        await fetch('/step', { method: 'POST' });
        await refresh();
      }
      animFrame = requestAnimationFrame(loop);
    };

    bindEvents();
    loop();
  </script>
</body>
</html>`;

  Bun.serve({
    port,
    fetch: async (req) => {
      const url = new URL(req.url);

      if (url.pathname === '/' || url.pathname === '') {
        return new Response(htmlPage(render(engine)), {
          headers: { 'Content-Type': 'text/html; charset=utf-8' },
        });
      }

      if (url.pathname === '/render') {
        return new Response(render(engine), {
          headers: { 'Content-Type': 'text/html; charset=utf-8' },
        });
      }

      if (url.pathname === '/event' && req.method === 'POST') {
        const body = await req.json() as { trigger: string; value?: string };
        handleEvent(engine, body.trigger, body.value);
        return Response.json({ ok: true, running: engine.simState.running });
      }

      if (url.pathname === '/step' && req.method === 'POST') {
        stepAndRender(engine, 1 / 60);
        return Response.json({ ok: true, time: engine.simState.time });
      }

      if (url.pathname === '/state') {
        return Response.json({
          sim: engine.simState,
          pendulum: { state: engine.pendulumState, params: engine.pendulumParams },
          projectile: { state: engine.projectileState, params: engine.projectileParams },
          spring: { state: engine.springState, params: engine.springParams },
        });
      }

      return new Response('Not Found', { status: 404 });
    },
  });

  console.log(`Newton's Laws Simulator running at http://localhost:${port}`);
};

