const clientScript = (presets: SimPreset[]) => `
(function() {
  const DEG2RAD = Math.PI / 180;
  let activeTab = 'pendulum';
  let playing = false;
  let speed = 1;
  let lastFrame = 0;

  // Pendulum state
  let pend = { angle: Math.PI/4, av: 0, aa: 0, t: 0 };
  let pendP = { length: 1.5, gravity: 9.81 };

  // Projectile state
  let proj = { x: 0, y: 0, vx: 0, vy: 0, t: 0, landed: false, trail: [] };
  let projP = { angle: 45, vel: 20, gravity: 9.81 };

  // Spring state
  let spr = { disp: 1.0, vel: 0, acc: 0, t: 0 };
  let sprP = { k: 10, mass: 1 };

  const $ = (s) => document.querySelector(s);
  const $$ = (s) => document.querySelectorAll(s);

  // Tab switching
  $$('.tab').forEach(tab => {
    tab.addEventListener('click', () => {
      activeTab = tab.dataset.sim;
      $$('.tab').forEach(t => t.classList.remove('active'));
      tab.classList.add('active');
      $$('.sim-panel').forEach(p => p.classList.remove('active'));
      $('#panel-' + activeTab).classList.add('active');
    });
  });

  // Play/Pause
  const playBtn = $('#btn-play');
  const resetBtn = $('#btn-reset');

  playBtn.addEventListener('click', () => {
    playing = !playing;
    playBtn.textContent = playing ? 'Pause' : 'Play';
    playBtn.classList.toggle('primary', playing);
    if (playing) { lastFrame = performance.now(); requestAnimationFrame(loop); }
  });

  resetBtn.addEventListener('click', () => {
    playing = false;
    playBtn.textContent = 'Play';
    playBtn.classList.remove('primary');
    resetPendulum();
    resetProjectile();
    resetSpring();
    render();
  });

  // Speed
  const speedSlider = $('#speed-slider');
  const speedVal = $('#speed-val');
  speedSlider.addEventListener('input', () => {
    speed = parseFloat(speedSlider.value);
    speedVal.textContent = speed.toFixed(2) + 'x';
  });

  // Param sliders
  const bindSlider = (id, cb) => {
    const el = $('#' + id);
    if (!el) return;
    el.addEventListener('input', () => cb(parseFloat(el.value)));
  };

  bindSlider('pend-length', v => { pendP.length = v; $('#pend-length-val').textContent = v.toFixed(1) + ' m'; });
  bindSlider('pend-gravity', v => { pendP.gravity = v; $('#pend-gravity-val').textContent = v.toFixed(1) + ' m/s\\u00b2'; });
  bindSlider('proj-angle', v => { projP.angle = v; $('#proj-angle-val').textContent = v + '\\u00b0'; if (!playing) { resetProjectile(); render(); } });
  bindSlider('proj-vel', v => { projP.vel = v; $('#proj-vel-val').textContent = v + ' m/s'; if (!playing) { resetProjectile(); render(); } });
  bindSlider('spr-k', v => { sprP.k = v; $('#spr-k-val').textContent = v + ' N/m'; });
  bindSlider('spr-mass', v => { sprP.mass = v; $('#spr-mass-val').textContent = v.toFixed(1) + ' kg'; });

  function resetPendulum() {
    pend = { angle: Math.PI/4, av: 0, aa: 0, t: 0 };
  }
  function resetProjectile() {
    proj = { x: 0, y: 0, vx: 0, vy: 0, t: 0, landed: false, trail: [] };
  }
  function resetSpring() {
    spr = { disp: 1.0, vel: 0, acc: 0, t: 0 };
  }

  // Physics
  function stepPendulum(dt) {
    const acc = -(pendP.gravity / pendP.length) * Math.sin(pend.angle);
    pend.av += acc * dt;
    pend.angle += pend.av * dt;
    pend.aa = acc;
    pend.t += dt;
  }

  function stepProjectile(dt) {
    if (proj.landed) return;
    if (proj.t === 0) {
      const rad = projP.angle * DEG2RAD;
      proj.vx = projP.vel * Math.cos(rad);
      proj.vy = projP.vel * Math.sin(rad);
    }
    proj.vy -= projP.gravity * dt;
    proj.x += proj.vx * dt;
    proj.y += proj.vy * dt;
    proj.t += dt;
    proj.trail.push({ x: proj.x, y: Math.max(0, proj.y) });
    if (proj.trail.length > 2000) proj.trail.shift();
    if (proj.y < 0 && proj.t > 0.05) {
      proj.y = 0;
      proj.vy = 0;
      proj.landed = true;
    }
  }

  function stepSpring(dt) {
    const omega2 = sprP.k / sprP.mass;
    const acc = -omega2 * spr.disp;
    spr.vel += acc * dt;
    spr.disp += spr.vel * dt;
    spr.acc = -omega2 * spr.disp;
    spr.t += dt;
  }

  // Rendering
  function render() {
    if (activeTab === 'pendulum') renderPendulum();
    else if (activeTab === 'projectile') renderProjectile();
    else renderSpring();
  }

  function renderPendulum() {
    const svg = $('#svg-pendulum');
    const cx = 460, cy = 40;
    const scale = 120;
    const L = pendP.length * scale;
    const bx = cx + L * Math.sin(pend.angle);
    const by = cy + L * Math.cos(pend.angle);

    const rod = svg.querySelector('.pend-rod');
    const bob = svg.querySelector('.pend-bob');
    const pivot = svg.querySelector('.pend-pivot');
    const trail = svg.querySelector('.pend-trail');

    pivot.setAttribute('cx', cx);
    pivot.setAttribute('cy', cy);
    rod.setAttribute('x1', cx);
    rod.setAttribute('y1', cy);
    rod.setAttribute('x2', bx);
    rod.setAttribute('y2', by);
    bob.setAttribute('cx', bx);
    bob.setAttribute('cy', by);

    // Ghost trail
    if (!renderPendulum._trail) renderPendulum._trail = [];
    renderPendulum._trail.push({ x: bx, y: by });
    if (renderPendulum._trail.length > 60) renderPendulum._trail.shift();
    const pts = renderPendulum._trail.map(p => p.x + ',' + p.y).join(' ');
    trail.setAttribute('points', pts);

    // Values
    const tanAcc = -pendP.gravity * Math.sin(pend.angle);
    const tanVel = pend.av * pendP.length;
    $('#pend-val-pos').textContent = pend.angle.toFixed(3) + ' rad';
    $('#pend-val-vel').textContent = tanVel.toFixed(3) + ' m/s';
    $('#pend-val-acc').textContent = tanAcc.toFixed(3) + ' m/s\\u00b2';
  }

  function renderProjectile() {
    const svg = $('#svg-projectile');
    const trail = svg.querySelector('.proj-trail');
    const dot = svg.querySelector('.proj-dot');
    const ground = svg.querySelector('.proj-ground');
    const arrow = svg.querySelector('.proj-arrow');

    const ox = 60, oy = 350;
    const scaleX = 7, scaleY = 7;

    ground.setAttribute('x1', 0);
    ground.setAttribute('y1', oy);
    ground.setAttribute('x2', 920);
    ground.setAttribute('y2', oy);

    const sx = ox + proj.x * scaleX;
    const sy = oy - proj.y * scaleY;

    dot.setAttribute('cx', sx);
    dot.setAttribute('cy', Math.min(sy, oy));

    if (proj.trail.length > 1) {
      const pts = proj.trail.map(p => (ox + p.x * scaleX) + ',' + (oy - p.y * scaleY)).join(' ');
      trail.setAttribute('points', pts);
    }

    // Velocity arrow when not launched
    if (proj.t === 0) {
      const rad = projP.angle * DEG2RAD;
      const al = 50;
      const ax = ox + al * Math.cos(rad);
      const ay = oy - al * Math.sin(rad);
      arrow.setAttribute('x1', ox);
      arrow.setAttribute('y1', oy);
      arrow.setAttribute('x2', ax);
      arrow.setAttribute('y2', ay);
      arrow.setAttribute('stroke-opacity', '1');
    } else {
      arrow.setAttribute('stroke-opacity', '0');
    }

    const vel = Math.sqrt(proj.vx * proj.vx + proj.vy * proj.vy);
    const acc = proj.landed ? 0 : projP.gravity;
    $('#proj-val-pos').textContent = '(' + proj.x.toFixed(1) + ', ' + Math.max(0, proj.y).toFixed(1) + ') m';
    $('#proj-val-vel').textContent = vel.toFixed(2) + ' m/s';
    $('#proj-val-acc').textContent = acc.toFixed(2) + ' m/s\\u00b2';
  }

  function renderSpring() {
    const svg = $('#svg-spring');
    const mass = svg.querySelector('.spr-mass');
    const spring = svg.querySelector('.spr-spring');
    const wall = svg.querySelector('.spr-wall');
    const eqLine = svg.querySelector('.spr-eq');

    const wallX = 80, cy = 200;
    const eqX = 460;
    const scale = 80;
    const massX = eqX + spr.disp * scale;
    const massW = 50, massH = 50;

    wall.setAttribute('x1', wallX);
    wall.setAttribute('y1', cy - 60);
    wall.setAttribute('x2', wallX);
    wall.setAttribute('y2', cy + 60);

    eqLine.setAttribute('x1', eqX);
    eqLine.setAttribute('y1', cy - 70);
    eqLine.setAttribute('x2', eqX);
    eqLine.setAttribute('y2', cy + 70);

    mass.setAttribute('x', massX - massW/2);
    mass.setAttribute('y', cy - massH/2);
    mass.setAttribute('width', massW);
    mass.setAttribute('height', massH);

    // Draw spring as zigzag
    const coils = 16;
    const startX = wallX + 10;
    const endX = massX - massW/2;
    const segLen = (endX - startX) / coils;
    const amp = 14;
    let d = 'M' + startX + ',' + cy;
    for (let i = 0; i < coils; i++) {
      const px = startX + (i + 0.5) * segLen;
      const py = cy + (i % 2 === 0 ? -amp : amp);
      d += ' L' + px + ',' + py;
    }
    d += ' L' + endX + ',' + cy;
    spring.setAttribute('d', d);

    // Force arrow
    const forceArrow = svg.querySelector('.spr-force');
    const forceScale = 3;
    const forceLen = -spr.acc * sprP.mass * forceScale;
    forceArrow.setAttribute('x1', massX);
    forceArrow.setAttribute('y1', cy);
    forceArrow.setAttribute('x2', massX + forceLen);
    forceArrow.setAttribute('y2', cy);

    $('#spr-val-pos').textContent = spr.disp.toFixed(3) + ' m';
    $('#spr-val-vel').textContent = spr.vel.toFixed(3) + ' m/s';
    $('#spr-val-acc').textContent = spr.acc.toFixed(3) + ' m/s\\u00b2';
  }

  // Main loop
  function loop(now) {
    if (!playing) return;
    const rawDt = Math.min((now - lastFrame) / 1000, 0.05);
    const dt = rawDt * speed;
    lastFrame = now;

    const steps = 4;
    const subDt = dt / steps;
    for (let i = 0; i < steps; i++) {
      if (activeTab === 'pendulum') stepPendulum(subDt);
      else if (activeTab === 'projectile') stepProjectile(subDt);
      else stepSpring(subDt);
    }

    render();
    requestAnimationFrame(loop);
  }

  // Initial render
  render();
})();
`

