import { renderPage } from './render'
import type { SimPreset } from './types'

const DATA_PATH = new URL('../data/presets.json', import.meta.url).pathname

const loadPresets = async (): Promise<SimPreset[]> => {
  const file = Bun.file(DATA_PATH)
  if (await file.exists()) {
    return file.json() as Promise<SimPreset[]>
  }
  return []
}

const savePresets = async (presets: SimPreset[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(presets, null, 2))
}

const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url)

    if (url.pathname === '/' || url.pathname === '/index.html') {
      const presets = await loadPresets()
      const html = renderPage(presets)
      return new Response(html, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      })
    }

    if (url.pathname === '/api/presets') {
      if (req.method === 'GET') {
        const presets = await loadPresets()
        return Response.json(presets)
      }
      if (req.method === 'POST') {
        const body = (await req.json()) as SimPreset
        const presets = await loadPresets()
        presets.push(body)
        await savePresets(presets)
        return Response.json({ ok: true })
      }
    }

    return new Response('Not Found', { status: 404 })
  },
})

console.log(`Newton's Laws Simulator running at http://localhost:${server.port}`)
